export const ARTICLES_07: Article[] = [
  { id: 'ccyc-art-724', lawId: 'codigo-civil-comercial', number: '724', order: 724, title: "Definición", originalText: "Definición. La obligación es una relación jurídica en virtud de la cual el acreedor tiene el derecho a exigir del deudor una prestación destinada a satisfacer un interés lícito y, ante el incumplimiento, a obtener forzadamente la satisfacción de dicho interés.", currentText: "Definición. La obligación es una relación jurídica en virtud de la cual el acreedor tiene el derecho a exigir del deudor una prestación destinada a satisfacer un interés lícito y, ante el incumplimiento, a obtener forzadamente la satisfacción de dicho interés.", plainLanguageExplanation: "Establece el régimen de definición. La obligación es una relación jurídica en virtud de la cual el acreedor tiene el derecho a exigir del deudor una prestación destinada a satisfacer un interés lícito y, ante el incumplimiento, a obtener forzadamente la satisfacción de dicho interés.", practicalEffects: ['En la práctica, este artículo rige definición. La obligación es una relación jurídica en virtud de la cual el acreedor tiene el derecho a exigir del deudor una prestación destinada a satisfacer un'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 724'], segments: [], amendments: [] },
  { id: 'ccyc-art-725', lawId: 'codigo-civil-comercial', number: '725', order: 725, title: "Requisitos", originalText: "Requisitos. La prestación que constituye el objeto de la obligación debe ser material y jurídicamente posible, lícita, determinada o determinable, susceptible de valoración económica y debe corresponder a un interés patrimonial o extrapatrimonial del acreedor.", currentText: "Requisitos. La prestación que constituye el objeto de la obligación debe ser material y jurídicamente posible, lícita, determinada o determinable, susceptible de valoración económica y debe corresponder a un interés patrimonial o extrapatrimonial del acreedor.", plainLanguageExplanation: "Establece el régimen de requisitos. La prestación que constituye el objeto de la obligación debe ser material y jurídicamente posible, lícita, determinada o determinable, susceptible de valoración económica y debe corresponder a un interés patrimonial o extrapatrimonial del acreedor.", practicalEffects: ['En la práctica, este artículo rige requisitos. La prestación que constituye el objeto de la obligación debe ser material y jurídicamente posible, lícita, determinada o determinable, susceptible de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitosarticulo 725'], segments: [], amendments: [] },
  { id: 'ccyc-art-726', lawId: 'codigo-civil-comercial', number: '726', order: 726, title: "Causa", originalText: "Causa. No hay obligación sin causa, es decir, sin que derive de algún hecho idóneo para producirla, de conformidad con el ordenamiento jurídico.", currentText: "Causa. No hay obligación sin causa, es decir, sin que derive de algún hecho idóneo para producirla, de conformidad con el ordenamiento jurídico.", plainLanguageExplanation: "Establece el régimen de causa. No hay obligación sin causa, es decir, sin que derive de algún hecho idóneo para producirla, de conformidad con el ordenamiento jurídico.", practicalEffects: ['En la práctica, este artículo rige causa. No hay obligación sin causa, es decir, sin que derive de algún hecho idóneo para producirla, de conformidad con el ordenamiento jurídico.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['causaarticulo 726'], segments: [], amendments: [] },
  { id: 'ccyc-art-727', lawId: 'codigo-civil-comercial', number: '727', order: 727, title: "Prueba de la existencia de la obligación", originalText: "Prueba de la existencia de la obligación. Presunción de fuente legítima. La existencia de la obligación no se presume. La interpretación respecto de la existencia y extensión de la obligación es restrictiva. Probada la obligación, se presume que nace de fuente legítima mientras no se acredite lo contrario.", currentText: "Prueba de la existencia de la obligación. Presunción de fuente legítima. La existencia de la obligación no se presume. La interpretación respecto de la existencia y extensión de la obligación es restrictiva. Probada la obligación, se presume que nace de fuente legítima mientras no se acredite lo contrario.", plainLanguageExplanation: "Establece el régimen de prueba de la existencia de la obligación. Presunción de fuente legítima.", practicalEffects: ['En la práctica, este artículo rige prueba de la existencia de la obligación. Presunción de fuente legítima.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prueba', 'existencia', 'obligacin', 'articulo 727'], segments: [], amendments: [] },
  { id: 'ccyc-art-728', lawId: 'codigo-civil-comercial', number: '728', order: 728, title: "Deber moral", originalText: "Deber moral. Lo entregado en cumplimiento de deberes morales o de conciencia es irrepetible.", currentText: "Deber moral. Lo entregado en cumplimiento de deberes morales o de conciencia es irrepetible.", plainLanguageExplanation: "Establece el régimen de deber moral. Lo entregado en cumplimiento de deberes morales o de conciencia es irrepetible.", practicalEffects: ['En la práctica, este artículo rige deber moral. Lo entregado en cumplimiento de deberes morales o de conciencia es irrepetible.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['deber', 'moral', 'articulo 728'], segments: [], amendments: [] },
  { id: 'ccyc-art-729', lawId: 'codigo-civil-comercial', number: '729', order: 729, title: "Buena fe", originalText: "Buena fe. Deudor y acreedor deben obrar con cuidado, previsión y según las exigencias de la buena fe.", currentText: "Buena fe. Deudor y acreedor deben obrar con cuidado, previsión y según las exigencias de la buena fe.", plainLanguageExplanation: "Establece el régimen de buena fe. Deudor y acreedor deben obrar con cuidado, previsión y según las exigencias de la buena fe.", practicalEffects: ['En la práctica, este artículo rige buena fe. Deudor y acreedor deben obrar con cuidado, previsión y según las exigencias de la buena fe.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['buenaarticulo 729'], segments: [], amendments: [] },
  { id: 'ccyc-art-730', lawId: 'codigo-civil-comercial', number: '730', order: 730, title: "Efectos con relación al acreedor", originalText: "Efectos con relación al acreedor. La obligación da derecho al acreedor a: a) emplear los medios legales para que el deudor le procure aquello a que se ha obligado; b) hacérselo procurar por otro a costa del deudor; c) obtener del deudor las indemnizaciones correspondientes. Si el incumplimiento de la obligación, cualquiera sea su fuente, deriva en litigio judicial o arbitral, la responsabilidad por el pago de las costas, incluidos los honorarios profesionales, de todo tipo, allí devengados y correspondientes a la primera o única instancia, no debe exceder del veinticinco por ciento del monto de la sentencia, laudo, transacción o instrumento que ponga fin al diferendo. Si las regulaciones de honorarios practicadas conforme a las leyes arancelarias o usos locales, correspondientes a todas las profesiones y especialidades, superan dicho porcentaje, el juez debe proceder a prorratear los montos entre los beneficiarios. Para el cómputo del porcentaje indicado, no se debe tener en cuenta el monto de los honorarios de los profesionales que han representado, patrocinado o asistido a la parte condenada en costas.", currentText: "Efectos con relación al acreedor. La obligación da derecho al acreedor a: a) emplear los medios legales para que el deudor le procure aquello a que se ha obligado; b) hacérselo procurar por otro a costa del deudor; c) obtener del deudor las indemnizaciones correspondientes. Si el incumplimiento de la obligación, cualquiera sea su fuente, deriva en litigio judicial o arbitral, la responsabilidad por el pago de las costas, incluidos los honorarios profesionales, de todo tipo, allí devengados y correspondientes a la primera o única instancia, no debe exceder del veinticinco por ciento del monto de la sentencia, laudo, transacción o instrumento que ponga fin al diferendo. Si las regulaciones de honorarios practicadas conforme a las leyes arancelarias o usos locales, correspondientes a todas las profesiones y especialidades, superan dicho porcentaje, el juez debe proceder a prorratear los montos entre los beneficiarios. Para el cómputo del porcentaje indicado, no se debe tener en cuenta el monto de los honorarios de los profesionales que han representado, patrocinado o asistido a la parte condenada en costas.", plainLanguageExplanation: "Establece el régimen de efectos con relación al acreedor. La obligación da derecho al acreedor a: a) emplear los medios legales para que el deudor le procure aquello a que se ha obligado; b) hacérselo procurar por otro a costa del deudor; c) obtener del deudor las indemnizaciones correspondientes.", practicalEffects: ['En la práctica, este artículo rige efectos con relación al acreedor. La obligación da derecho al acreedor a: a) emplear los medios legales para que el deudor le procure aquello a que se ha obligado; b) hacérselo procura'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'relacin', 'acreedor', 'articulo 730'], segments: [], amendments: [] },
  { id: 'ccyc-art-731', lawId: 'codigo-civil-comercial', number: '731', order: 731, title: "Efectos con relación al deudor", originalText: "Efectos con relación al deudor. El cumplimiento exacto de la obligación confiere al deudor el derecho a obtener la liberación y el de rechazar las acciones del acreedor.", currentText: "Efectos con relación al deudor. El cumplimiento exacto de la obligación confiere al deudor el derecho a obtener la liberación y el de rechazar las acciones del acreedor.", plainLanguageExplanation: "Establece el régimen de efectos con relación al deudor. El cumplimiento exacto de la obligación confiere al deudor el derecho a obtener la liberación y el de rechazar las acciones del acreedor.", practicalEffects: ['En la práctica, este artículo rige efectos con relación al deudor. El cumplimiento exacto de la obligación confiere al deudor el derecho a obtener la liberación y el de rechazar las acciones del acreedor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'relacin', 'deudor', 'articulo 731'], segments: [], amendments: [] },
  { id: 'ccyc-art-732', lawId: 'codigo-civil-comercial', number: '732', order: 732, title: "Actuación de auxiliares", originalText: "Actuación de auxiliares. Principio de equiparación. El incumplimiento de las personas de las que el deudor se sirve para la ejecución de la obligación se equipara al derivado del propio hecho del obligado.", currentText: "Actuación de auxiliares. Principio de equiparación. El incumplimiento de las personas de las que el deudor se sirve para la ejecución de la obligación se equipara al derivado del propio hecho del obligado.", plainLanguageExplanation: "Establece el régimen de actuación de auxiliares. Principio de equiparación.", practicalEffects: ['En la práctica, este artículo rige actuación de auxiliares. Principio de equiparación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actuacin', 'auxiliares', 'articulo 732'], segments: [], amendments: [] },
  { id: 'ccyc-art-733', lawId: 'codigo-civil-comercial', number: '733', order: 733, title: "Reconocimiento de la obligación", originalText: "Reconocimiento de la obligación. El reconocimiento consiste en una manifestación de voluntad, expresa o tácita, por la que el deudor admite estar obligado al cumplimiento de una prestación.", currentText: "Reconocimiento de la obligación. El reconocimiento consiste en una manifestación de voluntad, expresa o tácita, por la que el deudor admite estar obligado al cumplimiento de una prestación.", plainLanguageExplanation: "Establece el régimen de reconocimiento de la obligación. El reconocimiento consiste en una manifestación de voluntad, expresa o tácita, por la que el deudor admite estar obligado al cumplimiento de una prestación.", practicalEffects: ['En la práctica, este artículo rige reconocimiento de la obligación. El reconocimiento consiste en una manifestación de voluntad, expresa o tácita, por la que el deudor admite estar obligado al cumplimiento de una prest'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reconocimiento', 'obligacin', 'articulo 733'], segments: [], amendments: [] },
  { id: 'ccyc-art-734', lawId: 'codigo-civil-comercial', number: '734', order: 734, title: "Reconocimiento y promesa autónoma", originalText: "Reconocimiento y promesa autónoma. El reconocimiento puede referirse a un título o causa anterior; también puede constituir una promesa autónoma de deuda.", currentText: "Reconocimiento y promesa autónoma. El reconocimiento puede referirse a un título o causa anterior; también puede constituir una promesa autónoma de deuda.", plainLanguageExplanation: "Establece el régimen de reconocimiento y promesa autónoma. El reconocimiento puede referirse a un título o causa anterior; también puede constituir una promesa autónoma de deuda.", practicalEffects: ['En la práctica, este artículo rige reconocimiento y promesa autónoma. El reconocimiento puede referirse a un título o causa anterior; también puede constituir una promesa autónoma de deuda.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reconocimiento', 'promesa', 'autnoma', 'articulo 734'], segments: [], amendments: [] },
  { id: 'ccyc-art-735', lawId: 'codigo-civil-comercial', number: '735', order: 735, title: "Reconocimiento causal", originalText: "Reconocimiento causal. Si el acto del reconocimiento agrava la prestación original, o la modifica en perjuicio del deudor, debe estarse al título originario, si no hay una nueva y lícita causa de deber. CAPITULO 2 Acciones y garantía común de los acreedores SECCION 1ª Acción directa", currentText: "Reconocimiento causal. Si el acto del reconocimiento agrava la prestación original, o la modifica en perjuicio del deudor, debe estarse al título originario, si no hay una nueva y lícita causa de deber. CAPITULO 2 Acciones y garantía común de los acreedores SECCION 1ª Acción directa", plainLanguageExplanation: "Establece el régimen de reconocimiento causal. Si el acto del reconocimiento agrava la prestación original, o la modifica en perjuicio del deudor, debe estarse al título originario, si no hay una nueva y lícita causa de deber.", practicalEffects: ['En la práctica, este artículo rige reconocimiento causal. Si el acto del reconocimiento agrava la prestación original, o la modifica en perjuicio del deudor, debe estarse al título originario, si no hay una nueva y lícita causa de deber.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reconocimiento', 'causal', 'articulo 735'], segments: [], amendments: [] },
  { id: 'ccyc-art-736', lawId: 'codigo-civil-comercial', number: '736', order: 736, title: "Acción directa", originalText: "Acción directa. Acción directa es la que compete al acreedor para percibir lo que un tercero debe a su deudor, hasta el importe del propio crédito. El acreedor la ejerce por derecho propio y en su exclusivo beneficio. Tiene carácter excepcional, es de interpretación restrictiva, y sólo procede en los casos expresamente previstos por la ley.", currentText: "Acción directa. Acción directa es la que compete al acreedor para percibir lo que un tercero debe a su deudor, hasta el importe del propio crédito. El acreedor la ejerce por derecho propio y en su exclusivo beneficio. Tiene carácter excepcional, es de interpretación restrictiva, y sólo procede en los casos expresamente previstos por la ley.", plainLanguageExplanation: "Establece el régimen de acción directa. Acción directa es la que compete al acreedor para percibir lo que un tercero debe a su deudor, hasta el importe del propio crédito.", practicalEffects: ['En la práctica, este artículo rige acción directa. Acción directa es la que compete al acreedor para percibir lo que un tercero debe a su deudor, hasta el importe del propio crédito.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accin', 'directa', 'articulo 736'], segments: [], amendments: [] },
  { id: 'ccyc-art-737', lawId: 'codigo-civil-comercial', number: '737', order: 737, title: "Requisitos de ejercicio", originalText: "Requisitos de ejercicio. El ejercicio de la acción directa por el acreedor requiere el cumplimiento de los siguientes requisitos: a) un crédito exigible del acreedor contra su propio deudor; b) una deuda correlativa exigible del tercero demandado a favor del deudor; c) homogeneidad de ambos créditos entre sí; d) ninguno de los dos créditos debe haber sido objeto de embargo anterior a la promoción de la acción directa; e) citación del deudor a juicio.", currentText: "Requisitos de ejercicio. El ejercicio de la acción directa por el acreedor requiere el cumplimiento de los siguientes requisitos: a) un crédito exigible del acreedor contra su propio deudor; b) una deuda correlativa exigible del tercero demandado a favor del deudor; c) homogeneidad de ambos créditos entre sí; d) ninguno de los dos créditos debe haber sido objeto de embargo anterior a la promoción de la acción directa; e) citación del deudor a juicio.", plainLanguageExplanation: "Establece el régimen de requisitos de ejercicio. El ejercicio de la acción directa por el acreedor requiere el cumplimiento de los siguientes requisitos: a) un crédito exigible del acreedor contra su propio deudor; b) una deuda correlativa exigible del tercero demandado a favor del deudor; c) homogeneidad de ambos créditos entr", practicalEffects: ['En la práctica, este artículo rige requisitos de ejercicio. El ejercicio de la acción directa por el acreedor requiere el cumplimiento de los siguientes requisitos: a) un crédito exigible del acreedor contra su'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitos', 'ejercicio', 'articulo 737'], segments: [], amendments: [] },
  { id: 'ccyc-art-738', lawId: 'codigo-civil-comercial', number: '738', order: 738, title: "Efectos", originalText: "Efectos. La acción directa produce los siguientes efectos: a) la notificación de la demanda causa el embargo del crédito a favor del demandante; b) el reclamo sólo puede prosperar hasta el monto menor de las dos obligaciones; c) el tercero demandado puede oponer al progreso de la acción todas las defensas que tenga contra su propio acreedor y contra el demandante; d) el monto percibido por el actor ingresa directamente a su patrimonio; e) el deudor se libera frente a su acreedor en la medida en que corresponda en función del pago efectuado por el demandado. SECCION 2ª Acción subrogatoria", currentText: "Efectos. La acción directa produce los siguientes efectos: a) la notificación de la demanda causa el embargo del crédito a favor del demandante; b) el reclamo sólo puede prosperar hasta el monto menor de las dos obligaciones; c) el tercero demandado puede oponer al progreso de la acción todas las defensas que tenga contra su propio acreedor y contra el demandante; d) el monto percibido por el actor ingresa directamente a su patrimonio; e) el deudor se libera frente a su acreedor en la medida en que corresponda en función del pago efectuado por el demandado. SECCION 2ª Acción subrogatoria", plainLanguageExplanation: "Establece el régimen de efectos. La acción directa produce los siguientes efectos: a) la notificación de la demanda causa el embargo del crédito a favor del demandante; b) el reclamo sólo puede prosperar hasta el monto menor de las dos obligaciones; c) el tercero demandado puede oponer al progreso de la acción t", practicalEffects: ['En la práctica, este artículo rige efectos. La acción directa produce los siguientes efectos: a) la notificación de la demanda causa el embargo del crédito a favor del demandante; b) el reclamo'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 738'], segments: [], amendments: [] },
  { id: 'ccyc-art-739', lawId: 'codigo-civil-comercial', number: '739', order: 739, title: "Acción subrogatoria", originalText: "Acción subrogatoria. El acreedor de un crédito cierto, exigible o no, puede ejercer judicialmente los derechos patrimoniales de su deudor, si éste es remiso en hacerlo y esa omisión afecta el cobro de su acreencia. El acreedor no goza de preferencia alguna sobre los bienes obtenidos por ese medio.", currentText: "Acción subrogatoria. El acreedor de un crédito cierto, exigible o no, puede ejercer judicialmente los derechos patrimoniales de su deudor, si éste es remiso en hacerlo y esa omisión afecta el cobro de su acreencia. El acreedor no goza de preferencia alguna sobre los bienes obtenidos por ese medio.", plainLanguageExplanation: "Establece el régimen de acción subrogatoria. El acreedor de un crédito cierto, exigible o no, puede ejercer judicialmente los derechos patrimoniales de su deudor, si éste es remiso en hacerlo y esa omisión afecta el cobro de su acreencia.", practicalEffects: ['En la práctica, este artículo rige acción subrogatoria. El acreedor de un crédito cierto, exigible o no, puede ejercer judicialmente los derechos patrimoniales de su deudor, si éste es remiso en hacerlo y esa omisión afecta el cobro de su acreencia.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accin', 'subrogatoria', 'articulo 739'], segments: [], amendments: [] },
  { id: 'ccyc-art-740', lawId: 'codigo-civil-comercial', number: '740', order: 740, title: "Citación del deudor", originalText: "Citación del deudor. El deudor debe ser citado para que tome intervención en el juicio respectivo.", currentText: "Citación del deudor. El deudor debe ser citado para que tome intervención en el juicio respectivo.", plainLanguageExplanation: "Establece el régimen de citación del deudor. El deudor debe ser citado para que tome intervención en el juicio respectivo.", practicalEffects: ['En la práctica, este artículo rige citación del deudor. El deudor debe ser citado para que tome intervención en el juicio respectivo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['citacin', 'deudor', 'articulo 740'], segments: [], amendments: [] },
  { id: 'ccyc-art-741', lawId: 'codigo-civil-comercial', number: '741', order: 741, title: "Derechos excluidos", originalText: "Derechos excluidos. Están excluidos de la acción subrogatoria: a) los derechos y acciones que, por su naturaleza o por disposición de la ley, sólo pueden ser ejercidos por su titular; b) los derechos y acciones sustraídos de la garantía colectiva de los acreedores; c) las meras facultades, excepto que de su ejercicio pueda resultar una mejora en la situación patrimonial del deudor.", currentText: "Derechos excluidos. Están excluidos de la acción subrogatoria: a) los derechos y acciones que, por su naturaleza o por disposición de la ley, sólo pueden ser ejercidos por su titular; b) los derechos y acciones sustraídos de la garantía colectiva de los acreedores; c) las meras facultades, excepto que de su ejercicio pueda resultar una mejora en la situación patrimonial del deudor.", plainLanguageExplanation: "Establece el régimen de derechos excluidos. Están excluidos de la acción subrogatoria: a) los derechos y acciones que, por su naturaleza o por disposición de la ley, sólo pueden ser ejercidos por su titular; b) los derechos y acciones sustraídos de la garantía colectiva de los acreedores; c) las meras facultades, excepto q", practicalEffects: ['En la práctica, este artículo rige derechos excluidos. Están excluidos de la acción subrogatoria: a) los derechos y acciones que, por su naturaleza o por disposición de la ley, sólo pueden ser ejercidos po'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos', 'excluidos', 'articulo 741'], segments: [], amendments: [] },
  { id: 'ccyc-art-742', lawId: 'codigo-civil-comercial', number: '742', order: 742, title: "Defensas oponibles", originalText: "Defensas oponibles. Pueden oponerse al acreedor todas las excepciones y causas de extinción de su crédito, aun cuando provengan de hechos del deudor posteriores a la demanda, siempre que éstos no sean en fraude de los derechos del acreedor. SECCION 3ª Garantía común de los acreedores", currentText: "Defensas oponibles. Pueden oponerse al acreedor todas las excepciones y causas de extinción de su crédito, aun cuando provengan de hechos del deudor posteriores a la demanda, siempre que éstos no sean en fraude de los derechos del acreedor. SECCION 3ª Garantía común de los acreedores", plainLanguageExplanation: "Establece el régimen de defensas oponibles. Pueden oponerse al acreedor todas las excepciones y causas de extinción de su crédito, aun cuando provengan de hechos del deudor posteriores a la demanda, siempre que éstos no sean en fraude de los derechos del acreedor.", practicalEffects: ['En la práctica, este artículo rige defensas oponibles. Pueden oponerse al acreedor todas las excepciones y causas de extinción de su crédito, aun cuando provengan de hechos del deudor posteriores a la dema'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['defensas', 'oponibles', 'articulo 742'], segments: [], amendments: [] },
  { id: 'ccyc-art-743', lawId: 'codigo-civil-comercial', number: '743', order: 743, title: "Bienes que constituyen la garantía", originalText: "Bienes que constituyen la garantía. Los bienes presentes y futuros del deudor constituyen la garantía común de sus acreedores. El acreedor puede exigir la venta judicial de los bienes del deudor, pero sólo en la medida necesaria para satisfacer su crédito. Todos los acreedores pueden ejecutar estos bienes en posición igualitaria, excepto que exista una causa legal de preferencia.", currentText: "Bienes que constituyen la garantía. Los bienes presentes y futuros del deudor constituyen la garantía común de sus acreedores. El acreedor puede exigir la venta judicial de los bienes del deudor, pero sólo en la medida necesaria para satisfacer su crédito. Todos los acreedores pueden ejecutar estos bienes en posición igualitaria, excepto que exista una causa legal de preferencia.", plainLanguageExplanation: "Establece el régimen de bienes que constituyen la garantía. Los bienes presentes y futuros del deudor constituyen la garantía común de sus acreedores.", practicalEffects: ['En la práctica, este artículo rige bienes que constituyen la garantía. Los bienes presentes y futuros del deudor constituyen la garantía común de sus acreedores.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['bienes', 'constituyen', 'garanta', 'articulo 743'], segments: [], amendments: [] },
  { id: 'ccyc-art-744', lawId: 'codigo-civil-comercial', number: '744', order: 744, title: "Bienes excluidos de la garantía común", originalText: "Bienes excluidos de la garantía común. Quedan excluidos de la garantía prevista en el artículo 743: a) las ropas y muebles de uso indispensable del deudor, de su cónyuge o conviviente, y de sus hijos; b) los instrumentos necesarios para el ejercicio personal de la profesión, arte u oficio del deudor; c) los sepulcros afectados a su destino, excepto que se reclame su precio de venta, construcción o reparación; d) los bienes afectados a cualquier religión reconocida por el Estado; e) los derechos de usufructo, uso y habitación, así como las servidumbres prediales, que sólo pueden ejecutarse en los términos de los artículos 2144, 2157 y 2178; f) las indemnizaciones que corresponden al deudor por daño moral y por daño material derivado de lesiones a su integridad psicofísica; g) la indemnización por alimentos que corresponde al cónyuge, al conviviente y a los hijos con derecho alimentario, en caso de homicidio; h) los demás bienes declarados inembargables o excluidos por otras leyes.", currentText: "Bienes excluidos de la garantía común. Quedan excluidos de la garantía prevista en el artículo 743: a) las ropas y muebles de uso indispensable del deudor, de su cónyuge o conviviente, y de sus hijos; b) los instrumentos necesarios para el ejercicio personal de la profesión, arte u oficio del deudor; c) los sepulcros afectados a su destino, excepto que se reclame su precio de venta, construcción o reparación; d) los bienes afectados a cualquier religión reconocida por el Estado; e) los derechos de usufructo, uso y habitación, así como las servidumbres prediales, que sólo pueden ejecutarse en los términos de los artículos 2144, 2157 y 2178; f) las indemnizaciones que corresponden al deudor por daño moral y por daño material derivado de lesiones a su integridad psicofísica; g) la indemnización por alimentos que corresponde al cónyuge, al conviviente y a los hijos con derecho alimentario, en caso de homicidio; h) los demás bienes declarados inembargables o excluidos por otras leyes.", plainLanguageExplanation: "Establece el régimen de bienes excluidos de la garantía común. Quedan excluidos de la garantía prevista en el artículo 743: a) las ropas y muebles de uso indispensable del deudor, de su cónyuge o conviviente, y de sus hijos; b) los instrumentos necesarios para el ejercicio personal de la profesión, arte u oficio del deudor; c) los sepulcros", practicalEffects: ['En la práctica, este artículo rige bienes excluidos de la garantía común. Quedan excluidos de la garantía prevista en el artículo 743: a) las ropas y muebles de uso indispensable del deudor, de su cónyuge o conviviente, y de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['bienes', 'excluidos', 'garanta', 'comn', 'articulo 744'], segments: [], amendments: [] },
  { id: 'ccyc-art-745', lawId: 'codigo-civil-comercial', number: '745', order: 745, title: "Prioridad del primer embargante", originalText: "Prioridad del primer embargante. El acreedor que obtuvo el embargo de bienes de su deudor tiene derecho a cobrar su crédito, intereses y costas, con preferencia a otros acreedores. Esta prioridad sólo es oponible a los acreedores quirografarios en los procesos individuales. Si varios acreedores embargan el mismo bien del deudor, el rango entre ellos se determina por la fecha de la traba de la medida. Los embargos posteriores deben afectar únicamente el sobrante que quede después de pagados los créditos que hayan obtenido embargos anteriores. CAPITULO 3 Clases de obligaciones SECCION 1ª Obligaciones de dar Parágrafo 1° Disposiciones generales", currentText: "Prioridad del primer embargante. El acreedor que obtuvo el embargo de bienes de su deudor tiene derecho a cobrar su crédito, intereses y costas, con preferencia a otros acreedores. Esta prioridad sólo es oponible a los acreedores quirografarios en los procesos individuales. Si varios acreedores embargan el mismo bien del deudor, el rango entre ellos se determina por la fecha de la traba de la medida. Los embargos posteriores deben afectar únicamente el sobrante que quede después de pagados los créditos que hayan obtenido embargos anteriores. CAPITULO 3 Clases de obligaciones SECCION 1ª Obligaciones de dar Parágrafo 1° Disposiciones generales", plainLanguageExplanation: "Establece el régimen de prioridad del primer embargante. El acreedor que obtuvo el embargo de bienes de su deudor tiene derecho a cobrar su crédito, intereses y costas, con preferencia a otros acreedores.", practicalEffects: ['En la práctica, este artículo rige prioridad del primer embargante. El acreedor que obtuvo el embargo de bienes de su deudor tiene derecho a cobrar su crédito, intereses y costas, con preferencia a otros acreedores.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prioridad', 'primer', 'embargante', 'articulo 745'], segments: [], amendments: [] },
  { id: 'ccyc-art-746', lawId: 'codigo-civil-comercial', number: '746', order: 746, title: "Efectos", originalText: "Efectos. El deudor de una cosa cierta está obligado a conservarla en el mismo estado en que se encontraba cuando contrajo la obligación, y entregarla con sus accesorios, aunque hayan sido momentáneamente separados de ella.", currentText: "Efectos. El deudor de una cosa cierta está obligado a conservarla en el mismo estado en que se encontraba cuando contrajo la obligación, y entregarla con sus accesorios, aunque hayan sido momentáneamente separados de ella.", plainLanguageExplanation: "Establece el régimen de efectos. El deudor de una cosa cierta está obligado a conservarla en el mismo estado en que se encontraba cuando contrajo la obligación, y entregarla con sus accesorios, aunque hayan sido momentáneamente separados de ella.", practicalEffects: ['En la práctica, este artículo rige efectos. El deudor de una cosa cierta está obligado a conservarla en el mismo estado en que se encontraba cuando contrajo la obligación, y entregarla con sus a'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 746'], segments: [], amendments: [] },
  { id: 'ccyc-art-747', lawId: 'codigo-civil-comercial', number: '747', order: 747, title: "Entrega", originalText: "Entrega. Cualquiera de las partes tiene derecho a requerir la inspección de la cosa en el acto de su entrega. La recepción de la cosa por el acreedor hace presumir la inexistencia de vicios aparentes y la calidad adecuada de la cosa, sin perjuicio de lo dispuesto sobre la obligación de saneamiento en la Sección 4ª, Capítulo 9, Título II del Libro Tercero.", currentText: "Entrega. Cualquiera de las partes tiene derecho a requerir la inspección de la cosa en el acto de su entrega. La recepción de la cosa por el acreedor hace presumir la inexistencia de vicios aparentes y la calidad adecuada de la cosa, sin perjuicio de lo dispuesto sobre la obligación de saneamiento en la Sección 4ª, Capítulo 9, Título II del Libro Tercero.", plainLanguageExplanation: "Establece el régimen de entrega. Cualquiera de las partes tiene derecho a requerir la inspección de la cosa en el acto de su entrega.", practicalEffects: ['En la práctica, este artículo rige entrega. Cualquiera de las partes tiene derecho a requerir la inspección de la cosa en el acto de su entrega.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['entregaarticulo 747'], segments: [], amendments: [] },
  { id: 'ccyc-art-748', lawId: 'codigo-civil-comercial', number: '748', order: 748, title: "Entrega de cosa mueble cerrada o bajo cubierta", originalText: "Entrega de cosa mueble cerrada o bajo cubierta. Cuando se entrega una cosa mueble bajo cubierta y sin inspeccionar al tiempo de la tradición, el acreedor tiene un plazo de caducidad de tres días desde la recepción para reclamar por defectos de cantidad, calidad o vicios aparentes.", currentText: "Entrega de cosa mueble cerrada o bajo cubierta. Cuando se entrega una cosa mueble bajo cubierta y sin inspeccionar al tiempo de la tradición, el acreedor tiene un plazo de caducidad de tres días desde la recepción para reclamar por defectos de cantidad, calidad o vicios aparentes.", plainLanguageExplanation: "Establece el régimen de entrega de cosa mueble cerrada o bajo cubierta. Cuando se entrega una cosa mueble bajo cubierta y sin inspeccionar al tiempo de la tradición, el acreedor tiene un plazo de caducidad de tres días desde la recepción para reclamar por defectos de cantidad, calidad o vicios aparentes.", practicalEffects: ['En la práctica, este artículo rige entrega de cosa mueble cerrada o bajo cubierta. Cuando se entrega una cosa mueble bajo cubierta y sin inspeccionar al tiempo de la tradición, el acreedor tiene un plazo de caducidad de tres días des'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['entrega', 'cosa', 'mueble', 'cerrada', 'bajo', 'cubierta', 'articulo 748'], segments: [], amendments: [] },
  { id: 'ccyc-art-749', lawId: 'codigo-civil-comercial', number: '749', order: 749, title: "Obligación de dar cosas ciertas para transferir el uso o la tenencia", originalText: "Obligación de dar cosas ciertas para transferir el uso o la tenencia. Remisión. Cuando la obligación de dar una cosa determinada tenga por objeto transferir solamente el uso o la tenencia de ella, se aplican las normas contenidas en los títulos especiales. Parágrafo 2° Obligaciones de dar cosa cierta para constituir derechos reales", currentText: "Obligación de dar cosas ciertas para transferir el uso o la tenencia. Remisión. Cuando la obligación de dar una cosa determinada tenga por objeto transferir solamente el uso o la tenencia de ella, se aplican las normas contenidas en los títulos especiales. Parágrafo 2° Obligaciones de dar cosa cierta para constituir derechos reales", plainLanguageExplanation: "Establece el régimen de obligación de dar cosas ciertas para transferir el uso o la tenencia. Remisión.", practicalEffects: ['En la práctica, este artículo rige obligación de dar cosas ciertas para transferir el uso o la tenencia. Remisión.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacin', 'cosas', 'ciertas', 'para', 'transferir', 'tenencia', 'articulo 749'], segments: [], amendments: [] },
  { id: 'ccyc-art-750', lawId: 'codigo-civil-comercial', number: '750', order: 750, title: "Tradición", originalText: "Tradición. El acreedor no adquiere ningún derecho real sobre la cosa antes de la tradición, excepto disposición legal en contrario.", currentText: "Tradición. El acreedor no adquiere ningún derecho real sobre la cosa antes de la tradición, excepto disposición legal en contrario.", plainLanguageExplanation: "Establece el régimen de tradición. El acreedor no adquiere ningún derecho real sobre la cosa antes de la tradición, excepto disposición legal en contrario.", practicalEffects: ['En la práctica, este artículo rige tradición. El acreedor no adquiere ningún derecho real sobre la cosa antes de la tradición, excepto disposición legal en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tradicinarticulo 750'], segments: [], amendments: [] },
  { id: 'ccyc-art-751', lawId: 'codigo-civil-comercial', number: '751', order: 751, title: "Mejoras", originalText: "Mejoras. Concepto y clases. Mejora es el aumento del valor intrínseco de la cosa. Las mejoras pueden ser naturales o artificiales. Las artificiales, provenientes de hecho del hombre, se clasifican en necesarias, útiles y de mero lujo, recreo o suntuarias.", currentText: "Mejoras. Concepto y clases. Mejora es el aumento del valor intrínseco de la cosa. Las mejoras pueden ser naturales o artificiales. Las artificiales, provenientes de hecho del hombre, se clasifican en necesarias, útiles y de mero lujo, recreo o suntuarias.", plainLanguageExplanation: "Establece el régimen de mejoras. Concepto y clases.", practicalEffects: ['En la práctica, este artículo rige mejoras. Concepto y clases.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mejorasarticulo 751'], segments: [], amendments: [] },
  { id: 'ccyc-art-752', lawId: 'codigo-civil-comercial', number: '752', order: 752, title: "Mejora natural", originalText: "Mejora natural. Efectos. La mejora natural autoriza al deudor a exigir un mayor valor. Si el acreedor no lo acepta, la obligación queda extinguida, sin responsabilidad para ninguna de las partes.", currentText: "Mejora natural. Efectos. La mejora natural autoriza al deudor a exigir un mayor valor. Si el acreedor no lo acepta, la obligación queda extinguida, sin responsabilidad para ninguna de las partes.", plainLanguageExplanation: "Establece el régimen de mejora natural. Efectos.", practicalEffects: ['En la práctica, este artículo rige mejora natural. Efectos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mejora', 'natural', 'articulo 752'], segments: [], amendments: [] },
  { id: 'ccyc-art-753', lawId: 'codigo-civil-comercial', number: '753', order: 753, title: "Mejoras artificiales", originalText: "Mejoras artificiales. El deudor está obligado a realizar las mejoras necesarias, sin derecho a percibir su valor. No tiene derecho a reclamar indemnización por las mejoras útiles ni por las de mero lujo, recreo o suntuarias, pero puede retirarlas en tanto no deterioren la cosa.", currentText: "Mejoras artificiales. El deudor está obligado a realizar las mejoras necesarias, sin derecho a percibir su valor. No tiene derecho a reclamar indemnización por las mejoras útiles ni por las de mero lujo, recreo o suntuarias, pero puede retirarlas en tanto no deterioren la cosa.", plainLanguageExplanation: "Establece el régimen de mejoras artificiales. El deudor está obligado a realizar las mejoras necesarias, sin derecho a percibir su valor.", practicalEffects: ['En la práctica, este artículo rige mejoras artificiales. El deudor está obligado a realizar las mejoras necesarias, sin derecho a percibir su valor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mejoras', 'artificiales', 'articulo 753'], segments: [], amendments: [] },
  { id: 'ccyc-art-754', lawId: 'codigo-civil-comercial', number: '754', order: 754, title: "Frutos", originalText: "Frutos. Hasta el día de la tradición los frutos percibidos le pertenecen al deudor; a partir de esa fecha, los frutos devengados y los no percibidos le corresponden al acreedor.", currentText: "Frutos. Hasta el día de la tradición los frutos percibidos le pertenecen al deudor; a partir de esa fecha, los frutos devengados y los no percibidos le corresponden al acreedor.", plainLanguageExplanation: "Establece el régimen de frutos. Hasta el día de la tradición los frutos percibidos le pertenecen al deudor; a partir de esa fecha, los frutos devengados y los no percibidos le corresponden al acreedor.", practicalEffects: ['En la práctica, este artículo rige frutos. Hasta el día de la tradición los frutos percibidos le pertenecen al deudor; a partir de esa fecha, los frutos devengados y los no percibidos le corres'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['frutosarticulo 754'], segments: [], amendments: [] },
  { id: 'ccyc-art-755', lawId: 'codigo-civil-comercial', number: '755', order: 755, title: "Riesgos de la cosa", originalText: "Riesgos de la cosa. El propietario soporta los riesgos de la cosa. Los casos de deterioro o pérdida, con o sin culpa, se rigen por lo dispuesto sobre la imposibilidad de cumplimiento.", currentText: "Riesgos de la cosa. El propietario soporta los riesgos de la cosa. Los casos de deterioro o pérdida, con o sin culpa, se rigen por lo dispuesto sobre la imposibilidad de cumplimiento.", plainLanguageExplanation: "Establece el régimen de riesgos de la cosa. El propietario soporta los riesgos de la cosa.", practicalEffects: ['En la práctica, este artículo rige riesgos de la cosa. El propietario soporta los riesgos de la cosa.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['riesgos', 'cosa', 'articulo 755'], segments: [], amendments: [] },
  { id: 'ccyc-art-756', lawId: 'codigo-civil-comercial', number: '756', order: 756, title: "Concurrencia de varios acreedores", originalText: "Concurrencia de varios acreedores. Bienes inmuebles. Si varios acreedores reclaman la misma cosa inmueble prometida por el deudor, son todos de buena fe y a título oneroso, tiene mejor derecho: a) el que tiene emplazamiento registral y tradición; b) el que ha recibido la tradición; c) el que tiene emplazamiento registral precedente; d) en los demás supuestos, el que tiene título de fecha cierta anterior.", currentText: "Concurrencia de varios acreedores. Bienes inmuebles. Si varios acreedores reclaman la misma cosa inmueble prometida por el deudor, son todos de buena fe y a título oneroso, tiene mejor derecho: a) el que tiene emplazamiento registral y tradición; b) el que ha recibido la tradición; c) el que tiene emplazamiento registral precedente; d) en los demás supuestos, el que tiene título de fecha cierta anterior.", plainLanguageExplanation: "Establece el régimen de concurrencia de varios acreedores. Bienes inmuebles.", practicalEffects: ['En la práctica, este artículo rige concurrencia de varios acreedores. Bienes inmuebles.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['concurrencia', 'varios', 'acreedores', 'articulo 756'], segments: [], amendments: [] },
  { id: 'ccyc-art-757', lawId: 'codigo-civil-comercial', number: '757', order: 757, title: "Concurrencia de varios acreedores", originalText: "Concurrencia de varios acreedores. Bienes muebles. Si varios acreedores reclaman la misma cosa mueble prometida por el deudor, son todos de buena fe y a título oneroso, tiene mejor derecho: a) el que tiene emplazamiento registral precedente, si se trata de bienes muebles registrables; b) el que ha recibido la tradición, si fuese no registrable; c) en los demás supuestos, el que tiene título de fecha cierta anterior.", currentText: "Concurrencia de varios acreedores. Bienes muebles. Si varios acreedores reclaman la misma cosa mueble prometida por el deudor, son todos de buena fe y a título oneroso, tiene mejor derecho: a) el que tiene emplazamiento registral precedente, si se trata de bienes muebles registrables; b) el que ha recibido la tradición, si fuese no registrable; c) en los demás supuestos, el que tiene título de fecha cierta anterior.", plainLanguageExplanation: "Establece el régimen de concurrencia de varios acreedores. Bienes muebles.", practicalEffects: ['En la práctica, este artículo rige concurrencia de varios acreedores. Bienes muebles.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['concurrencia', 'varios', 'acreedores', 'articulo 757'], segments: [], amendments: [] },
  { id: 'ccyc-art-758', lawId: 'codigo-civil-comercial', number: '758', order: 758, title: "Acreedor frustrado", originalText: "Acreedor frustrado. El acreedor de buena fe que resulta frustrado en su derecho, conserva su acción contra el deudor para reclamar los daños y perjuicios sufridos. Parágrafo 3º Obligaciones de dar para restituir", currentText: "Acreedor frustrado. El acreedor de buena fe que resulta frustrado en su derecho, conserva su acción contra el deudor para reclamar los daños y perjuicios sufridos. Parágrafo 3º Obligaciones de dar para restituir", plainLanguageExplanation: "Establece el régimen de acreedor frustrado. El acreedor de buena fe que resulta frustrado en su derecho, conserva su acción contra el deudor para reclamar los daños y perjuicios sufridos.", practicalEffects: ['En la práctica, este artículo rige acreedor frustrado. El acreedor de buena fe que resulta frustrado en su derecho, conserva su acción contra el deudor para reclamar los daños y perjuicios sufridos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acreedor', 'frustrado', 'articulo 758'], segments: [], amendments: [] },
  { id: 'ccyc-art-759', lawId: 'codigo-civil-comercial', number: '759', order: 759, title: "Regla general", originalText: "Regla general. En la obligación de dar para restituir, el deudor debe entregar la cosa al acreedor, quien por su parte puede exigirla. Si quien debe restituir se obligó a entregar la cosa a más de un acreedor, el deudor debe entregarla al dueño, previa citación fehaciente a los otros que la hayan pretendido.", currentText: "Regla general. En la obligación de dar para restituir, el deudor debe entregar la cosa al acreedor, quien por su parte puede exigirla. Si quien debe restituir se obligó a entregar la cosa a más de un acreedor, el deudor debe entregarla al dueño, previa citación fehaciente a los otros que la hayan pretendido.", plainLanguageExplanation: "Establece el régimen de regla general. En la obligación de dar para restituir, el deudor debe entregar la cosa al acreedor, quien por su parte puede exigirla.", practicalEffects: ['En la práctica, este artículo rige regla general. En la obligación de dar para restituir, el deudor debe entregar la cosa al acreedor, quien por su parte puede exigirla.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['regla', 'general', 'articulo 759'], segments: [], amendments: [] },
  { id: 'ccyc-art-760', lawId: 'codigo-civil-comercial', number: '760', order: 760, title: "Entrega de la cosa a quien no es propietario", originalText: "Entrega de la cosa a quien no es propietario. Bienes no registrables. Con relación a terceros, cuando la obligación de dar cosas ciertas tiene por fin restituirlas a su dueño, si la cosa es mueble no registrable y el deudor hace, a título oneroso, tradición de ella a otro por transferencia o constitución de prenda, el acreedor no tiene derecho contra los poseedores de buena fe, sino solamente cuando la cosa le fue robada o se ha perdido. En todos los casos lo tiene contra los poseedores de mala fe.", currentText: "Entrega de la cosa a quien no es propietario. Bienes no registrables. Con relación a terceros, cuando la obligación de dar cosas ciertas tiene por fin restituirlas a su dueño, si la cosa es mueble no registrable y el deudor hace, a título oneroso, tradición de ella a otro por transferencia o constitución de prenda, el acreedor no tiene derecho contra los poseedores de buena fe, sino solamente cuando la cosa le fue robada o se ha perdido. En todos los casos lo tiene contra los poseedores de mala fe.", plainLanguageExplanation: "Establece el régimen de entrega de la cosa a quien no es propietario. Bienes no registrables.", practicalEffects: ['En la práctica, este artículo rige entrega de la cosa a quien no es propietario. Bienes no registrables.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['entrega', 'cosa', 'quien', 'propietario', 'articulo 760'], segments: [], amendments: [] },
  { id: 'ccyc-art-761', lawId: 'codigo-civil-comercial', number: '761', order: 761, title: "Entrega de la cosa a quien no es propietario", originalText: "Entrega de la cosa a quien no es propietario. Bienes registrables. Si la cosa es inmueble o mueble registrable, el acreedor tiene acción real contra terceros que sobre ella aparentemente adquirieron derechos reales, o que la tengan en su posesión por cualquier contrato hecho con el deudor. Parágrafo 4° Obligaciones de género", currentText: "Entrega de la cosa a quien no es propietario. Bienes registrables. Si la cosa es inmueble o mueble registrable, el acreedor tiene acción real contra terceros que sobre ella aparentemente adquirieron derechos reales, o que la tengan en su posesión por cualquier contrato hecho con el deudor. Parágrafo 4° Obligaciones de género", plainLanguageExplanation: "Establece el régimen de entrega de la cosa a quien no es propietario. Bienes registrables.", practicalEffects: ['En la práctica, este artículo rige entrega de la cosa a quien no es propietario. Bienes registrables.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['entrega', 'cosa', 'quien', 'propietario', 'articulo 761'], segments: [], amendments: [] },
  { id: 'ccyc-art-762', lawId: 'codigo-civil-comercial', number: '762', order: 762, title: "Individualización", originalText: "Individualización. La obligación de dar es de género si recae sobre cosas determinadas sólo por su especie y cantidad. Las cosas debidas en una obligación de género deben ser individualizadas. La elección corresponde al deudor, excepto que lo contrario resulte de la convención de las partes. La elección debe recaer sobre cosa de calidad media, y puede ser hecha mediante manifestación de voluntad expresa o tácita.", currentText: "Individualización. La obligación de dar es de género si recae sobre cosas determinadas sólo por su especie y cantidad. Las cosas debidas en una obligación de género deben ser individualizadas. La elección corresponde al deudor, excepto que lo contrario resulte de la convención de las partes. La elección debe recaer sobre cosa de calidad media, y puede ser hecha mediante manifestación de voluntad expresa o tácita.", plainLanguageExplanation: "Establece el régimen de individualización. La obligación de dar es de género si recae sobre cosas determinadas sólo por su especie y cantidad.", practicalEffects: ['En la práctica, este artículo rige individualización. La obligación de dar es de género si recae sobre cosas determinadas sólo por su especie y cantidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['individualizacinarticulo 762'], segments: [], amendments: [] },
  { id: 'ccyc-art-763', lawId: 'codigo-civil-comercial', number: '763', order: 763, title: "Período anterior a la individualización", originalText: "Período anterior a la individualización. Antes de la individualización de la cosa debida, el caso fortuito no libera al deudor. Después de hecha la elección, se aplican las reglas sobre la obligación de dar cosas ciertas. Parágrafo 5° Obligaciones relativas a bienes que no son cosas", currentText: "Período anterior a la individualización. Antes de la individualización de la cosa debida, el caso fortuito no libera al deudor. Después de hecha la elección, se aplican las reglas sobre la obligación de dar cosas ciertas. Parágrafo 5° Obligaciones relativas a bienes que no son cosas", plainLanguageExplanation: "Establece el régimen de período anterior a la individualización. Antes de la individualización de la cosa debida, el caso fortuito no libera al deudor.", practicalEffects: ['En la práctica, este artículo rige período anterior a la individualización. Antes de la individualización de la cosa debida, el caso fortuito no libera al deudor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['perodo', 'anterior', 'individualizacin', 'articulo 763'], segments: [], amendments: [] },
  { id: 'ccyc-art-764', lawId: 'codigo-civil-comercial', number: '764', order: 764, title: "Aplicación de normas", originalText: "Aplicación de normas. Las normas de los Parágrafos 1°, 2°, 3° y 4° de esta Sección se aplican, en lo pertinente, a los casos en que la prestación debida consiste en transmitir, o poner a disposición del acreedor, un bien que no es cosa. Parágrafo 6° Obligaciones de dar dinero", currentText: "Aplicación de normas. Las normas de los Parágrafos 1°, 2°, 3° y 4° de esta Sección se aplican, en lo pertinente, a los casos en que la prestación debida consiste en transmitir, o poner a disposición del acreedor, un bien que no es cosa. Parágrafo 6° Obligaciones de dar dinero", plainLanguageExplanation: "Establece el régimen de aplicación de normas. Las normas de los Parágrafos 1°, 2°, 3° y 4° de esta Sección se aplican, en lo pertinente, a los casos en que la prestación debida consiste en transmitir, o poner a disposición del acreedor, un bien que no es cosa.", practicalEffects: ['En la práctica, este artículo rige aplicación de normas. Las normas de los Parágrafos 1°, 2°, 3° y 4° de esta Sección se aplican, en lo pertinente, a los casos en que la prestación debida consiste en transmi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aplicacin', 'normas', 'articulo 764'], segments: [], amendments: [] },
  { id: 'ccyc-art-765', lawId: 'codigo-civil-comercial', number: '765', order: 765, title: "Concepto", originalText: "Concepto. La obligación es de dar dinero si el deudor debe cierta cantidad de moneda, determinada o determinable, al momento de constitución de la obligación, sea o no de curso legal en el país. El deudor solo se libera si entrega las cantidades comprometidas en la moneda pactada. Los jueces no pueden modificar la forma de pago o la moneda pactada por las partes. (Artículo sustituido por art. 250 del Decreto N° 70/2023 B.O. 21/12/2023)", currentText: "Concepto. La obligación es de dar dinero si el deudor debe cierta cantidad de moneda, determinada o determinable, al momento de constitución de la obligación, sea o no de curso legal en el país. El deudor solo se libera si entrega las cantidades comprometidas en la moneda pactada. Los jueces no pueden modificar la forma de pago o la moneda pactada por las partes. (Artículo sustituido por art. 250 del Decreto N° 70/2023 B.O. 21/12/2023)", plainLanguageExplanation: "Establece el régimen de concepto. La obligación es de dar dinero si el deudor debe cierta cantidad de moneda, determinada o determinable, al momento de constitución de la obligación, sea o no de curso legal en el país.", practicalEffects: ['En la práctica, este artículo rige concepto. La obligación es de dar dinero si el deudor debe cierta cantidad de moneda, determinada o determinable, al momento de constitución de la obligación, sea o no de curso legal en el país.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 765'], segments: [], amendments: [] },
  { id: 'ccyc-art-766', lawId: 'codigo-civil-comercial', number: '766', order: 766, title: "Obligación del deudor", originalText: "Obligación del deudor. El deudor debe entregar la cantidad correspondiente de la especie designada, tanto si la moneda tiene curso legal en la República como si no lo tiene. (Artículo sustituido por art. 251 del Decreto N° 70/2023 B.O. 21/12/2023)", currentText: "Obligación del deudor. El deudor debe entregar la cantidad correspondiente de la especie designada, tanto si la moneda tiene curso legal en la República como si no lo tiene. (Artículo sustituido por art. 251 del Decreto N° 70/2023 B.O. 21/12/2023)", plainLanguageExplanation: "Establece el régimen de obligación del deudor. El deudor debe entregar la cantidad correspondiente de la especie designada, tanto si la moneda tiene curso legal en la República como si no lo tiene.", practicalEffects: ['En la práctica, este artículo rige obligación del deudor. El deudor debe entregar la cantidad correspondiente de la especie designada, tanto si la moneda tiene curso legal en la República como si no lo tiene.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacin', 'deudor', 'articulo 766'], segments: [], amendments: [] },
  { id: 'ccyc-art-767', lawId: 'codigo-civil-comercial', number: '767', order: 767, title: "Intereses compensatorios", originalText: "Intereses compensatorios. La obligación puede llevar intereses y son válidos los que se han convenido entre el deudor y el acreedor, como también la tasa fijada para su liquidación. Si no fue acordada por las partes, ni por las leyes, ni resulta de los usos, la tasa de interés compensatorio puede ser fijada por los jueces.", currentText: "Intereses compensatorios. La obligación puede llevar intereses y son válidos los que se han convenido entre el deudor y el acreedor, como también la tasa fijada para su liquidación. Si no fue acordada por las partes, ni por las leyes, ni resulta de los usos, la tasa de interés compensatorio puede ser fijada por los jueces.", plainLanguageExplanation: "Establece el régimen de intereses compensatorios. La obligación puede llevar intereses y son válidos los que se han convenido entre el deudor y el acreedor, como también la tasa fijada para su liquidación.", practicalEffects: ['En la práctica, este artículo rige intereses compensatorios. La obligación puede llevar intereses y son válidos los que se han convenido entre el deudor y el acreedor, como también la tasa fijada para su liquidación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['intereses', 'compensatorios', 'articulo 767'], segments: [], amendments: [] },
  { id: 'ccyc-art-768', lawId: 'codigo-civil-comercial', number: '768', order: 768, title: "Intereses moratorios", originalText: "Intereses moratorios. A partir de su mora el deudor debe los intereses correspondientes. La tasa se determina: a) por lo que acuerden las partes; b) por lo que dispongan las leyes especiales; c) en subsidio, por tasas que se fijen según las reglamentaciones del Banco Central.", currentText: "Intereses moratorios. A partir de su mora el deudor debe los intereses correspondientes. La tasa se determina: a) por lo que acuerden las partes; b) por lo que dispongan las leyes especiales; c) en subsidio, por tasas que se fijen según las reglamentaciones del Banco Central.", plainLanguageExplanation: "Establece el régimen de intereses moratorios. A partir de su mora el deudor debe los intereses correspondientes.", practicalEffects: ['En la práctica, este artículo rige intereses moratorios. A partir de su mora el deudor debe los intereses correspondientes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['intereses', 'moratorios', 'articulo 768'], segments: [], amendments: [] },
  { id: 'ccyc-art-769', lawId: 'codigo-civil-comercial', number: '769', order: 769, title: "Intereses punitorios", originalText: "Intereses punitorios. Los intereses punitorios convencionales se rigen por las normas que regulan la cláusula penal.", currentText: "Intereses punitorios. Los intereses punitorios convencionales se rigen por las normas que regulan la cláusula penal.", plainLanguageExplanation: "Establece el régimen de intereses punitorios. Los intereses punitorios convencionales se rigen por las normas que regulan la cláusula penal.", practicalEffects: ['En la práctica, este artículo rige intereses punitorios. Los intereses punitorios convencionales se rigen por las normas que regulan la cláusula penal.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['intereses', 'punitorios', 'articulo 769'], segments: [], amendments: [] },
  { id: 'ccyc-art-770', lawId: 'codigo-civil-comercial', number: '770', order: 770, title: "Anatocismo", originalText: "Anatocismo. No se deben intereses de los intereses, excepto que: a) una cláusula expresa autorice la acumulación de los intereses al capital con una periodicidad no inferior a seis meses; b) la obligación se demande judicialmente; en este caso, la acumulación opera desde la fecha de la notificación de la demanda; c) la obligación se liquide judicialmente; en este caso, la capitalización se produce desde que el juez manda pagar la suma resultante y el deudor es moroso en hacerlo; d) otras disposiciones legales prevean la acumulación.", currentText: "Anatocismo. No se deben intereses de los intereses, excepto que: a) una cláusula expresa autorice la acumulación de los intereses al capital con una periodicidad no inferior a seis meses; b) la obligación se demande judicialmente; en este caso, la acumulación opera desde la fecha de la notificación de la demanda; c) la obligación se liquide judicialmente; en este caso, la capitalización se produce desde que el juez manda pagar la suma resultante y el deudor es moroso en hacerlo; d) otras disposiciones legales prevean la acumulación.", plainLanguageExplanation: "Establece el régimen de anatocismo. No se deben intereses de los intereses, excepto que: a) una cláusula expresa autorice la acumulación de los intereses al capital con una periodicidad no inferior a seis meses; b) la obligación se demande judicialmente; en este caso, la acumulación opera desde la fecha de la notif", practicalEffects: ['En la práctica, este artículo rige anatocismo. No se deben intereses de los intereses, excepto que: a) una cláusula expresa autorice la acumulación de los intereses al capital con una periodicidad'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['anatocismoarticulo 770'], segments: [], amendments: [] },
  { id: 'ccyc-art-771', lawId: 'codigo-civil-comercial', number: '771', order: 771, title: "Facultades judiciales", originalText: "Facultades judiciales. Los jueces pueden reducir los intereses cuando la tasa fijada o el resultado que provoque la capitalización de intereses excede, sin justificación y desproporcionadamente, el costo medio del dinero para deudores y operaciones similares en el lugar donde se contrajo la obligación. Los intereses pagados en exceso se imputan al capital y, una vez extinguido éste, pueden ser repetidos.", currentText: "Facultades judiciales. Los jueces pueden reducir los intereses cuando la tasa fijada o el resultado que provoque la capitalización de intereses excede, sin justificación y desproporcionadamente, el costo medio del dinero para deudores y operaciones similares en el lugar donde se contrajo la obligación. Los intereses pagados en exceso se imputan al capital y, una vez extinguido éste, pueden ser repetidos.", plainLanguageExplanation: "Establece el régimen de facultades judiciales. Los jueces pueden reducir los intereses cuando la tasa fijada o el resultado que provoque la capitalización de intereses excede, sin justificación y desproporcionadamente, el costo medio del dinero para deudores y operaciones similares en el lugar donde se contrajo la obligación.", practicalEffects: ['En la práctica, este artículo rige facultades judiciales. Los jueces pueden reducir los intereses cuando la tasa fijada o el resultado que provoque la capitalización de intereses excede, sin justificación y d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['facultades', 'judiciales', 'articulo 771'], segments: [], amendments: [] },
  { id: 'ccyc-art-772', lawId: 'codigo-civil-comercial', number: '772', order: 772, title: "Cuantificación de un valor", originalText: "Cuantificación de un valor. Si la deuda consiste en cierto valor, el monto resultante debe referirse al valor real al momento que corresponda tomar en cuenta para la evaluación de la deuda. Puede ser expresada en una moneda sin curso legal que sea usada habitualmente en el tráfico. Una vez que el valor es cuantificado en dinero se aplican las disposiciones de esta Sección. SECCION 2ª Obligaciones de hacer y de no hacer", currentText: "Cuantificación de un valor. Si la deuda consiste en cierto valor, el monto resultante debe referirse al valor real al momento que corresponda tomar en cuenta para la evaluación de la deuda. Puede ser expresada en una moneda sin curso legal que sea usada habitualmente en el tráfico. Una vez que el valor es cuantificado en dinero se aplican las disposiciones de esta Sección. SECCION 2ª Obligaciones de hacer y de no hacer", plainLanguageExplanation: "Establece el régimen de cuantificación de un valor. Si la deuda consiste en cierto valor, el monto resultante debe referirse al valor real al momento que corresponda tomar en cuenta para la evaluación de la deuda.", practicalEffects: ['En la práctica, este artículo rige cuantificación de un valor. Si la deuda consiste en cierto valor, el monto resultante debe referirse al valor real al momento que corresponda tomar en cuenta para la evaluación de la deuda.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cuantificacin', 'valor', 'articulo 772'], segments: [], amendments: [] },
  { id: 'ccyc-art-773', lawId: 'codigo-civil-comercial', number: '773', order: 773, title: "Concepto", originalText: "Concepto. La obligación de hacer es aquella cuyo objeto consiste en la prestación de un servicio o en la realización de un hecho, en el tiempo, lugar y modo acordados por las partes.", currentText: "Concepto. La obligación de hacer es aquella cuyo objeto consiste en la prestación de un servicio o en la realización de un hecho, en el tiempo, lugar y modo acordados por las partes.", plainLanguageExplanation: "Establece el régimen de concepto. La obligación de hacer es aquella cuyo objeto consiste en la prestación de un servicio o en la realización de un hecho, en el tiempo, lugar y modo acordados por las partes.", practicalEffects: ['En la práctica, este artículo rige concepto. La obligación de hacer es aquella cuyo objeto consiste en la prestación de un servicio o en la realización de un hecho, en el tiempo, lugar y modo aco'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 773'], segments: [], amendments: [] },
  { id: 'ccyc-art-774', lawId: 'codigo-civil-comercial', number: '774', order: 774, title: "Prestación de un servicio", originalText: "Prestación de un servicio. La prestación de un servicio puede consistir: a) en realizar cierta actividad, con la diligencia apropiada, independientemente de su éxito. Las cláusulas que comprometen a los buenos oficios, o a aplicar los mejores esfuerzos están comprendidas en este inciso; b) en procurar al acreedor cierto resultado concreto, con independencia de su eficacia; c) en procurar al acreedor el resultado eficaz prometido. La cláusula llave en mano o producto en mano está comprendida en este inciso. Si el resultado de la actividad del deudor consiste en una cosa, para su entrega se aplican las reglas de las obligaciones de dar cosas ciertas para constituir derechos reales.", currentText: "Prestación de un servicio. La prestación de un servicio puede consistir: a) en realizar cierta actividad, con la diligencia apropiada, independientemente de su éxito. Las cláusulas que comprometen a los buenos oficios, o a aplicar los mejores esfuerzos están comprendidas en este inciso; b) en procurar al acreedor cierto resultado concreto, con independencia de su eficacia; c) en procurar al acreedor el resultado eficaz prometido. La cláusula llave en mano o producto en mano está comprendida en este inciso. Si el resultado de la actividad del deudor consiste en una cosa, para su entrega se aplican las reglas de las obligaciones de dar cosas ciertas para constituir derechos reales.", plainLanguageExplanation: "Establece el régimen de prestación de un servicio. La prestación de un servicio puede consistir: a) en realizar cierta actividad, con la diligencia apropiada, independientemente de su éxito.", practicalEffects: ['En la práctica, este artículo rige prestación de un servicio. La prestación de un servicio puede consistir: a) en realizar cierta actividad, con la diligencia apropiada, independientemente de su éxito.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prestacin', 'servicio', 'articulo 774'], segments: [], amendments: [] },
  { id: 'ccyc-art-775', lawId: 'codigo-civil-comercial', number: '775', order: 775, title: "Realización de un hecho", originalText: "Realización de un hecho. El obligado a realizar un hecho debe cumplirlo en tiempo y modo acordes con la intención de las partes o con la índole de la obligación. Si lo hace de otra manera, la prestación se tiene por incumplida, y el acreedor puede exigir la destrucción de lo mal hecho, siempre que tal exigencia no sea abusiva.", currentText: "Realización de un hecho. El obligado a realizar un hecho debe cumplirlo en tiempo y modo acordes con la intención de las partes o con la índole de la obligación. Si lo hace de otra manera, la prestación se tiene por incumplida, y el acreedor puede exigir la destrucción de lo mal hecho, siempre que tal exigencia no sea abusiva.", plainLanguageExplanation: "Establece el régimen de realización de un hecho. El obligado a realizar un hecho debe cumplirlo en tiempo y modo acordes con la intención de las partes o con la índole de la obligación.", practicalEffects: ['En la práctica, este artículo rige realización de un hecho. El obligado a realizar un hecho debe cumplirlo en tiempo y modo acordes con la intención de las partes o con la índole de la obligación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['realizacin', 'hecho', 'articulo 775'], segments: [], amendments: [] },
  { id: 'ccyc-art-776', lawId: 'codigo-civil-comercial', number: '776', order: 776, title: "Incorporación de terceros", originalText: "Incorporación de terceros. La prestación puede ser ejecutada por persona distinta del deudor, a no ser que de la convención, de la naturaleza de la obligación o de las circunstancias resulte que éste fue elegido por sus cualidades para realizarla personalmente. Esta elección se presume en los contratos que suponen una confianza especial.", currentText: "Incorporación de terceros. La prestación puede ser ejecutada por persona distinta del deudor, a no ser que de la convención, de la naturaleza de la obligación o de las circunstancias resulte que éste fue elegido por sus cualidades para realizarla personalmente. Esta elección se presume en los contratos que suponen una confianza especial.", plainLanguageExplanation: "Establece el régimen de incorporación de terceros. La prestación puede ser ejecutada por persona distinta del deudor, a no ser que de la convención, de la naturaleza de la obligación o de las circunstancias resulte que éste fue elegido por sus cualidades para realizarla personalmente.", practicalEffects: ['En la práctica, este artículo rige incorporación de terceros. La prestación puede ser ejecutada por persona distinta del deudor, a no ser que de la convención, de la naturaleza de la obligación o de las circunsta'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incorporacin', 'terceros', 'articulo 776'], segments: [], amendments: [] },
  { id: 'ccyc-art-777', lawId: 'codigo-civil-comercial', number: '777', order: 777, title: "Ejecución forzada", originalText: "Ejecución forzada. El incumplimiento imputable de la prestación le da derecho al acreedor a: a) exigir el cumplimiento específico; b) hacerlo cumplir por terceros a costa del deudor; c) reclamar los daños y perjuicios.", currentText: "Ejecución forzada. El incumplimiento imputable de la prestación le da derecho al acreedor a: a) exigir el cumplimiento específico; b) hacerlo cumplir por terceros a costa del deudor; c) reclamar los daños y perjuicios.", plainLanguageExplanation: "Establece el régimen de ejecución forzada. El incumplimiento imputable de la prestación le da derecho al acreedor a: a) exigir el cumplimiento específico; b) hacerlo cumplir por terceros a costa del deudor; c) reclamar los daños y perjuicios.", practicalEffects: ['En la práctica, este artículo rige ejecución forzada. El incumplimiento imputable de la prestación le da derecho al acreedor a: a) exigir el cumplimiento específico; b) hacerlo cumplir por terceros a cost'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ejecucin', 'forzada', 'articulo 777'], segments: [], amendments: [] },
  { id: 'ccyc-art-778', lawId: 'codigo-civil-comercial', number: '778', order: 778, title: "Obligación de no hacer", originalText: "Obligación de no hacer. Es aquella que tiene por objeto una abstención del deudor o tolerar una actividad ajena. Su incumplimiento imputable permite reclamar la destrucción física de lo hecho, y los daños y perjuicios. SECCION 3ª Obligaciones alternativas", currentText: "Obligación de no hacer. Es aquella que tiene por objeto una abstención del deudor o tolerar una actividad ajena. Su incumplimiento imputable permite reclamar la destrucción física de lo hecho, y los daños y perjuicios. SECCION 3ª Obligaciones alternativas", plainLanguageExplanation: "Establece el régimen de obligación de no hacer. Es aquella que tiene por objeto una abstención del deudor o tolerar una actividad ajena.", practicalEffects: ['En la práctica, este artículo rige obligación de no hacer. Es aquella que tiene por objeto una abstención del deudor o tolerar una actividad ajena.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacin', 'hacer', 'articulo 778'], segments: [], amendments: [] },
  { id: 'ccyc-art-779', lawId: 'codigo-civil-comercial', number: '779', order: 779, title: "Concepto", originalText: "Concepto. La obligación alternativa tiene por objeto una prestación entre varias que son independientes y distintas entre sí. El deudor está obligado a cumplir una sola de ellas.", currentText: "Concepto. La obligación alternativa tiene por objeto una prestación entre varias que son independientes y distintas entre sí. El deudor está obligado a cumplir una sola de ellas.", plainLanguageExplanation: "Establece el régimen de concepto. La obligación alternativa tiene por objeto una prestación entre varias que son independientes y distintas entre sí.", practicalEffects: ['En la práctica, este artículo rige concepto. La obligación alternativa tiene por objeto una prestación entre varias que son independientes y distintas entre sí.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 779'], segments: [], amendments: [] },
  { id: 'ccyc-art-780', lawId: 'codigo-civil-comercial', number: '780', order: 780, title: "Elección", originalText: "Elección. Sujetos. Efectos. Excepto estipulación en contrario, la facultad de elegir corresponde al deudor. La opción que corresponde a varias personas requiere unanimidad. Si la parte a quien corresponde la elección no se pronuncia oportunamente, la facultad de opción pasa a la otra. Si esa facultad se ha deferido a un tercero y éste no opta en el plazo fijado, corresponde al deudor designar el objeto del pago. En las obligaciones periódicas, la elección realizada una vez no implica renuncia a la facultad de optar en lo sucesivo. La elección es irrevocable desde que se la comunica a la otra parte o desde que el deudor ejecuta alguna de las prestaciones, aunque sea parcialmente. Una vez realizada, la prestación escogida se considera única desde su origen, y se aplican las reglas de las obligaciones de dar, de hacer o de no hacer, según corresponda.", currentText: "Elección. Sujetos. Efectos. Excepto estipulación en contrario, la facultad de elegir corresponde al deudor. La opción que corresponde a varias personas requiere unanimidad. Si la parte a quien corresponde la elección no se pronuncia oportunamente, la facultad de opción pasa a la otra. Si esa facultad se ha deferido a un tercero y éste no opta en el plazo fijado, corresponde al deudor designar el objeto del pago. En las obligaciones periódicas, la elección realizada una vez no implica renuncia a la facultad de optar en lo sucesivo. La elección es irrevocable desde que se la comunica a la otra parte o desde que el deudor ejecuta alguna de las prestaciones, aunque sea parcialmente. Una vez realizada, la prestación escogida se considera única desde su origen, y se aplican las reglas de las obligaciones de dar, de hacer o de no hacer, según corresponda.", plainLanguageExplanation: "Establece el régimen de elección. Sujetos.", practicalEffects: ['En la práctica, este artículo rige elección. Sujetos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['eleccinarticulo 780'], segments: [], amendments: [] },
  { id: 'ccyc-art-781', lawId: 'codigo-civil-comercial', number: '781', order: 781, title: "Obligación alternativa regular", originalText: "Obligación alternativa regular. En los casos en que la elección corresponde al deudor y la alternativa se da entre dos prestaciones, se aplican las siguientes reglas: a) si una de las prestaciones resulta imposible por causas ajenas a la responsabilidad de las partes, o atribuibles a la responsabilidad del deudor, la obligación se concentra en la restante; si la imposibilidad proviene de causas atribuibles a la responsabilidad del acreedor, el deudor tiene derecho a optar entre dar por cumplida su obligación; o cumplir la prestación que todavía es posible y reclamar los daños y perjuicios emergentes de la mayor onerosidad que le cause el pago realizado, con relación al que resultó imposible; b) si todas las prestaciones resultan imposibles, y la imposibilidad es sucesiva, la obligación se concentra en esta última, excepto si la imposibilidad de alguna de ellas obedece a causas que comprometen la responsabilidad del acreedor; en este caso, el deudor tiene derecho a elegir con cuál queda liberado; c) si todas las prestaciones resultan imposibles por causas atribuibles a la responsabilidad del deudor, y la imposibilidad es simultánea, se libera entregando el valor de cualquiera de ella; si lo son por causas atribuibles a la responsabilidad del acreedor, el deudor tiene derecho a dar por cumplida su obligación con una y reclamar los daños y perjuicios emergentes de la mayor onerosidad que le ocasione el pago realizado, con relación al que resultó imposible; d) si todas las prestaciones resultan imposibles por causas ajenas a la responsabilidad de las partes, la obligación se extingue.", currentText: "Obligación alternativa regular. En los casos en que la elección corresponde al deudor y la alternativa se da entre dos prestaciones, se aplican las siguientes reglas: a) si una de las prestaciones resulta imposible por causas ajenas a la responsabilidad de las partes, o atribuibles a la responsabilidad del deudor, la obligación se concentra en la restante; si la imposibilidad proviene de causas atribuibles a la responsabilidad del acreedor, el deudor tiene derecho a optar entre dar por cumplida su obligación; o cumplir la prestación que todavía es posible y reclamar los daños y perjuicios emergentes de la mayor onerosidad que le cause el pago realizado, con relación al que resultó imposible; b) si todas las prestaciones resultan imposibles, y la imposibilidad es sucesiva, la obligación se concentra en esta última, excepto si la imposibilidad de alguna de ellas obedece a causas que comprometen la responsabilidad del acreedor; en este caso, el deudor tiene derecho a elegir con cuál queda liberado; c) si todas las prestaciones resultan imposibles por causas atribuibles a la responsabilidad del deudor, y la imposibilidad es simultánea, se libera entregando el valor de cualquiera de ella; si lo son por causas atribuibles a la responsabilidad del acreedor, el deudor tiene derecho a dar por cumplida su obligación con una y reclamar los daños y perjuicios emergentes de la mayor onerosidad que le ocasione el pago realizado, con relación al que resultó imposible; d) si todas las prestaciones resultan imposibles por causas ajenas a la responsabilidad de las partes, la obligación se extingue.", plainLanguageExplanation: "Establece el régimen de obligación alternativa regular. En los casos en que la elección corresponde al deudor y la alternativa se da entre dos prestaciones, se aplican las siguientes reglas: a) si una de las prestaciones resulta imposible por causas ajenas a la responsabilidad de las partes, o atribuibles a la responsabilidad del deud", practicalEffects: ['En la práctica, este artículo rige obligación alternativa regular. En los casos en que la elección corresponde al deudor y la alternativa se da entre dos prestaciones, se aplican las siguientes reglas: a) si una de la'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacin', 'alternativa', 'regular', 'articulo 781'], segments: [], amendments: [] },
  { id: 'ccyc-art-782', lawId: 'codigo-civil-comercial', number: '782', order: 782, title: "Obligación alternativa irregular", originalText: "Obligación alternativa irregular. En los casos en que la elección corresponde al acreedor y la alternativa se da entre dos prestaciones, se aplican las siguientes reglas: a) si una de las prestaciones resulta imposible por causas ajenas a la responsabilidad de las partes, o atribuibles a la responsabilidad del acreedor, la obligación se concentra en la restante; si la imposibilidad proviene de causas atribuibles a la responsabilidad del deudor, el acreedor tiene derecho a optar entre reclamar la prestación que es posible, o el valor de la que resulta imposible; b) si todas las prestaciones resultan imposibles y la imposibilidad es sucesiva, la obligación se concentra en la última, excepto que la imposibilidad de la primera obedezca a causas que comprometan la responsabilidad del deudor; en este caso el acreedor tiene derecho a reclamar el valor de cualquiera de las prestaciones; c) si todas las prestaciones resultan imposibles por causas atribuibles a la responsabilidad del acreedor, y la imposibilidad es simultánea, el acreedor tiene derecho a elegir con cuál de ellas queda satisfecho, y debe al deudor los daños y perjuicios emergentes de la mayor onerosidad que le reporte el pago realizado; si lo son por causas atribuibles a la responsabilidad del deudor, el acreedor tiene derecho a elegir con el valor de cuál de ellas queda satisfecho; d) si todas las prestaciones resultan imposibles por causas ajenas a la responsabilidad de las partes, la obligación se extingue.", currentText: "Obligación alternativa irregular. En los casos en que la elección corresponde al acreedor y la alternativa se da entre dos prestaciones, se aplican las siguientes reglas: a) si una de las prestaciones resulta imposible por causas ajenas a la responsabilidad de las partes, o atribuibles a la responsabilidad del acreedor, la obligación se concentra en la restante; si la imposibilidad proviene de causas atribuibles a la responsabilidad del deudor, el acreedor tiene derecho a optar entre reclamar la prestación que es posible, o el valor de la que resulta imposible; b) si todas las prestaciones resultan imposibles y la imposibilidad es sucesiva, la obligación se concentra en la última, excepto que la imposibilidad de la primera obedezca a causas que comprometan la responsabilidad del deudor; en este caso el acreedor tiene derecho a reclamar el valor de cualquiera de las prestaciones; c) si todas las prestaciones resultan imposibles por causas atribuibles a la responsabilidad del acreedor, y la imposibilidad es simultánea, el acreedor tiene derecho a elegir con cuál de ellas queda satisfecho, y debe al deudor los daños y perjuicios emergentes de la mayor onerosidad que le reporte el pago realizado; si lo son por causas atribuibles a la responsabilidad del deudor, el acreedor tiene derecho a elegir con el valor de cuál de ellas queda satisfecho; d) si todas las prestaciones resultan imposibles por causas ajenas a la responsabilidad de las partes, la obligación se extingue.", plainLanguageExplanation: "Establece el régimen de obligación alternativa irregular. En los casos en que la elección corresponde al acreedor y la alternativa se da entre dos prestaciones, se aplican las siguientes reglas: a) si una de las prestaciones resulta imposible por causas ajenas a la responsabilidad de las partes, o atribuibles a la responsabilidad del ac", practicalEffects: ['En la práctica, este artículo rige obligación alternativa irregular. En los casos en que la elección corresponde al acreedor y la alternativa se da entre dos prestaciones, se aplican las siguientes reglas: a) si una de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacin', 'alternativa', 'irregular', 'articulo 782'], segments: [], amendments: [] },
  { id: 'ccyc-art-783', lawId: 'codigo-civil-comercial', number: '783', order: 783, title: "Elección por un tercero", originalText: "Elección por un tercero. Las opciones conferidas al deudor y al acreedor en los artículos 781 y 782 también pueden ser ejercidas, a favor de aquéllos, por un tercero a quien le haya sido encargada la elección.", currentText: "Elección por un tercero. Las opciones conferidas al deudor y al acreedor en los artículos 781 y 782 también pueden ser ejercidas, a favor de aquéllos, por un tercero a quien le haya sido encargada la elección.", plainLanguageExplanation: "Establece el régimen de elección por un tercero. Las opciones conferidas al deudor y al acreedor en los artículos 781 y 782 también pueden ser ejercidas, a favor de aquéllos, por un tercero a quien le haya sido encargada la elección.", practicalEffects: ['En la práctica, este artículo rige elección por un tercero. Las opciones conferidas al deudor y al acreedor en los artículos 781 y 782 también pueden ser ejercidas, a favor de aquéllos, por un tercero a quien l'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['eleccin', 'tercero', 'articulo 783'], segments: [], amendments: [] },
  { id: 'ccyc-art-784', lawId: 'codigo-civil-comercial', number: '784', order: 784, title: "Elección de modalidades o circunstancias", originalText: "Elección de modalidades o circunstancias. Si en la obligación se autoriza la elección respecto de sus modalidades o circunstancias, se aplican las reglas precedentes sobre el derecho de realizar la opción y sus efectos legales.", currentText: "Elección de modalidades o circunstancias. Si en la obligación se autoriza la elección respecto de sus modalidades o circunstancias, se aplican las reglas precedentes sobre el derecho de realizar la opción y sus efectos legales.", plainLanguageExplanation: "Establece el régimen de elección de modalidades o circunstancias. Si en la obligación se autoriza la elección respecto de sus modalidades o circunstancias, se aplican las reglas precedentes sobre el derecho de realizar la opción y sus efectos legales.", practicalEffects: ['En la práctica, este artículo rige elección de modalidades o circunstancias. Si en la obligación se autoriza la elección respecto de sus modalidades o circunstancias, se aplican las reglas precedentes sobre el derecho de realiz'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['eleccin', 'modalidades', 'circunstancias', 'articulo 784'], segments: [], amendments: [] },
  { id: 'ccyc-art-785', lawId: 'codigo-civil-comercial', number: '785', order: 785, title: "Obligaciones de género limitado", originalText: "Obligaciones de género limitado. Las disposiciones de esta Sección se aplican a las obligaciones en las que el deudor debe entregar una cosa incierta pero comprendida dentro de un número de cosas ciertas de la misma especie. SECCION 4ª Obligaciones facultativas", currentText: "Obligaciones de género limitado. Las disposiciones de esta Sección se aplican a las obligaciones en las que el deudor debe entregar una cosa incierta pero comprendida dentro de un número de cosas ciertas de la misma especie. SECCION 4ª Obligaciones facultativas", plainLanguageExplanation: "Establece el régimen de obligaciones de género limitado. Las disposiciones de esta Sección se aplican a las obligaciones en las que el deudor debe entregar una cosa incierta pero comprendida dentro de un número de cosas ciertas de la misma especie.", practicalEffects: ['En la práctica, este artículo rige obligaciones de género limitado. Las disposiciones de esta Sección se aplican a las obligaciones en las que el deudor debe entregar una cosa incierta pero comprendida dentro de un número de cosas ciertas de la misma especie.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'gnero', 'limitado', 'articulo 785'], segments: [], amendments: [] },
  { id: 'ccyc-art-786', lawId: 'codigo-civil-comercial', number: '786', order: 786, title: "Concepto", originalText: "Concepto. La obligación facultativa tiene una prestación principal y otra accesoria. El acreedor solo puede exigir la principal, pero el deudor puede liberarse cumpliendo la accesoria. El deudor dispone hasta el momento del pago para ejercitar la facultad de optar.", currentText: "Concepto. La obligación facultativa tiene una prestación principal y otra accesoria. El acreedor solo puede exigir la principal, pero el deudor puede liberarse cumpliendo la accesoria. El deudor dispone hasta el momento del pago para ejercitar la facultad de optar.", plainLanguageExplanation: "Establece el régimen de concepto. La obligación facultativa tiene una prestación principal y otra accesoria.", practicalEffects: ['En la práctica, este artículo rige concepto. La obligación facultativa tiene una prestación principal y otra accesoria.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 786'], segments: [], amendments: [] },
  { id: 'ccyc-art-787', lawId: 'codigo-civil-comercial', number: '787', order: 787, title: "Extinción", originalText: "Extinción. La obligación facultativa se extingue si la prestación principal resulta imposible, sin perjuicio de la responsabilidad que pueda corresponder.", currentText: "Extinción. La obligación facultativa se extingue si la prestación principal resulta imposible, sin perjuicio de la responsabilidad que pueda corresponder.", plainLanguageExplanation: "Establece el régimen de extinción. La obligación facultativa se extingue si la prestación principal resulta imposible, sin perjuicio de la responsabilidad que pueda corresponder.", practicalEffects: ['En la práctica, este artículo rige extinción. La obligación facultativa se extingue si la prestación principal resulta imposible, sin perjuicio de la responsabilidad que pueda corresponder.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extincinarticulo 787'], segments: [], amendments: [] },
  { id: 'ccyc-art-788', lawId: 'codigo-civil-comercial', number: '788', order: 788, title: "Caso de duda", originalText: "Caso de duda. En caso de duda respecto a si la obligación es alternativa o facultativa, se la tiene por alternativa.", currentText: "Caso de duda. En caso de duda respecto a si la obligación es alternativa o facultativa, se la tiene por alternativa.", plainLanguageExplanation: "Establece el régimen de caso de duda. En caso de duda respecto a si la obligación es alternativa o facultativa, se la tiene por alternativa.", practicalEffects: ['En la práctica, este artículo rige caso de duda. En caso de duda respecto a si la obligación es alternativa o facultativa, se la tiene por alternativa.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caso', 'duda', 'articulo 788'], segments: [], amendments: [] },
  { id: 'ccyc-art-789', lawId: 'codigo-civil-comercial', number: '789', order: 789, title: "Opción entre modalidades y circunstancias", originalText: "Opción entre modalidades y circunstancias. Si en la obligación se autoriza la opción respecto de sus modalidades o circunstancias, se aplican las reglas precedentes. SECCION 5ª Obligaciones con cláusula penal y sanciones conminatorias", currentText: "Opción entre modalidades y circunstancias. Si en la obligación se autoriza la opción respecto de sus modalidades o circunstancias, se aplican las reglas precedentes. SECCION 5ª Obligaciones con cláusula penal y sanciones conminatorias", plainLanguageExplanation: "Establece el régimen de opción entre modalidades y circunstancias. Si en la obligación se autoriza la opción respecto de sus modalidades o circunstancias, se aplican las reglas precedentes.", practicalEffects: ['En la práctica, este artículo rige opción entre modalidades y circunstancias. Si en la obligación se autoriza la opción respecto de sus modalidades o circunstancias, se aplican las reglas precedentes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['opcin', 'entre', 'modalidades', 'circunstancias', 'articulo 789'], segments: [], amendments: [] },
  { id: 'ccyc-art-790', lawId: 'codigo-civil-comercial', number: '790', order: 790, title: "Concepto", originalText: "Concepto. La cláusula penal es aquella por la cual una persona, para asegurar el cumplimiento de una obligación, se sujeta a una pena o multa en caso de retardar o de no ejecutar la obligación.", currentText: "Concepto. La cláusula penal es aquella por la cual una persona, para asegurar el cumplimiento de una obligación, se sujeta a una pena o multa en caso de retardar o de no ejecutar la obligación.", plainLanguageExplanation: "Establece el régimen de concepto. La cláusula penal es aquella por la cual una persona, para asegurar el cumplimiento de una obligación, se sujeta a una pena o multa en caso de retardar o de no ejecutar la obligación.", practicalEffects: ['En la práctica, este artículo rige concepto. La cláusula penal es aquella por la cual una persona, para asegurar el cumplimiento de una obligación, se sujeta a una pena o multa en caso de retarda'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 790'], segments: [], amendments: [] },
  { id: 'ccyc-art-791', lawId: 'codigo-civil-comercial', number: '791', order: 791, title: "Objeto", originalText: "Objeto. La cláusula penal puede tener por objeto el pago de una suma de dinero, o cualquiera otra prestación que pueda ser objeto de las obligaciones, bien sea en beneficio del acreedor o de un tercero.", currentText: "Objeto. La cláusula penal puede tener por objeto el pago de una suma de dinero, o cualquiera otra prestación que pueda ser objeto de las obligaciones, bien sea en beneficio del acreedor o de un tercero.", plainLanguageExplanation: "Establece el régimen de objeto. La cláusula penal puede tener por objeto el pago de una suma de dinero, o cualquiera otra prestación que pueda ser objeto de las obligaciones, bien sea en beneficio del acreedor o de un tercero.", practicalEffects: ['En la práctica, este artículo rige objeto. La cláusula penal puede tener por objeto el pago de una suma de dinero, o cualquiera otra prestación que pueda ser objeto de las obligaciones, bien se'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['objetoarticulo 791'], segments: [], amendments: [] },
  { id: 'ccyc-art-792', lawId: 'codigo-civil-comercial', number: '792', order: 792, title: "Incumplimiento", originalText: "Incumplimiento. El deudor que no cumple la obligación en el tiempo convenido debe la pena, si no prueba la causa extraña que suprime la relación causal. La eximente del caso fortuito debe ser interpretada y aplicada restrictivamente.", currentText: "Incumplimiento. El deudor que no cumple la obligación en el tiempo convenido debe la pena, si no prueba la causa extraña que suprime la relación causal. La eximente del caso fortuito debe ser interpretada y aplicada restrictivamente.", plainLanguageExplanation: "Establece el régimen de incumplimiento. El deudor que no cumple la obligación en el tiempo convenido debe la pena, si no prueba la causa extraña que suprime la relación causal.", practicalEffects: ['En la práctica, este artículo rige incumplimiento. El deudor que no cumple la obligación en el tiempo convenido debe la pena, si no prueba la causa extraña que suprime la relación causal.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incumplimientoarticulo 792'], segments: [], amendments: [] },
  { id: 'ccyc-art-793', lawId: 'codigo-civil-comercial', number: '793', order: 793, title: "Relación con la indemnización", originalText: "Relación con la indemnización. La pena o multa impuesta en la obligación suple la indemnización de los daños cuando el deudor se constituyó en mora; y el acreedor no tiene derecho a otra indemnización, aunque pruebe que la pena no es reparación suficiente.", currentText: "Relación con la indemnización. La pena o multa impuesta en la obligación suple la indemnización de los daños cuando el deudor se constituyó en mora; y el acreedor no tiene derecho a otra indemnización, aunque pruebe que la pena no es reparación suficiente.", plainLanguageExplanation: "Establece el régimen de relación con la indemnización. La pena o multa impuesta en la obligación suple la indemnización de los daños cuando el deudor se constituyó en mora; y el acreedor no tiene derecho a otra indemnización, aunque pruebe que la pena no es reparación suficiente.", practicalEffects: ['En la práctica, este artículo rige relación con la indemnización. La pena o multa impuesta en la obligación suple la indemnización de los daños cuando el deudor se constituyó en mora; y el acreedor no tiene derecho a'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['relacin', 'indemnizacin', 'articulo 793'], segments: [], amendments: [] },
  { id: 'ccyc-art-794', lawId: 'codigo-civil-comercial', number: '794', order: 794, title: "Ejecución", originalText: "Ejecución. Para pedir la pena, el acreedor no está obligado a probar que ha sufrido perjuicios, ni el deudor puede eximirse de satisfacerla, acreditando que el acreedor no sufrió perjuicio alguno. Los jueces pueden reducir las penas cuando su monto desproporcionado con la gravedad de la falta que sancionan, habida cuenta del valor de las prestaciones y demás circunstancias del caso, configuran un abusivo aprovechamiento de la situación del deudor.", currentText: "Ejecución. Para pedir la pena, el acreedor no está obligado a probar que ha sufrido perjuicios, ni el deudor puede eximirse de satisfacerla, acreditando que el acreedor no sufrió perjuicio alguno. Los jueces pueden reducir las penas cuando su monto desproporcionado con la gravedad de la falta que sancionan, habida cuenta del valor de las prestaciones y demás circunstancias del caso, configuran un abusivo aprovechamiento de la situación del deudor.", plainLanguageExplanation: "Establece el régimen de ejecución. Para pedir la pena, el acreedor no está obligado a probar que ha sufrido perjuicios, ni el deudor puede eximirse de satisfacerla, acreditando que el acreedor no sufrió perjuicio alguno.", practicalEffects: ['En la práctica, este artículo rige ejecución. Para pedir la pena, el acreedor no está obligado a probar que ha sufrido perjuicios, ni el deudor puede eximirse de satisfacerla, acreditando que el acreedor no sufrió perjuicio alguno.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ejecucinarticulo 794'], segments: [], amendments: [] },
  { id: 'ccyc-art-795', lawId: 'codigo-civil-comercial', number: '795', order: 795, title: "Obligaciones de no hacer", originalText: "Obligaciones de no hacer. En las obligaciones de no hacer el deudor incurre en la pena desde el momento que ejecuta el acto del cual se obligó a abstenerse.", currentText: "Obligaciones de no hacer. En las obligaciones de no hacer el deudor incurre en la pena desde el momento que ejecuta el acto del cual se obligó a abstenerse.", plainLanguageExplanation: "Establece el régimen de obligaciones de no hacer. En las obligaciones de no hacer el deudor incurre en la pena desde el momento que ejecuta el acto del cual se obligó a abstenerse.", practicalEffects: ['En la práctica, este artículo rige obligaciones de no hacer. En las obligaciones de no hacer el deudor incurre en la pena desde el momento que ejecuta el acto del cual se obligó a abstenerse.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'hacer', 'articulo 795'], segments: [], amendments: [] },
  { id: 'ccyc-art-796', lawId: 'codigo-civil-comercial', number: '796', order: 796, title: "Opciones del deudor", originalText: "Opciones del deudor. El deudor puede eximirse de cumplir la obligación con el pago de la pena únicamente si se reservó expresamente este derecho.", currentText: "Opciones del deudor. El deudor puede eximirse de cumplir la obligación con el pago de la pena únicamente si se reservó expresamente este derecho.", plainLanguageExplanation: "Establece el régimen de opciones del deudor. El deudor puede eximirse de cumplir la obligación con el pago de la pena únicamente si se reservó expresamente este derecho.", practicalEffects: ['En la práctica, este artículo rige opciones del deudor. El deudor puede eximirse de cumplir la obligación con el pago de la pena únicamente si se reservó expresamente este derecho.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['opciones', 'deudor', 'articulo 796'], segments: [], amendments: [] },
  { id: 'ccyc-art-797', lawId: 'codigo-civil-comercial', number: '797', order: 797, title: "Opciones del acreedor", originalText: "Opciones del acreedor. El acreedor no puede pedir el cumplimiento de la obligación y la pena, sino una de las dos cosas, a su arbitrio, a menos que se haya estipulado la pena por el simple retardo, o que se haya estipulado que por el pago de la pena no se entienda extinguida la obligación principal.", currentText: "Opciones del acreedor. El acreedor no puede pedir el cumplimiento de la obligación y la pena, sino una de las dos cosas, a su arbitrio, a menos que se haya estipulado la pena por el simple retardo, o que se haya estipulado que por el pago de la pena no se entienda extinguida la obligación principal.", plainLanguageExplanation: "Establece el régimen de opciones del acreedor. El acreedor no puede pedir el cumplimiento de la obligación y la pena, sino una de las dos cosas, a su arbitrio, a menos que se haya estipulado la pena por el simple retardo, o que se haya estipulado que por el pago de la pena no se entienda extinguida la obligación principal.", practicalEffects: ['En la práctica, este artículo rige opciones del acreedor. El acreedor no puede pedir el cumplimiento de la obligación y la pena, sino una de las dos cosas, a su arbitrio, a menos que se haya estipulado la pen'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['opciones', 'acreedor', 'articulo 797'], segments: [], amendments: [] },
  { id: 'ccyc-art-798', lawId: 'codigo-civil-comercial', number: '798', order: 798, title: "Disminución proporcional", originalText: "Disminución proporcional. Si el deudor cumple sólo una parte de la obligación, o la cumple de un modo irregular, o fuera del lugar o del tiempo a que se obligó, y el acreedor la acepta, la pena debe disminuirse proporcionalmente.", currentText: "Disminución proporcional. Si el deudor cumple sólo una parte de la obligación, o la cumple de un modo irregular, o fuera del lugar o del tiempo a que se obligó, y el acreedor la acepta, la pena debe disminuirse proporcionalmente.", plainLanguageExplanation: "Establece el régimen de disminución proporcional. Si el deudor cumple sólo una parte de la obligación, o la cumple de un modo irregular, o fuera del lugar o del tiempo a que se obligó, y el acreedor la acepta, la pena debe disminuirse proporcionalmente.", practicalEffects: ['En la práctica, este artículo rige disminución proporcional. Si el deudor cumple sólo una parte de la obligación, o la cumple de un modo irregular, o fuera del lugar o del tiempo a que se obligó, y el acreedor l'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disminucin', 'proporcional', 'articulo 798'], segments: [], amendments: [] },
  { id: 'ccyc-art-799', lawId: 'codigo-civil-comercial', number: '799', order: 799, title: "Divisibilidad", originalText: "Divisibilidad. Sea divisible o indivisible la obligación principal, cada uno de los codeudores o de los herederos del deudor no incurre en la pena sino en proporción de su parte, siempre que sea divisible la obligación de la cláusula penal.", currentText: "Divisibilidad. Sea divisible o indivisible la obligación principal, cada uno de los codeudores o de los herederos del deudor no incurre en la pena sino en proporción de su parte, siempre que sea divisible la obligación de la cláusula penal.", plainLanguageExplanation: "Establece el régimen de divisibilidad. Sea divisible o indivisible la obligación principal, cada uno de los codeudores o de los herederos del deudor no incurre en la pena sino en proporción de su parte, siempre que sea divisible la obligación de la cláusula penal.", practicalEffects: ['En la práctica, este artículo rige divisibilidad. Sea divisible o indivisible la obligación principal, cada uno de los codeudores o de los herederos del deudor no incurre en la pena sino en proporción'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['divisibilidadarticulo 799'], segments: [], amendments: [] },
  { id: 'ccyc-art-800', lawId: 'codigo-civil-comercial', number: '800', order: 800, title: "Indivisibilidad", originalText: "Indivisibilidad. Si la obligación de la cláusula penal es indivisible, o si es solidaria aunque divisible, cada uno de los codeudores, o de los coherederos del deudor, queda obligado a satisfacer la pena entera.", currentText: "Indivisibilidad. Si la obligación de la cláusula penal es indivisible, o si es solidaria aunque divisible, cada uno de los codeudores, o de los coherederos del deudor, queda obligado a satisfacer la pena entera.", plainLanguageExplanation: "Establece el régimen de indivisibilidad. Si la obligación de la cláusula penal es indivisible, o si es solidaria aunque divisible, cada uno de los codeudores, o de los coherederos del deudor, queda obligado a satisfacer la pena entera.", practicalEffects: ['En la práctica, este artículo rige indivisibilidad. Si la obligación de la cláusula penal es indivisible, o si es solidaria aunque divisible, cada uno de los codeudores, o de los coherederos del deudor,'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['indivisibilidadarticulo 800'], segments: [], amendments: [] },
  { id: 'ccyc-art-801', lawId: 'codigo-civil-comercial', number: '801', order: 801, title: "Nulidad", originalText: "Nulidad. La nulidad de la obligación con cláusula penal no causa la de la principal. La nulidad de la principal causa la de la cláusula penal, excepto si la obligación con cláusula penal fue contraída por otra persona, para el caso que la principal fuese nula por falta de capacidad del deudor.", currentText: "Nulidad. La nulidad de la obligación con cláusula penal no causa la de la principal. La nulidad de la principal causa la de la cláusula penal, excepto si la obligación con cláusula penal fue contraída por otra persona, para el caso que la principal fuese nula por falta de capacidad del deudor.", plainLanguageExplanation: "Establece el régimen de nulidad. La nulidad de la obligación con cláusula penal no causa la de la principal.", practicalEffects: ['En la práctica, este artículo rige nulidad. La nulidad de la obligación con cláusula penal no causa la de la principal.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['nulidadarticulo 801'], segments: [], amendments: [] },
  { id: 'ccyc-art-802', lawId: 'codigo-civil-comercial', number: '802', order: 802, title: "Extinción de la obligación principal", originalText: "Extinción de la obligación principal. Si la obligación principal se extingue sin culpa del deudor queda también extinguida la cláusula penal.", currentText: "Extinción de la obligación principal. Si la obligación principal se extingue sin culpa del deudor queda también extinguida la cláusula penal.", plainLanguageExplanation: "Establece el régimen de extinción de la obligación principal. Si la obligación principal se extingue sin culpa del deudor queda también extinguida la cláusula penal.", practicalEffects: ['En la práctica, este artículo rige extinción de la obligación principal. Si la obligación principal se extingue sin culpa del deudor queda también extinguida la cláusula penal.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extincin', 'obligacin', 'principal', 'articulo 802'], segments: [], amendments: [] },
  { id: 'ccyc-art-803', lawId: 'codigo-civil-comercial', number: '803', order: 803, title: "Obligación no exigible", originalText: "Obligación no exigible. La cláusula penal tiene efecto, aunque sea puesta para asegurar el cumplimiento de una obligación que al tiempo de concertar la accesoria no podía exigirse judicialmente, siempre que no sea reprobada por la ley.", currentText: "Obligación no exigible. La cláusula penal tiene efecto, aunque sea puesta para asegurar el cumplimiento de una obligación que al tiempo de concertar la accesoria no podía exigirse judicialmente, siempre que no sea reprobada por la ley.", plainLanguageExplanation: "Establece el régimen de obligación no exigible. La cláusula penal tiene efecto, aunque sea puesta para asegurar el cumplimiento de una obligación que al tiempo de concertar la accesoria no podía exigirse judicialmente, siempre que no sea reprobada por la ley.", practicalEffects: ['En la práctica, este artículo rige obligación no exigible. La cláusula penal tiene efecto, aunque sea puesta para asegurar el cumplimiento de una obligación que al tiempo de concertar la accesoria no podía exi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacin', 'exigible', 'articulo 803'], segments: [], amendments: [] },
  { id: 'ccyc-art-804', lawId: 'codigo-civil-comercial', number: '804', order: 804, title: "Sanciones conminatorias", originalText: "Sanciones conminatorias. Los jueces pueden imponer en beneficio del titular del derecho, condenaciones conminatorias de carácter pecuniario a quienes no cumplen deberes jurídicos impuestos en una resolución judicial. Las condenas se deben graduar en proporción al caudal económico de quien debe satisfacerlas y pueden ser dejadas sin efecto o reajustadas si aquél desiste de su resistencia y justifica total o parcialmente su proceder. La observancia de los mandatos judiciales impartidos a las autoridades públicas se rige por las normas propias del derecho administrativo. SECCION 6ª Obligaciones divisibles e indivisibles Parágrafo 1° Obligaciones divisibles", currentText: "Sanciones conminatorias. Los jueces pueden imponer en beneficio del titular del derecho, condenaciones conminatorias de carácter pecuniario a quienes no cumplen deberes jurídicos impuestos en una resolución judicial. Las condenas se deben graduar en proporción al caudal económico de quien debe satisfacerlas y pueden ser dejadas sin efecto o reajustadas si aquél desiste de su resistencia y justifica total o parcialmente su proceder. La observancia de los mandatos judiciales impartidos a las autoridades públicas se rige por las normas propias del derecho administrativo. SECCION 6ª Obligaciones divisibles e indivisibles Parágrafo 1° Obligaciones divisibles", plainLanguageExplanation: "Establece el régimen de sanciones conminatorias. Los jueces pueden imponer en beneficio del titular del derecho, condenaciones conminatorias de carácter pecuniario a quienes no cumplen deberes jurídicos impuestos en una resolución judicial.", practicalEffects: ['En la práctica, este artículo rige sanciones conminatorias. Los jueces pueden imponer en beneficio del titular del derecho, condenaciones conminatorias de carácter pecuniario a quienes no cumplen deberes jurídicos impuestos en una resolución judicial.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sanciones', 'conminatorias', 'articulo 804'], segments: [], amendments: [] },
  { id: 'ccyc-art-805', lawId: 'codigo-civil-comercial', number: '805', order: 805, title: "Concepto", originalText: "Concepto. Obligación divisible es la que tiene por objeto prestaciones susceptibles de cumplimiento parcial.", currentText: "Concepto. Obligación divisible es la que tiene por objeto prestaciones susceptibles de cumplimiento parcial.", plainLanguageExplanation: "Establece el régimen de concepto. Obligación divisible es la que tiene por objeto prestaciones susceptibles de cumplimiento parcial.", practicalEffects: ['En la práctica, este artículo rige concepto. Obligación divisible es la que tiene por objeto prestaciones susceptibles de cumplimiento parcial.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 805'], segments: [], amendments: [] },
  { id: 'ccyc-art-806', lawId: 'codigo-civil-comercial', number: '806', order: 806, title: "Requisitos", originalText: "Requisitos. La prestación jurídicamente divisible exige la concurrencia de los siguientes requisitos: a) ser materialmente fraccionable, de modo que cada una de sus partes tenga la misma calidad del todo; b) no quedar afectado significativamente el valor del objeto, ni ser antieconómico su uso y goce, por efecto de la división.", currentText: "Requisitos. La prestación jurídicamente divisible exige la concurrencia de los siguientes requisitos: a) ser materialmente fraccionable, de modo que cada una de sus partes tenga la misma calidad del todo; b) no quedar afectado significativamente el valor del objeto, ni ser antieconómico su uso y goce, por efecto de la división.", plainLanguageExplanation: "Establece el régimen de requisitos. La prestación jurídicamente divisible exige la concurrencia de los siguientes requisitos: a) ser materialmente fraccionable, de modo que cada una de sus partes tenga la misma calidad del todo; b) no quedar afectado significativamente el valor del objeto, ni ser antieconómico su u", practicalEffects: ['En la práctica, este artículo rige requisitos. La prestación jurídicamente divisible exige la concurrencia de los siguientes requisitos: a) ser materialmente fraccionable, de modo que cada una de s'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitosarticulo 806'], segments: [], amendments: [] },
  { id: 'ccyc-art-807', lawId: 'codigo-civil-comercial', number: '807', order: 807, title: "Deudor y acreedor singulares", originalText: "Deudor y acreedor singulares. Si solo hay un deudor y un acreedor, la prestación debe ser cumplida por entero, aunque su objeto sea divisible.", currentText: "Deudor y acreedor singulares. Si solo hay un deudor y un acreedor, la prestación debe ser cumplida por entero, aunque su objeto sea divisible.", plainLanguageExplanation: "Establece el régimen de deudor y acreedor singulares. Si solo hay un deudor y un acreedor, la prestación debe ser cumplida por entero, aunque su objeto sea divisible.", practicalEffects: ['En la práctica, este artículo rige deudor y acreedor singulares. Si solo hay un deudor y un acreedor, la prestación debe ser cumplida por entero, aunque su objeto sea divisible.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['deudor', 'acreedor', 'singulares', 'articulo 807'], segments: [], amendments: [] },
  { id: 'ccyc-art-808', lawId: 'codigo-civil-comercial', number: '808', order: 808, title: "Principio de división", originalText: "Principio de división. Si la obligación divisible tiene más de un acreedor o más de un deudor, se debe fraccionar en tantos créditos o deudas iguales, como acreedores o deudores haya, siempre que el título constitutivo no determine proporciones distintas. Cada una de las partes equivale a una prestación diversa e independiente. Los acreedores tienen derecho a su cuota y los deudores no responden por la insolvencia de los demás.", currentText: "Principio de división. Si la obligación divisible tiene más de un acreedor o más de un deudor, se debe fraccionar en tantos créditos o deudas iguales, como acreedores o deudores haya, siempre que el título constitutivo no determine proporciones distintas. Cada una de las partes equivale a una prestación diversa e independiente. Los acreedores tienen derecho a su cuota y los deudores no responden por la insolvencia de los demás.", plainLanguageExplanation: "Establece el régimen de principio de división. Si la obligación divisible tiene más de un acreedor o más de un deudor, se debe fraccionar en tantos créditos o deudas iguales, como acreedores o deudores haya, siempre que el título constitutivo no determine proporciones distintas.", practicalEffects: ['En la práctica, este artículo rige principio de división. Si la obligación divisible tiene más de un acreedor o más de un deudor, se debe fraccionar en tantos créditos o deudas iguales, como acreedores o deud'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['principio', 'divisin', 'articulo 808'], segments: [], amendments: [] },
  { id: 'ccyc-art-809', lawId: 'codigo-civil-comercial', number: '809', order: 809, title: "Límite de la divisibilidad", originalText: "Límite de la divisibilidad. La divisibilidad de la obligación no puede invocarse por el codeudor a cuyo cargo se deja el pago de toda la deuda.", currentText: "Límite de la divisibilidad. La divisibilidad de la obligación no puede invocarse por el codeudor a cuyo cargo se deja el pago de toda la deuda.", plainLanguageExplanation: "Establece el régimen de límite de la divisibilidad. La divisibilidad de la obligación no puede invocarse por el codeudor a cuyo cargo se deja el pago de toda la deuda.", practicalEffects: ['En la práctica, este artículo rige límite de la divisibilidad. La divisibilidad de la obligación no puede invocarse por el codeudor a cuyo cargo se deja el pago de toda la deuda.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['lmite', 'divisibilidad', 'articulo 809'], segments: [], amendments: [] },
  { id: 'ccyc-art-810', lawId: 'codigo-civil-comercial', number: '810', order: 810, title: "Derecho al reintegro", originalText: "Derecho al reintegro. En los casos en que el deudor paga más de su parte en la deuda: a) si lo hace sabiendo que en la demasía paga una deuda ajena, se aplican las reglas de la subrogación por ejecución de la prestación por un tercero; b) si lo hace sin causa, porque cree ser deudor del todo, o porque el acreedor ya percibió la demasía, se aplican las reglas del pago indebido.", currentText: "Derecho al reintegro. En los casos en que el deudor paga más de su parte en la deuda: a) si lo hace sabiendo que en la demasía paga una deuda ajena, se aplican las reglas de la subrogación por ejecución de la prestación por un tercero; b) si lo hace sin causa, porque cree ser deudor del todo, o porque el acreedor ya percibió la demasía, se aplican las reglas del pago indebido.", plainLanguageExplanation: "Establece el régimen de derecho al reintegro. En los casos en que el deudor paga más de su parte en la deuda: a) si lo hace sabiendo que en la demasía paga una deuda ajena, se aplican las reglas de la subrogación por ejecución de la prestación por un tercero; b) si lo hace sin causa, porque cree ser deudor del todo, o porque", practicalEffects: ['En la práctica, este artículo rige derecho al reintegro. En los casos en que el deudor paga más de su parte en la deuda: a) si lo hace sabiendo que en la demasía paga una deuda ajena, se aplican las reglas d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'reintegro', 'articulo 810'], segments: [], amendments: [] },
  { id: 'ccyc-art-811', lawId: 'codigo-civil-comercial', number: '811', order: 811, title: "Participación", originalText: "Participación. La participación entre los acreedores de lo que uno de ellos percibe de más se determina conforme a lo dispuesto por el artículo 841.", currentText: "Participación. La participación entre los acreedores de lo que uno de ellos percibe de más se determina conforme a lo dispuesto por el artículo 841.", plainLanguageExplanation: "Establece el régimen de participación. La participación entre los acreedores de lo que uno de ellos percibe de más se determina conforme a lo dispuesto por el artículo 841.", practicalEffects: ['En la práctica, este artículo rige participación. La participación entre los acreedores de lo que uno de ellos percibe de más se determina conforme a lo dispuesto por el artículo 841.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['participacinarticulo 811'], segments: [], amendments: [] },
  { id: 'ccyc-art-812', lawId: 'codigo-civil-comercial', number: '812', order: 812, title: "Caso de solidaridad", originalText: "Caso de solidaridad. Si la obligación divisible es además solidaria, se aplican las reglas de las obligaciones solidarias, y la solidaridad activa o pasiva, según corresponda. Parágrafo 2° Obligaciones indivisibles", currentText: "Caso de solidaridad. Si la obligación divisible es además solidaria, se aplican las reglas de las obligaciones solidarias, y la solidaridad activa o pasiva, según corresponda. Parágrafo 2° Obligaciones indivisibles", plainLanguageExplanation: "Establece el régimen de caso de solidaridad. Si la obligación divisible es además solidaria, se aplican las reglas de las obligaciones solidarias, y la solidaridad activa o pasiva, según corresponda.", practicalEffects: ['En la práctica, este artículo rige caso de solidaridad. Si la obligación divisible es además solidaria, se aplican las reglas de las obligaciones solidarias, y la solidaridad activa o pasiva, según corresponda.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caso', 'solidaridad', 'articulo 812'], segments: [], amendments: [] },
  { id: 'ccyc-art-813', lawId: 'codigo-civil-comercial', number: '813', order: 813, title: "Concepto", originalText: "Concepto. Son indivisibles las obligaciones no susceptibles de cumplimiento parcial.", currentText: "Concepto. Son indivisibles las obligaciones no susceptibles de cumplimiento parcial.", plainLanguageExplanation: "Establece el régimen de concepto. Son indivisibles las obligaciones no susceptibles de cumplimiento parcial.", practicalEffects: ['En la práctica, este artículo rige concepto. Son indivisibles las obligaciones no susceptibles de cumplimiento parcial.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 813'], segments: [], amendments: [] },
  { id: 'ccyc-art-814', lawId: 'codigo-civil-comercial', number: '814', order: 814, title: "Casos de indivisibilidad", originalText: "Casos de indivisibilidad. Hay indivisibilidad: a) si la prestación no puede ser materialmente dividida; b) si la indivisibilidad es convenida; en caso de duda sobre si se convino que la obligación sea indivisible o solidaria, se considera solidaria; c) si lo dispone la ley.", currentText: "Casos de indivisibilidad. Hay indivisibilidad: a) si la prestación no puede ser materialmente dividida; b) si la indivisibilidad es convenida; en caso de duda sobre si se convino que la obligación sea indivisible o solidaria, se considera solidaria; c) si lo dispone la ley.", plainLanguageExplanation: "Establece el régimen de casos de indivisibilidad. Hay indivisibilidad: a) si la prestación no puede ser materialmente dividida; b) si la indivisibilidad es convenida; en caso de duda sobre si se convino que la obligación sea indivisible o solidaria, se considera solidaria; c) si lo dispone la ley.", practicalEffects: ['En la práctica, este artículo rige casos de indivisibilidad. Hay indivisibilidad: a) si la prestación no puede ser materialmente dividida; b) si la indivisibilidad es convenida; en caso de duda sobre si se convi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['casos', 'indivisibilidad', 'articulo 814'], segments: [], amendments: [] },
  { id: 'ccyc-art-815', lawId: 'codigo-civil-comercial', number: '815', order: 815, title: "Prestaciones indivisibles", originalText: "Prestaciones indivisibles. Se consideran indivisibles las prestaciones correspondientes a las obligaciones: a) de dar una cosa cierta; b) de hacer, excepto si han sido convenidas por unidad de medida y el deudor tiene derecho a la liberación parcial; c) de no hacer; d) accesorias, si la principal es indivisible.", currentText: "Prestaciones indivisibles. Se consideran indivisibles las prestaciones correspondientes a las obligaciones: a) de dar una cosa cierta; b) de hacer, excepto si han sido convenidas por unidad de medida y el deudor tiene derecho a la liberación parcial; c) de no hacer; d) accesorias, si la principal es indivisible.", plainLanguageExplanation: "Establece el régimen de prestaciones indivisibles. Se consideran indivisibles las prestaciones correspondientes a las obligaciones: a) de dar una cosa cierta; b) de hacer, excepto si han sido convenidas por unidad de medida y el deudor tiene derecho a la liberación parcial; c) de no hacer; d) accesorias, si la principal es indivi", practicalEffects: ['En la práctica, este artículo rige prestaciones indivisibles. Se consideran indivisibles las prestaciones correspondientes a las obligaciones: a) de dar una cosa cierta; b) de hacer, excepto si han sido convenida'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prestaciones', 'indivisibles', 'articulo 815'], segments: [], amendments: [] },
  { id: 'ccyc-art-816', lawId: 'codigo-civil-comercial', number: '816', order: 816, title: "Derecho de los acreedores al pago total", originalText: "Derecho de los acreedores al pago total. Cada uno de los acreedores tiene derecho de exigir la totalidad del pago a cualquiera de los codeudores, o a todos ellos, simultánea o sucesivamente.", currentText: "Derecho de los acreedores al pago total. Cada uno de los acreedores tiene derecho de exigir la totalidad del pago a cualquiera de los codeudores, o a todos ellos, simultánea o sucesivamente.", plainLanguageExplanation: "Establece el régimen de derecho de los acreedores al pago total. Cada uno de los acreedores tiene derecho de exigir la totalidad del pago a cualquiera de los codeudores, o a todos ellos, simultánea o sucesivamente.", practicalEffects: ['En la práctica, este artículo rige derecho de los acreedores al pago total. Cada uno de los acreedores tiene derecho de exigir la totalidad del pago a cualquiera de los codeudores, o a todos ellos, simultánea o sucesivamente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'acreedores', 'pago', 'total', 'articulo 816'], segments: [], amendments: [] },
  { id: 'ccyc-art-817', lawId: 'codigo-civil-comercial', number: '817', order: 817, title: "Derecho a pagar", originalText: "Derecho a pagar. Cualquiera de los codeudores tiene derecho a pagar la totalidad de la deuda a cualquiera de los acreedores.", currentText: "Derecho a pagar. Cualquiera de los codeudores tiene derecho a pagar la totalidad de la deuda a cualquiera de los acreedores.", plainLanguageExplanation: "Establece el régimen de derecho a pagar. Cualquiera de los codeudores tiene derecho a pagar la totalidad de la deuda a cualquiera de los acreedores.", practicalEffects: ['En la práctica, este artículo rige derecho a pagar. Cualquiera de los codeudores tiene derecho a pagar la totalidad de la deuda a cualquiera de los acreedores.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'pagar', 'articulo 817'], segments: [], amendments: [] },
  { id: 'ccyc-art-818', lawId: 'codigo-civil-comercial', number: '818', order: 818, title: "Modos extintivos", originalText: "Modos extintivos. La unanimidad de los acreedores es requerida para extinguir el crédito por transacción, novación, dación en pago y remisión. Igual recaudo exige la cesión del crédito, no así la compensación.", currentText: "Modos extintivos. La unanimidad de los acreedores es requerida para extinguir el crédito por transacción, novación, dación en pago y remisión. Igual recaudo exige la cesión del crédito, no así la compensación.", plainLanguageExplanation: "Establece el régimen de modos extintivos. La unanimidad de los acreedores es requerida para extinguir el crédito por transacción, novación, dación en pago y remisión.", practicalEffects: ['En la práctica, este artículo rige modos extintivos. La unanimidad de los acreedores es requerida para extinguir el crédito por transacción, novación, dación en pago y remisión.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['modos', 'extintivos', 'articulo 818'], segments: [], amendments: [] },
  { id: 'ccyc-art-819', lawId: 'codigo-civil-comercial', number: '819', order: 819, title: "Responsabilidad de cada codeudor", originalText: "Responsabilidad de cada codeudor. La mora de uno de los deudores o de uno de los acreedores, y los factores de atribución de responsabilidad de uno u otro, no perjudican a los demás.", currentText: "Responsabilidad de cada codeudor. La mora de uno de los deudores o de uno de los acreedores, y los factores de atribución de responsabilidad de uno u otro, no perjudican a los demás.", plainLanguageExplanation: "Establece el régimen de responsabilidad de cada codeudor. La mora de uno de los deudores o de uno de los acreedores, y los factores de atribución de responsabilidad de uno u otro, no perjudican a los demás.", practicalEffects: ['En la práctica, este artículo rige responsabilidad de cada codeudor. La mora de uno de los deudores o de uno de los acreedores, y los factores de atribución de responsabilidad de uno u otro, no perjudican a los demás.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'cada', 'codeudor', 'articulo 819'], segments: [], amendments: [] },
  { id: 'ccyc-art-820', lawId: 'codigo-civil-comercial', number: '820', order: 820, title: "Contribución", originalText: "Contribución. Si uno de los deudores paga la totalidad de la deuda, o repara la totalidad de los daños, o realiza gastos en interés común, tiene derecho a reclamar a los demás la contribución del valor de lo que ha invertido en interés de ellos, con los alcances que determina el artículo 841.", currentText: "Contribución. Si uno de los deudores paga la totalidad de la deuda, o repara la totalidad de los daños, o realiza gastos en interés común, tiene derecho a reclamar a los demás la contribución del valor de lo que ha invertido en interés de ellos, con los alcances que determina el artículo 841.", plainLanguageExplanation: "Establece el régimen de contribución. Si uno de los deudores paga la totalidad de la deuda, o repara la totalidad de los daños, o realiza gastos en interés común, tiene derecho a reclamar a los demás la contribución del valor de lo que ha invertido en interés de ellos, con los alcances que determina el artículo 841.", practicalEffects: ['En la práctica, este artículo rige contribución. Si uno de los deudores paga la totalidad de la deuda, o repara la totalidad de los daños, o realiza gastos en interés común, tiene derecho a reclamar'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contribucinarticulo 820'], segments: [], amendments: [] },
  { id: 'ccyc-art-821', lawId: 'codigo-civil-comercial', number: '821', order: 821, title: "Participación", originalText: "Participación. Si uno de los acreedores recibe la totalidad del crédito o de la reparación de los daños, o más que su cuota, los demás tienen derecho a que les pague el valor de lo que les corresponde conforme a la cuota de participación de cada uno de ellos, con los alcances que determina el artículo 841. Tienen igual derecho si el crédito se extingue total o parcialmente, por compensación legal.", currentText: "Participación. Si uno de los acreedores recibe la totalidad del crédito o de la reparación de los daños, o más que su cuota, los demás tienen derecho a que les pague el valor de lo que les corresponde conforme a la cuota de participación de cada uno de ellos, con los alcances que determina el artículo 841. Tienen igual derecho si el crédito se extingue total o parcialmente, por compensación legal.", plainLanguageExplanation: "Establece el régimen de participación. Si uno de los acreedores recibe la totalidad del crédito o de la reparación de los daños, o más que su cuota, los demás tienen derecho a que les pague el valor de lo que les corresponde conforme a la cuota de participación de cada uno de ellos, con los alcances que determina el artículo 841.", practicalEffects: ['En la práctica, este artículo rige participación. Si uno de los acreedores recibe la totalidad del crédito o de la reparación de los daños, o más que su cuota, los demás tienen derecho a que les pague'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['participacinarticulo 821'], segments: [], amendments: [] },
  { id: 'ccyc-art-822', lawId: 'codigo-civil-comercial', number: '822', order: 822, title: "Prescripción extintiva", originalText: "Prescripción extintiva. La prescripción extintiva cumplida es invocable por cualquiera de los deudores contra cualquiera de los acreedores. La interrupción y la suspensión del curso de la prescripción extintiva se rigen por lo dispuesto en el Libro Sexto.", currentText: "Prescripción extintiva. La prescripción extintiva cumplida es invocable por cualquiera de los deudores contra cualquiera de los acreedores. La interrupción y la suspensión del curso de la prescripción extintiva se rigen por lo dispuesto en el Libro Sexto.", plainLanguageExplanation: "Establece el régimen de prescripción extintiva. La prescripción extintiva cumplida es invocable por cualquiera de los deudores contra cualquiera de los acreedores.", practicalEffects: ['En la práctica, este artículo rige prescripción extintiva. La prescripción extintiva cumplida es invocable por cualquiera de los deudores contra cualquiera de los acreedores.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prescripcin', 'extintiva', 'articulo 822'], segments: [], amendments: [] },
  { id: 'ccyc-art-823', lawId: 'codigo-civil-comercial', number: '823', order: 823, title: "Normas subsidiarias", originalText: "Normas subsidiarias. Las normas relativas a las obligaciones solidarias son subsidiariamente aplicables a las obligaciones indivisibles.", currentText: "Normas subsidiarias. Las normas relativas a las obligaciones solidarias son subsidiariamente aplicables a las obligaciones indivisibles.", plainLanguageExplanation: "Establece el régimen de normas subsidiarias. Las normas relativas a las obligaciones solidarias son subsidiariamente aplicables a las obligaciones indivisibles.", practicalEffects: ['En la práctica, este artículo rige normas subsidiarias. Las normas relativas a las obligaciones solidarias son subsidiariamente aplicables a las obligaciones indivisibles.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['normas', 'subsidiarias', 'articulo 823'], segments: [], amendments: [] },
  { id: 'ccyc-art-824', lawId: 'codigo-civil-comercial', number: '824', order: 824, title: "Indivisibilidad impropia", originalText: "Indivisibilidad impropia. Las disposiciones de este parágrafo se aplican a las obligaciones cuyo cumplimiento sólo puede ser exigido por todos los acreedores en conjunto, o realizado por todos los deudores en conjunto, excepto las que otorgan a cada uno el derecho de cobrar o a pagar individualmente. SECCION 7ª Obligaciones de sujeto plural Parágrafo 1° Obligaciones simplemente mancomunadas", currentText: "Indivisibilidad impropia. Las disposiciones de este parágrafo se aplican a las obligaciones cuyo cumplimiento sólo puede ser exigido por todos los acreedores en conjunto, o realizado por todos los deudores en conjunto, excepto las que otorgan a cada uno el derecho de cobrar o a pagar individualmente. SECCION 7ª Obligaciones de sujeto plural Parágrafo 1° Obligaciones simplemente mancomunadas", plainLanguageExplanation: "Establece el régimen de indivisibilidad impropia. Las disposiciones de este parágrafo se aplican a las obligaciones cuyo cumplimiento sólo puede ser exigido por todos los acreedores en conjunto, o realizado por todos los deudores en conjunto, excepto las que otorgan a cada uno el derecho de cobrar o a pagar individualmente.", practicalEffects: ['En la práctica, este artículo rige indivisibilidad impropia. Las disposiciones de este parágrafo se aplican a las obligaciones cuyo cumplimiento sólo puede ser exigido por todos los acreedores en conjunto, o rea'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['indivisibilidad', 'impropia', 'articulo 824'], segments: [], amendments: [] },
  { id: 'ccyc-art-825', lawId: 'codigo-civil-comercial', number: '825', order: 825, title: "Concepto", originalText: "Concepto. La obligación simplemente mancomunada es aquella en la que el crédito o la deuda se fracciona en tantas relaciones particulares independientes entre sí como acreedores o deudores haya. Las cuotas respectivas se consideran deudas o créditos distintos los unos de los otros.", currentText: "Concepto. La obligación simplemente mancomunada es aquella en la que el crédito o la deuda se fracciona en tantas relaciones particulares independientes entre sí como acreedores o deudores haya. Las cuotas respectivas se consideran deudas o créditos distintos los unos de los otros.", plainLanguageExplanation: "Establece el régimen de concepto. La obligación simplemente mancomunada es aquella en la que el crédito o la deuda se fracciona en tantas relaciones particulares independientes entre sí como acreedores o deudores haya.", practicalEffects: ['En la práctica, este artículo rige concepto. La obligación simplemente mancomunada es aquella en la que el crédito o la deuda se fracciona en tantas relaciones particulares independientes entre sí como acreedores o deudores haya.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 825'], segments: [], amendments: [] },
  { id: 'ccyc-art-826', lawId: 'codigo-civil-comercial', number: '826', order: 826, title: "Efectos", originalText: "Efectos. Los efectos de la obligación simplemente mancomunada se rigen por lo dispuesto en la Sección 6a de este Capítulo, según que su objeto sea divisible o indivisible. Parágrafo 2° Obligaciones solidarias. Disposiciones generales", currentText: "Efectos. Los efectos de la obligación simplemente mancomunada se rigen por lo dispuesto en la Sección 6a de este Capítulo, según que su objeto sea divisible o indivisible. Parágrafo 2° Obligaciones solidarias. Disposiciones generales", plainLanguageExplanation: "Establece el régimen de efectos. Los efectos de la obligación simplemente mancomunada se rigen por lo dispuesto en la Sección 6a de este Capítulo, según que su objeto sea divisible o indivisible.", practicalEffects: ['En la práctica, este artículo rige efectos. Los efectos de la obligación simplemente mancomunada se rigen por lo dispuesto en la Sección 6a de este Capítulo, según que su objeto sea divisible o indivisible.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 826'], segments: [], amendments: [] },
  { id: 'ccyc-art-827', lawId: 'codigo-civil-comercial', number: '827', order: 827, title: "Concepto", originalText: "Concepto. Hay solidaridad en las obligaciones con pluralidad de sujetos y originadas en una causa única cuando, en razón del título constitutivo o de la ley, su cumplimiento total puede exigirse a cualquiera de los deudores, por cualquiera de los acreedores.", currentText: "Concepto. Hay solidaridad en las obligaciones con pluralidad de sujetos y originadas en una causa única cuando, en razón del título constitutivo o de la ley, su cumplimiento total puede exigirse a cualquiera de los deudores, por cualquiera de los acreedores.", plainLanguageExplanation: "Establece el régimen de concepto. Hay solidaridad en las obligaciones con pluralidad de sujetos y originadas en una causa única cuando, en razón del título constitutivo o de la ley, su cumplimiento total puede exigirse a cualquiera de los deudores, por cualquiera de los acreedores.", practicalEffects: ['En la práctica, este artículo rige concepto. Hay solidaridad en las obligaciones con pluralidad de sujetos y originadas en una causa única cuando, en razón del título constitutivo o de la ley, su'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 827'], segments: [], amendments: [] },
  { id: 'ccyc-art-828', lawId: 'codigo-civil-comercial', number: '828', order: 828, title: "Fuentes", originalText: "Fuentes. La solidaridad no se presume y debe surgir inequívocamente de la ley o del título constitutivo de la obligación.", currentText: "Fuentes. La solidaridad no se presume y debe surgir inequívocamente de la ley o del título constitutivo de la obligación.", plainLanguageExplanation: "Establece el régimen de fuentes. La solidaridad no se presume y debe surgir inequívocamente de la ley o del título constitutivo de la obligación.", practicalEffects: ['En la práctica, este artículo rige fuentes. La solidaridad no se presume y debe surgir inequívocamente de la ley o del título constitutivo de la obligación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fuentesarticulo 828'], segments: [], amendments: [] },
  { id: 'ccyc-art-829', lawId: 'codigo-civil-comercial', number: '829', order: 829, title: "Criterio de aplicación", originalText: "Criterio de aplicación. Con sujeción a lo dispuesto en este Parágrafo y en los dos siguientes, se considera que cada uno de los codeudores solidarios, en la solidaridad pasiva, y cada uno de los coacreedores, en la solidaridad activa, representa a los demás en los actos que realiza como tal.", currentText: "Criterio de aplicación. Con sujeción a lo dispuesto en este Parágrafo y en los dos siguientes, se considera que cada uno de los codeudores solidarios, en la solidaridad pasiva, y cada uno de los coacreedores, en la solidaridad activa, representa a los demás en los actos que realiza como tal.", plainLanguageExplanation: "Establece el régimen de criterio de aplicación. Con sujeción a lo dispuesto en este Parágrafo y en los dos siguientes, se considera que cada uno de los codeudores solidarios, en la solidaridad pasiva, y cada uno de los coacreedores, en la solidaridad activa, representa a los demás en los actos que realiza como tal.", practicalEffects: ['En la práctica, este artículo rige criterio de aplicación. Con sujeción a lo dispuesto en este Parágrafo y en los dos siguientes, se considera que cada uno de los codeudores solidarios, en la solidaridad pasiv'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['criterio', 'aplicacin', 'articulo 829'], segments: [], amendments: [] },
  { id: 'ccyc-art-830', lawId: 'codigo-civil-comercial', number: '830', order: 830, title: "Circunstancias de los vínculos", originalText: "Circunstancias de los vínculos. La incapacidad y la capacidad restringida de alguno de los acreedores o deudores solidarios no perjudica ni beneficia la situación de los demás; tampoco la existencia de modalidades a su respecto.", currentText: "Circunstancias de los vínculos. La incapacidad y la capacidad restringida de alguno de los acreedores o deudores solidarios no perjudica ni beneficia la situación de los demás; tampoco la existencia de modalidades a su respecto.", plainLanguageExplanation: "Establece el régimen de circunstancias de los vínculos. La incapacidad y la capacidad restringida de alguno de los acreedores o deudores solidarios no perjudica ni beneficia la situación de los demás; tampoco la existencia de modalidades a su respecto.", practicalEffects: ['En la práctica, este artículo rige circunstancias de los vínculos. La incapacidad y la capacidad restringida de alguno de los acreedores o deudores solidarios no perjudica ni beneficia la situación de los demás; tampo'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['circunstancias', 'vnculos', 'articulo 830'], segments: [], amendments: [] },
  { id: 'ccyc-art-831', lawId: 'codigo-civil-comercial', number: '831', order: 831, title: "Defensas", originalText: "Defensas. Cada uno de los deudores puede oponer al acreedor las defensas comunes a todos ellos. Las defensas personales pueden oponerse exclusivamente por el deudor o acreedor a quien correspondan, y sólo tienen valor frente al coacreedor a quien se refieran. Sin embargo, pueden expandir limitadamente sus efectos hacia los demás codeudores, y posibilitar una reducción del monto total de la deuda que se les reclama, hasta la concurrencia de la parte perteneciente en la deuda al codeudor que las puede invocar.", currentText: "Defensas. Cada uno de los deudores puede oponer al acreedor las defensas comunes a todos ellos. Las defensas personales pueden oponerse exclusivamente por el deudor o acreedor a quien correspondan, y sólo tienen valor frente al coacreedor a quien se refieran. Sin embargo, pueden expandir limitadamente sus efectos hacia los demás codeudores, y posibilitar una reducción del monto total de la deuda que se les reclama, hasta la concurrencia de la parte perteneciente en la deuda al codeudor que las puede invocar.", plainLanguageExplanation: "Establece el régimen de defensas. Cada uno de los deudores puede oponer al acreedor las defensas comunes a todos ellos.", practicalEffects: ['En la práctica, este artículo rige defensas. Cada uno de los deudores puede oponer al acreedor las defensas comunes a todos ellos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['defensasarticulo 831'], segments: [], amendments: [] },
  { id: 'ccyc-art-832', lawId: 'codigo-civil-comercial', number: '832', order: 832, title: "Cosa juzgada", originalText: "Cosa juzgada. La sentencia dictada contra uno de los codeudores no es oponible a los demás, pero éstos pueden invocarla cuando no se funda en circunstancias personales del codeudor demandado. El deudor no puede oponer a los demás coacreedores la sentencia obtenida contra uno de ellos; pero los coacreedores pueden oponerla al deudor, sin perjuicio de las excepciones personales que éste tenga frente a cada uno de ellos. Parágrafo 3° Solidaridad pasiva", currentText: "Cosa juzgada. La sentencia dictada contra uno de los codeudores no es oponible a los demás, pero éstos pueden invocarla cuando no se funda en circunstancias personales del codeudor demandado. El deudor no puede oponer a los demás coacreedores la sentencia obtenida contra uno de ellos; pero los coacreedores pueden oponerla al deudor, sin perjuicio de las excepciones personales que éste tenga frente a cada uno de ellos. Parágrafo 3° Solidaridad pasiva", plainLanguageExplanation: "Establece el régimen de cosa juzgada. La sentencia dictada contra uno de los codeudores no es oponible a los demás, pero éstos pueden invocarla cuando no se funda en circunstancias personales del codeudor demandado.", practicalEffects: ['En la práctica, este artículo rige cosa juzgada. La sentencia dictada contra uno de los codeudores no es oponible a los demás, pero éstos pueden invocarla cuando no se funda en circunstancias personales del codeudor demandado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cosa', 'juzgada', 'articulo 832'], segments: [], amendments: [] },
  { id: 'ccyc-art-833', lawId: 'codigo-civil-comercial', number: '833', order: 833, title: "Derecho a cobrar", originalText: "Derecho a cobrar. El acreedor tiene derecho a requerir el pago a uno, a varios o a todos los codeudores, simultánea o sucesivamente.", currentText: "Derecho a cobrar. El acreedor tiene derecho a requerir el pago a uno, a varios o a todos los codeudores, simultánea o sucesivamente.", plainLanguageExplanation: "Establece el régimen de derecho a cobrar. El acreedor tiene derecho a requerir el pago a uno, a varios o a todos los codeudores, simultánea o sucesivamente.", practicalEffects: ['En la práctica, este artículo rige derecho a cobrar. El acreedor tiene derecho a requerir el pago a uno, a varios o a todos los codeudores, simultánea o sucesivamente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'cobrar', 'articulo 833'], segments: [], amendments: [] },
  { id: 'ccyc-art-834', lawId: 'codigo-civil-comercial', number: '834', order: 834, title: "Derecho a pagar", originalText: "Derecho a pagar. Cualquiera de los deudores solidarios tiene derecho a pagar la totalidad de la deuda, sin perjuicio de lo dispuesto en el artículo 837.", currentText: "Derecho a pagar. Cualquiera de los deudores solidarios tiene derecho a pagar la totalidad de la deuda, sin perjuicio de lo dispuesto en el artículo 837.", plainLanguageExplanation: "Establece el régimen de derecho a pagar. Cualquiera de los deudores solidarios tiene derecho a pagar la totalidad de la deuda, sin perjuicio de lo dispuesto en el artículo 837.", practicalEffects: ['En la práctica, este artículo rige derecho a pagar. Cualquiera de los deudores solidarios tiene derecho a pagar la totalidad de la deuda, sin perjuicio de lo dispuesto en el artículo 837.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'pagar', 'articulo 834'], segments: [], amendments: [] },
  { id: 'ccyc-art-835', lawId: 'codigo-civil-comercial', number: '835', order: 835, title: "Modos extintivos", originalText: "Modos extintivos. Con sujeción a disposiciones especiales, los modos extintivos inciden, según el caso, sobre la obligación, o sobre la cuota de algún deudor solidario, conforme a las siguientes reglas: a) la obligación se extingue en el todo cuando uno de los deudores solidarios paga la deuda; b) la obligación también se extingue en el todo si el acreedor renuncia a su crédito a favor de uno de los deudores solidarios, o si se produce novación, dación en pago o compensación entre el acreedor y uno de los deudores solidarios; c) la confusión entre el acreedor y uno de los deudores solidarios sólo extingue la cuota de la deuda que corresponde a éste. La obligación subsistente conserva el carácter solidario; d) la transacción hecha con uno de los codeudores solidarios, aprovecha a los otros, pero no puede serles opuesta.", currentText: "Modos extintivos. Con sujeción a disposiciones especiales, los modos extintivos inciden, según el caso, sobre la obligación, o sobre la cuota de algún deudor solidario, conforme a las siguientes reglas: a) la obligación se extingue en el todo cuando uno de los deudores solidarios paga la deuda; b) la obligación también se extingue en el todo si el acreedor renuncia a su crédito a favor de uno de los deudores solidarios, o si se produce novación, dación en pago o compensación entre el acreedor y uno de los deudores solidarios; c) la confusión entre el acreedor y uno de los deudores solidarios sólo extingue la cuota de la deuda que corresponde a éste. La obligación subsistente conserva el carácter solidario; d) la transacción hecha con uno de los codeudores solidarios, aprovecha a los otros, pero no puede serles opuesta.", plainLanguageExplanation: "Establece el régimen de modos extintivos. Con sujeción a disposiciones especiales, los modos extintivos inciden, según el caso, sobre la obligación, o sobre la cuota de algún deudor solidario, conforme a las siguientes reglas: a) la obligación se extingue en el todo cuando uno de los deudores solidarios paga la deuda; b)", practicalEffects: ['En la práctica, este artículo rige modos extintivos. Con sujeción a disposiciones especiales, los modos extintivos inciden, según el caso, sobre la obligación, o sobre la cuota de algún deudor solidario,'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['modos', 'extintivos', 'articulo 835'], segments: [], amendments: [] },
  { id: 'ccyc-art-836', lawId: 'codigo-civil-comercial', number: '836', order: 836, title: "Extinción absoluta de la solidaridad", originalText: "Extinción absoluta de la solidaridad. Si el acreedor, sin renunciar al crédito, renuncia expresamente a la solidaridad en beneficio de todos los deudores solidarios, consintiendo la división de la deuda, ésta se transforma en simplemente mancomunada.", currentText: "Extinción absoluta de la solidaridad. Si el acreedor, sin renunciar al crédito, renuncia expresamente a la solidaridad en beneficio de todos los deudores solidarios, consintiendo la división de la deuda, ésta se transforma en simplemente mancomunada.", plainLanguageExplanation: "Establece el régimen de extinción absoluta de la solidaridad. Si el acreedor, sin renunciar al crédito, renuncia expresamente a la solidaridad en beneficio de todos los deudores solidarios, consintiendo la división de la deuda, ésta se transforma en simplemente mancomunada.", practicalEffects: ['En la práctica, este artículo rige extinción absoluta de la solidaridad. Si el acreedor, sin renunciar al crédito, renuncia expresamente a la solidaridad en beneficio de todos los deudores solidarios, consintiendo la divisi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extincin', 'absoluta', 'solidaridad', 'articulo 836'], segments: [], amendments: [] },
  { id: 'ccyc-art-837', lawId: 'codigo-civil-comercial', number: '837', order: 837, title: "Extinción relativa de la solidaridad", originalText: "Extinción relativa de la solidaridad. Si el acreedor, sin renunciar al crédito, renuncia expresa o tácitamente a la solidaridad en beneficio de uno solo de los deudores solidarios, la deuda continúa siendo solidaria respecto de los demás, con deducción de la cuota correspondiente al deudor beneficiario.", currentText: "Extinción relativa de la solidaridad. Si el acreedor, sin renunciar al crédito, renuncia expresa o tácitamente a la solidaridad en beneficio de uno solo de los deudores solidarios, la deuda continúa siendo solidaria respecto de los demás, con deducción de la cuota correspondiente al deudor beneficiario.", plainLanguageExplanation: "Establece el régimen de extinción relativa de la solidaridad. Si el acreedor, sin renunciar al crédito, renuncia expresa o tácitamente a la solidaridad en beneficio de uno solo de los deudores solidarios, la deuda continúa siendo solidaria respecto de los demás, con deducción de la cuota correspondiente al deudor beneficiario.", practicalEffects: ['En la práctica, este artículo rige extinción relativa de la solidaridad. Si el acreedor, sin renunciar al crédito, renuncia expresa o tácitamente a la solidaridad en beneficio de uno solo de los deudores solidarios, la deud'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extincin', 'relativa', 'solidaridad', 'articulo 837'], segments: [], amendments: [] },
  { id: 'ccyc-art-838', lawId: 'codigo-civil-comercial', number: '838', order: 838, title: "Responsabilidad", originalText: "Responsabilidad. La mora de uno de los deudores solidarios perjudica a los demás. Si el cumplimiento se hace imposible por causas imputables a un codeudor, los demás responden por el equivalente de la prestación debida y la indemnización de daños y perjuicios. Las consecuencias propias del incumplimiento doloso de uno de los deudores no son soportadas por los otros.", currentText: "Responsabilidad. La mora de uno de los deudores solidarios perjudica a los demás. Si el cumplimiento se hace imposible por causas imputables a un codeudor, los demás responden por el equivalente de la prestación debida y la indemnización de daños y perjuicios. Las consecuencias propias del incumplimiento doloso de uno de los deudores no son soportadas por los otros.", plainLanguageExplanation: "Establece el régimen de responsabilidad. La mora de uno de los deudores solidarios perjudica a los demás.", practicalEffects: ['En la práctica, este artículo rige responsabilidad. La mora de uno de los deudores solidarios perjudica a los demás.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidadarticulo 838'], segments: [], amendments: [] },
  { id: 'ccyc-art-839', lawId: 'codigo-civil-comercial', number: '839', order: 839, title: "Interrupción y suspensión de la prescripción", originalText: "Interrupción y suspensión de la prescripción. La interrupción y la suspensión del curso de la prescripción extintiva están regidas por lo dispuesto en el Título I del Libro Sexto.", currentText: "Interrupción y suspensión de la prescripción. La interrupción y la suspensión del curso de la prescripción extintiva están regidas por lo dispuesto en el Título I del Libro Sexto.", plainLanguageExplanation: "Establece el régimen de interrupción y suspensión de la prescripción. La interrupción y la suspensión del curso de la prescripción extintiva están regidas por lo dispuesto en el Título I del Libro Sexto.", practicalEffects: ['En la práctica, este artículo rige interrupción y suspensión de la prescripción. La interrupción y la suspensión del curso de la prescripción extintiva están regidas por lo dispuesto en el Título I del Libro Sexto.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['interrupcin', 'suspensin', 'prescripcin', 'articulo 839'], segments: [], amendments: [] },
  { id: 'ccyc-art-840', lawId: 'codigo-civil-comercial', number: '840', order: 840, title: "Contribución", originalText: "Contribución. El deudor que efectúa el pago puede repetirlo de los demás codeudores según la participación que cada uno tiene en la deuda. La acción de regreso no procede en caso de haberse remitido gratuitamente la deuda.", currentText: "Contribución. El deudor que efectúa el pago puede repetirlo de los demás codeudores según la participación que cada uno tiene en la deuda. La acción de regreso no procede en caso de haberse remitido gratuitamente la deuda.", plainLanguageExplanation: "Establece el régimen de contribución. El deudor que efectúa el pago puede repetirlo de los demás codeudores según la participación que cada uno tiene en la deuda.", practicalEffects: ['En la práctica, este artículo rige contribución. El deudor que efectúa el pago puede repetirlo de los demás codeudores según la participación que cada uno tiene en la deuda.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contribucinarticulo 840'], segments: [], amendments: [] },
  { id: 'ccyc-art-841', lawId: 'codigo-civil-comercial', number: '841', order: 841, title: "Determinación de la cuota de contribución", originalText: "Determinación de la cuota de contribución. Las cuotas de contribución se determinan sucesivamente de acuerdo con: a) lo pactado; b) la fuente y la finalidad de la obligación o, en su caso, la causa de la responsabilidad; c) las relaciones de los interesados entre sí; d) las demás circunstancias. Si por aplicación de estos criterios no es posible determinar las cuotas de contribución, se entiende que participan en partes iguales.", currentText: "Determinación de la cuota de contribución. Las cuotas de contribución se determinan sucesivamente de acuerdo con: a) lo pactado; b) la fuente y la finalidad de la obligación o, en su caso, la causa de la responsabilidad; c) las relaciones de los interesados entre sí; d) las demás circunstancias. Si por aplicación de estos criterios no es posible determinar las cuotas de contribución, se entiende que participan en partes iguales.", plainLanguageExplanation: "Establece el régimen de determinación de la cuota de contribución. Las cuotas de contribución se determinan sucesivamente de acuerdo con: a) lo pactado; b) la fuente y la finalidad de la obligación o, en su caso, la causa de la responsabilidad; c) las relaciones de los interesados entre sí; d) las demás circunstancias.", practicalEffects: ['En la práctica, este artículo rige determinación de la cuota de contribución. Las cuotas de contribución se determinan sucesivamente de acuerdo con: a) lo pactado; b) la fuente y la finalidad de la obligación o, en su caso, la c'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['determinacin', 'cuota', 'contribucin', 'articulo 841'], segments: [], amendments: [] },
  { id: 'ccyc-art-842', lawId: 'codigo-civil-comercial', number: '842', order: 842, title: "Caso de insolvencia", originalText: "Caso de insolvencia. La cuota correspondiente a los codeudores insolventes es cubierta por todos los obligados.", currentText: "Caso de insolvencia. La cuota correspondiente a los codeudores insolventes es cubierta por todos los obligados.", plainLanguageExplanation: "Establece el régimen de caso de insolvencia. La cuota correspondiente a los codeudores insolventes es cubierta por todos los obligados.", practicalEffects: ['En la práctica, este artículo rige caso de insolvencia. La cuota correspondiente a los codeudores insolventes es cubierta por todos los obligados.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caso', 'insolvencia', 'articulo 842'], segments: [], amendments: [] },
  { id: 'ccyc-art-843', lawId: 'codigo-civil-comercial', number: '843', order: 843, title: "Muerte de un deudor", originalText: "Muerte de un deudor. Si muere uno de los deudores solidarios y deja varios herederos, la deuda ingresa en la masa indivisa y cualquiera de los acreedores puede oponerse a que los bienes se entreguen a los herederos o legatarios sin haber sido previamente pagado. Después de la partición, cada heredero está obligado a pagar según la cuota que le corresponde en el haber hereditario. Parágrafo 4° Solidaridad activa", currentText: "Muerte de un deudor. Si muere uno de los deudores solidarios y deja varios herederos, la deuda ingresa en la masa indivisa y cualquiera de los acreedores puede oponerse a que los bienes se entreguen a los herederos o legatarios sin haber sido previamente pagado. Después de la partición, cada heredero está obligado a pagar según la cuota que le corresponde en el haber hereditario. Parágrafo 4° Solidaridad activa", plainLanguageExplanation: "Establece el régimen de muerte de un deudor. Si muere uno de los deudores solidarios y deja varios herederos, la deuda ingresa en la masa indivisa y cualquiera de los acreedores puede oponerse a que los bienes se entreguen a los herederos o legatarios sin haber sido previamente pagado.", practicalEffects: ['En la práctica, este artículo rige muerte de un deudor. Si muere uno de los deudores solidarios y deja varios herederos, la deuda ingresa en la masa indivisa y cualquiera de los acreedores puede oponerse a'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['muerte', 'deudor', 'articulo 843'], segments: [], amendments: [] },
  { id: 'ccyc-art-844', lawId: 'codigo-civil-comercial', number: '844', order: 844, title: "Derecho al cobro", originalText: "Derecho al cobro. El acreedor, o cada acreedor, o todos ellos conjuntamente, pueden reclamar al deudor la totalidad de la obligación.", currentText: "Derecho al cobro. El acreedor, o cada acreedor, o todos ellos conjuntamente, pueden reclamar al deudor la totalidad de la obligación.", plainLanguageExplanation: "Establece el régimen de derecho al cobro. El acreedor, o cada acreedor, o todos ellos conjuntamente, pueden reclamar al deudor la totalidad de la obligación.", practicalEffects: ['En la práctica, este artículo rige derecho al cobro. El acreedor, o cada acreedor, o todos ellos conjuntamente, pueden reclamar al deudor la totalidad de la obligación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'cobro', 'articulo 844'], segments: [], amendments: [] },
  { id: 'ccyc-art-845', lawId: 'codigo-civil-comercial', number: '845', order: 845, title: "Prevención de un acreedor", originalText: "Prevención de un acreedor. Si uno de los acreedores solidarios ha demandado judicialmente el cobro al deudor, el pago sólo puede ser hecho por éste al acreedor demandante.", currentText: "Prevención de un acreedor. Si uno de los acreedores solidarios ha demandado judicialmente el cobro al deudor, el pago sólo puede ser hecho por éste al acreedor demandante.", plainLanguageExplanation: "Establece el régimen de prevención de un acreedor. Si uno de los acreedores solidarios ha demandado judicialmente el cobro al deudor, el pago sólo puede ser hecho por éste al acreedor demandante.", practicalEffects: ['En la práctica, este artículo rige prevención de un acreedor. Si uno de los acreedores solidarios ha demandado judicialmente el cobro al deudor, el pago sólo puede ser hecho por éste al acreedor demandante.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prevencin', 'acreedor', 'articulo 845'], segments: [], amendments: [] },
  { id: 'ccyc-art-846', lawId: 'codigo-civil-comercial', number: '846', order: 846, title: "Modos extintivos", originalText: "Modos extintivos. Sujeto a disposiciones especiales, los modos extintivos inciden, según el caso, sobre la obligación, o sobre la cuota de algún acreedor solidario, conforme a las siguientes reglas: a) la obligación se extingue en el todo cuando uno de los acreedores solidarios recibe el pago del crédito; b) en tanto alguno de los acreedores solidarios no haya demandado el pago al deudor, la obligación también se extingue en el todo si uno de ellos renuncia a su crédito a favor del deudor, o si se produce novación, dación en pago o compensación entre uno de ellos y el deudor; c) la confusión entre el deudor y uno de los acreedores solidarios sólo extingue la cuota del crédito que corresponde a éste; d) la transacción hecha por uno de los coacreedores solidarios con el deudor no es oponible a los otros acreedores, excepto que éstos quieran aprovecharse de ésta.", currentText: "Modos extintivos. Sujeto a disposiciones especiales, los modos extintivos inciden, según el caso, sobre la obligación, o sobre la cuota de algún acreedor solidario, conforme a las siguientes reglas: a) la obligación se extingue en el todo cuando uno de los acreedores solidarios recibe el pago del crédito; b) en tanto alguno de los acreedores solidarios no haya demandado el pago al deudor, la obligación también se extingue en el todo si uno de ellos renuncia a su crédito a favor del deudor, o si se produce novación, dación en pago o compensación entre uno de ellos y el deudor; c) la confusión entre el deudor y uno de los acreedores solidarios sólo extingue la cuota del crédito que corresponde a éste; d) la transacción hecha por uno de los coacreedores solidarios con el deudor no es oponible a los otros acreedores, excepto que éstos quieran aprovecharse de ésta.", plainLanguageExplanation: "Establece el régimen de modos extintivos. Sujeto a disposiciones especiales, los modos extintivos inciden, según el caso, sobre la obligación, o sobre la cuota de algún acreedor solidario, conforme a las siguientes reglas: a) la obligación se extingue en el todo cuando uno de los acreedores solidarios recibe el pago del", practicalEffects: ['En la práctica, este artículo rige modos extintivos. Sujeto a disposiciones especiales, los modos extintivos inciden, según el caso, sobre la obligación, o sobre la cuota de algún acreedor solidario, con'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['modos', 'extintivos', 'articulo 846'], segments: [], amendments: [] },
  { id: 'ccyc-art-847', lawId: 'codigo-civil-comercial', number: '847', order: 847, title: "Participación", originalText: "Participación. Los acreedores solidarios tienen derecho a la participación con los siguientes alcances: a) si uno de los acreedores solidarios recibe la totalidad del crédito o de la reparación del daño, o más que su cuota, los demás tienen derecho a que les pague el valor de lo que les corresponde conforme a la cuota de participación de cada uno; b) en los casos del inciso b) del artículo 846, los demás acreedores solidarios tienen derecho a la participación, si hubo renuncia al crédito o compensación legal por la cuota de cada uno en el crédito original; y si hubo compensación convencional o facultativa, novación, dación en pago o transacción, por la cuota de cada uno en el crédito original, o por la que correspondería a cada uno conforme lo resultante de los actos extintivos, a su elección; c) el acreedor solidario que realiza gastos razonables en interés común tiene derecho a reclamar a los demás la participación en el reembolso de su valor.", currentText: "Participación. Los acreedores solidarios tienen derecho a la participación con los siguientes alcances: a) si uno de los acreedores solidarios recibe la totalidad del crédito o de la reparación del daño, o más que su cuota, los demás tienen derecho a que les pague el valor de lo que les corresponde conforme a la cuota de participación de cada uno; b) en los casos del inciso b) del artículo 846, los demás acreedores solidarios tienen derecho a la participación, si hubo renuncia al crédito o compensación legal por la cuota de cada uno en el crédito original; y si hubo compensación convencional o facultativa, novación, dación en pago o transacción, por la cuota de cada uno en el crédito original, o por la que correspondería a cada uno conforme lo resultante de los actos extintivos, a su elección; c) el acreedor solidario que realiza gastos razonables en interés común tiene derecho a reclamar a los demás la participación en el reembolso de su valor.", plainLanguageExplanation: "Establece el régimen de participación. Los acreedores solidarios tienen derecho a la participación con los siguientes alcances: a) si uno de los acreedores solidarios recibe la totalidad del crédito o de la reparación del daño, o más que su cuota, los demás tienen derecho a que les pague el valor de lo que les corresp", practicalEffects: ['En la práctica, este artículo rige participación. Los acreedores solidarios tienen derecho a la participación con los siguientes alcances: a) si uno de los acreedores solidarios recibe la totalidad de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['participacinarticulo 847'], segments: [], amendments: [] },
  { id: 'ccyc-art-848', lawId: 'codigo-civil-comercial', number: '848', order: 848, title: "Cuotas de participación", originalText: "Cuotas de participación. Las cuotas de participación de los acreedores solidarios se determinan conforme lo dispuesto en el artículo 841.", currentText: "Cuotas de participación. Las cuotas de participación de los acreedores solidarios se determinan conforme lo dispuesto en el artículo 841.", plainLanguageExplanation: "Establece el régimen de cuotas de participación. Las cuotas de participación de los acreedores solidarios se determinan conforme lo dispuesto en el artículo 841.", practicalEffects: ['En la práctica, este artículo rige cuotas de participación. Las cuotas de participación de los acreedores solidarios se determinan conforme lo dispuesto en el artículo 841.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cuotas', 'participacin', 'articulo 848'], segments: [], amendments: [] },
  { id: 'ccyc-art-849', lawId: 'codigo-civil-comercial', number: '849', order: 849, title: "Muerte de un acreedor", originalText: "Muerte de un acreedor. Si muere uno de los acreedores solidarios, el crédito se divide entre sus herederos en proporción a su participación en la herencia. Después de la partición, cada heredero tiene derecho a percibir según la cuota que le corresponde en el haber hereditario. SECCION 8ª Obligaciones concurrentes", currentText: "Muerte de un acreedor. Si muere uno de los acreedores solidarios, el crédito se divide entre sus herederos en proporción a su participación en la herencia. Después de la partición, cada heredero tiene derecho a percibir según la cuota que le corresponde en el haber hereditario. SECCION 8ª Obligaciones concurrentes", plainLanguageExplanation: "Establece el régimen de muerte de un acreedor. Si muere uno de los acreedores solidarios, el crédito se divide entre sus herederos en proporción a su participación en la herencia.", practicalEffects: ['En la práctica, este artículo rige muerte de un acreedor. Si muere uno de los acreedores solidarios, el crédito se divide entre sus herederos en proporción a su participación en la herencia.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['muerte', 'acreedor', 'articulo 849'], segments: [], amendments: [] },
  { id: 'ccyc-art-850', lawId: 'codigo-civil-comercial', number: '850', order: 850, title: "Concepto", originalText: "Concepto. Obligaciones concurrentes son aquellas en las que varios deudores deben el mismo objeto en razón de causas diferentes.", currentText: "Concepto. Obligaciones concurrentes son aquellas en las que varios deudores deben el mismo objeto en razón de causas diferentes.", plainLanguageExplanation: "Establece el régimen de concepto. Obligaciones concurrentes son aquellas en las que varios deudores deben el mismo objeto en razón de causas diferentes.", practicalEffects: ['En la práctica, este artículo rige concepto. Obligaciones concurrentes son aquellas en las que varios deudores deben el mismo objeto en razón de causas diferentes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 850'], segments: [], amendments: [] },
  { id: 'ccyc-art-851', lawId: 'codigo-civil-comercial', number: '851', order: 851, title: "Efectos", originalText: "Efectos. Excepto disposición especial en contrario, las obligaciones concurrentes se rigen por las siguientes reglas: a) el acreedor tiene derecho a requerir el pago a uno, a varios o a todos los codeudores, simultánea o sucesivamente; b) el pago realizado por uno de los deudores extingue la obligación de los otros obligados concurrentes; c) la dación en pago, la transacción, la novación y la compensación realizadas con uno de los deudores concurrentes, en tanto satisfagan íntegramente el interés del acreedor, extinguen la obligación de los otros obligados concurrentes o, en su caso, la extinguen parcialmente en la medida de lo satisfecho; d) la confusión entre el acreedor y uno de los deudores concurrentes y la renuncia al crédito a favor de uno de los deudores no extingue la deuda de los otros obligados concurrentes; e) la prescripción cumplida y la interrupción y suspensión de su curso no producen efectos expansivos respecto de los otros obligados concurrentes; f) la mora de uno de los deudores no produce efectos expansivos con respecto a los otros codeudores; g) la sentencia pasada en autoridad de cosa juzgada dictada contra uno de los codeudores no es oponible a los demás, pero éstos pueden invocarla cuando no se funda en circunstancias personales del codeudor demandado; h) la acción de contribución del deudor que paga la deuda contra los otros obligados concurrentes se rige por las relaciones causales que originan la concurrencia.", currentText: "Efectos. Excepto disposición especial en contrario, las obligaciones concurrentes se rigen por las siguientes reglas: a) el acreedor tiene derecho a requerir el pago a uno, a varios o a todos los codeudores, simultánea o sucesivamente; b) el pago realizado por uno de los deudores extingue la obligación de los otros obligados concurrentes; c) la dación en pago, la transacción, la novación y la compensación realizadas con uno de los deudores concurrentes, en tanto satisfagan íntegramente el interés del acreedor, extinguen la obligación de los otros obligados concurrentes o, en su caso, la extinguen parcialmente en la medida de lo satisfecho; d) la confusión entre el acreedor y uno de los deudores concurrentes y la renuncia al crédito a favor de uno de los deudores no extingue la deuda de los otros obligados concurrentes; e) la prescripción cumplida y la interrupción y suspensión de su curso no producen efectos expansivos respecto de los otros obligados concurrentes; f) la mora de uno de los deudores no produce efectos expansivos con respecto a los otros codeudores; g) la sentencia pasada en autoridad de cosa juzgada dictada contra uno de los codeudores no es oponible a los demás, pero éstos pueden invocarla cuando no se funda en circunstancias personales del codeudor demandado; h) la acción de contribución del deudor que paga la deuda contra los otros obligados concurrentes se rige por las relaciones causales que originan la concurrencia.", plainLanguageExplanation: "Establece el régimen de efectos. Excepto disposición especial en contrario, las obligaciones concurrentes se rigen por las siguientes reglas: a) el acreedor tiene derecho a requerir el pago a uno, a varios o a todos los codeudores, simultánea o sucesivamente; b) el pago realizado por uno de los deudores extingue", practicalEffects: ['En la práctica, este artículo rige efectos. Excepto disposición especial en contrario, las obligaciones concurrentes se rigen por las siguientes reglas: a) el acreedor tiene derecho a requerir e'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 851'], segments: [], amendments: [] },
  { id: 'ccyc-art-852', lawId: 'codigo-civil-comercial', number: '852', order: 852, title: "Normas subsidiarias", originalText: "Normas subsidiarias. Las normas relativas a las obligaciones solidarias son subsidiariamente aplicables a las obligaciones concurrentes. SECCION 9ª Obligaciones disyuntivas", currentText: "Normas subsidiarias. Las normas relativas a las obligaciones solidarias son subsidiariamente aplicables a las obligaciones concurrentes. SECCION 9ª Obligaciones disyuntivas", plainLanguageExplanation: "Establece el régimen de normas subsidiarias. Las normas relativas a las obligaciones solidarias son subsidiariamente aplicables a las obligaciones concurrentes.", practicalEffects: ['En la práctica, este artículo rige normas subsidiarias. Las normas relativas a las obligaciones solidarias son subsidiariamente aplicables a las obligaciones concurrentes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['normas', 'subsidiarias', 'articulo 852'], segments: [], amendments: [] },
  { id: 'ccyc-art-853', lawId: 'codigo-civil-comercial', number: '853', order: 853, title: "Alcances", originalText: "Alcances. Si la obligación debe ser cumplida por uno de varios sujetos, excepto estipulación en contrario, el acreedor elige cuál de ellos debe realizar el pago. Mientras el acreedor no demande a uno de los sujetos, cualquiera de ellos tiene derecho de pagar. El que paga no tiene derecho de exigir contribución o reembolso de los otros sujetos obligados.", currentText: "Alcances. Si la obligación debe ser cumplida por uno de varios sujetos, excepto estipulación en contrario, el acreedor elige cuál de ellos debe realizar el pago. Mientras el acreedor no demande a uno de los sujetos, cualquiera de ellos tiene derecho de pagar. El que paga no tiene derecho de exigir contribución o reembolso de los otros sujetos obligados.", plainLanguageExplanation: "Establece el régimen de alcances. Si la obligación debe ser cumplida por uno de varios sujetos, excepto estipulación en contrario, el acreedor elige cuál de ellos debe realizar el pago.", practicalEffects: ['En la práctica, este artículo rige alcances. Si la obligación debe ser cumplida por uno de varios sujetos, excepto estipulación en contrario, el acreedor elige cuál de ellos debe realizar el pago.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['alcancesarticulo 853'], segments: [], amendments: [] },
  { id: 'ccyc-art-854', lawId: 'codigo-civil-comercial', number: '854', order: 854, title: "Disyunción activa", originalText: "Disyunción activa. Si la obligación debe ser cumplida a favor de uno de varios sujetos, excepto estipulación en contrario, el deudor elige a cuál de éstos realiza el pago. La demanda de uno de los acreedores al deudor no extingue el derecho de éste a pagar a cualquiera de ellos. El que recibe el pago no está obligado a participarlo con los demás.", currentText: "Disyunción activa. Si la obligación debe ser cumplida a favor de uno de varios sujetos, excepto estipulación en contrario, el deudor elige a cuál de éstos realiza el pago. La demanda de uno de los acreedores al deudor no extingue el derecho de éste a pagar a cualquiera de ellos. El que recibe el pago no está obligado a participarlo con los demás.", plainLanguageExplanation: "Establece el régimen de disyunción activa. Si la obligación debe ser cumplida a favor de uno de varios sujetos, excepto estipulación en contrario, el deudor elige a cuál de éstos realiza el pago.", practicalEffects: ['En la práctica, este artículo rige disyunción activa. Si la obligación debe ser cumplida a favor de uno de varios sujetos, excepto estipulación en contrario, el deudor elige a cuál de éstos realiza el pago.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disyuncin', 'activa', 'articulo 854'], segments: [], amendments: [] },
  { id: 'ccyc-art-855', lawId: 'codigo-civil-comercial', number: '855', order: 855, title: "Reglas aplicables", originalText: "Reglas aplicables. Se aplican, subsidiariamente, las reglas de las obligaciones simplemente mancomunadas. SECCION 10ª Obligaciones principales y accesorias", currentText: "Reglas aplicables. Se aplican, subsidiariamente, las reglas de las obligaciones simplemente mancomunadas. SECCION 10ª Obligaciones principales y accesorias", plainLanguageExplanation: "Establece el régimen de reglas aplicables. Se aplican, subsidiariamente, las reglas de las obligaciones simplemente mancomunadas.", practicalEffects: ['En la práctica, este artículo rige reglas aplicables. Se aplican, subsidiariamente, las reglas de las obligaciones simplemente mancomunadas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglas', 'aplicables', 'articulo 855'], segments: [], amendments: [] },
  { id: 'ccyc-art-856', lawId: 'codigo-civil-comercial', number: '856', order: 856, title: "Definición", originalText: "Definición. Obligaciones principales son aquellas cuya existencia, régimen jurídico, eficacia y desarrollo funcional son autónomos e independientes de cualquier otro vínculo obligacional. Los derechos y obligaciones son accesorios a una obligación principal cuando dependen de ella en cualquiera de los aspectos precedentemente indicados, o cuando resultan esenciales para satisfacer el interés del acreedor.", currentText: "Definición. Obligaciones principales son aquellas cuya existencia, régimen jurídico, eficacia y desarrollo funcional son autónomos e independientes de cualquier otro vínculo obligacional. Los derechos y obligaciones son accesorios a una obligación principal cuando dependen de ella en cualquiera de los aspectos precedentemente indicados, o cuando resultan esenciales para satisfacer el interés del acreedor.", plainLanguageExplanation: "Establece el régimen de definición. Obligaciones principales son aquellas cuya existencia, régimen jurídico, eficacia y desarrollo funcional son autónomos e independientes de cualquier otro vínculo obligacional.", practicalEffects: ['En la práctica, este artículo rige definición. Obligaciones principales son aquellas cuya existencia, régimen jurídico, eficacia y desarrollo funcional son autónomos e independientes de cualquier otro vínculo obligacional.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 856'], segments: [], amendments: [] },
  { id: 'ccyc-art-857', lawId: 'codigo-civil-comercial', number: '857', order: 857, title: "Efectos", originalText: "Efectos. La extinción, nulidad o ineficacia del crédito principal, extinguen los derechos y obligaciones accesorios, excepto disposición legal o convencional en contrario. SECCION 11ª Rendición de cuentas", currentText: "Efectos. La extinción, nulidad o ineficacia del crédito principal, extinguen los derechos y obligaciones accesorios, excepto disposición legal o convencional en contrario. SECCION 11ª Rendición de cuentas", plainLanguageExplanation: "Establece el régimen de efectos. La extinción, nulidad o ineficacia del crédito principal, extinguen los derechos y obligaciones accesorios, excepto disposición legal o convencional en contrario.", practicalEffects: ['En la práctica, este artículo rige efectos. La extinción, nulidad o ineficacia del crédito principal, extinguen los derechos y obligaciones accesorios, excepto disposición legal o convencional en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 857'], segments: [], amendments: [] },
  { id: 'ccyc-art-858', lawId: 'codigo-civil-comercial', number: '858', order: 858, title: "Definiciones", originalText: "Definiciones. Se entiende por cuenta la descripción de los antecedentes, hechos y resultados pecuniarios de un negocio, aunque consista en un acto singular. Hay rendición de cuentas cuando se las pone en conocimiento de la persona interesada, conforme a lo dispuesto en los artículos siguientes.", currentText: "Definiciones. Se entiende por cuenta la descripción de los antecedentes, hechos y resultados pecuniarios de un negocio, aunque consista en un acto singular. Hay rendición de cuentas cuando se las pone en conocimiento de la persona interesada, conforme a lo dispuesto en los artículos siguientes.", plainLanguageExplanation: "Establece el régimen de definiciones. Se entiende por cuenta la descripción de los antecedentes, hechos y resultados pecuniarios de un negocio, aunque consista en un acto singular.", practicalEffects: ['En la práctica, este artículo rige definiciones. Se entiende por cuenta la descripción de los antecedentes, hechos y resultados pecuniarios de un negocio, aunque consista en un acto singular.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicionesarticulo 858'], segments: [], amendments: [] },
  { id: 'ccyc-art-859', lawId: 'codigo-civil-comercial', number: '859', order: 859, title: "Requisitos", originalText: "Requisitos. La rendición de cuentas debe: a) ser hecha de modo descriptivo y documentado; b) incluir las referencias y explicaciones razonablemente necesarias para su comprensión; c) acompañar los comprobantes de los ingresos y de los egresos, excepto que sea de uso no extenderlos; d) concordar con los libros que lleve quien las rinda.", currentText: "Requisitos. La rendición de cuentas debe: a) ser hecha de modo descriptivo y documentado; b) incluir las referencias y explicaciones razonablemente necesarias para su comprensión; c) acompañar los comprobantes de los ingresos y de los egresos, excepto que sea de uso no extenderlos; d) concordar con los libros que lleve quien las rinda.", plainLanguageExplanation: "Establece el régimen de requisitos. La rendición de cuentas debe: a) ser hecha de modo descriptivo y documentado; b) incluir las referencias y explicaciones razonablemente necesarias para su comprensión; c) acompañar los comprobantes de los ingresos y de los egresos, excepto que sea de uso no extenderlos; d) concor", practicalEffects: ['En la práctica, este artículo rige requisitos. La rendición de cuentas debe: a) ser hecha de modo descriptivo y documentado; b) incluir las referencias y explicaciones razonablemente necesarias par'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitosarticulo 859'], segments: [], amendments: [] },
  { id: 'ccyc-art-860', lawId: 'codigo-civil-comercial', number: '860', order: 860, title: "Obligación de rendir cuentas", originalText: "Obligación de rendir cuentas. Están obligados a rendir cuentas, excepto renuncia expresa del interesado: a) quien actúa en interés ajeno, aunque sea en nombre propio; b) quienes son parte en relaciones de ejecución continuada, cuando la rendición es apropiada a la naturaleza del negocio; c) quien debe hacerlo por disposición legal. La rendición de cuentas puede ser privada, excepto si la ley dispone que debe ser realizada ante un juez.", currentText: "Obligación de rendir cuentas. Están obligados a rendir cuentas, excepto renuncia expresa del interesado: a) quien actúa en interés ajeno, aunque sea en nombre propio; b) quienes son parte en relaciones de ejecución continuada, cuando la rendición es apropiada a la naturaleza del negocio; c) quien debe hacerlo por disposición legal. La rendición de cuentas puede ser privada, excepto si la ley dispone que debe ser realizada ante un juez.", plainLanguageExplanation: "Establece el régimen de obligación de rendir cuentas. Están obligados a rendir cuentas, excepto renuncia expresa del interesado: a) quien actúa en interés ajeno, aunque sea en nombre propio; b) quienes son parte en relaciones de ejecución continuada, cuando la rendición es apropiada a la naturaleza del negocio; c) quien debe hacerlo", practicalEffects: ['En la práctica, este artículo rige obligación de rendir cuentas. Están obligados a rendir cuentas, excepto renuncia expresa del interesado: a) quien actúa en interés ajeno, aunque sea en nombre propio; b) quienes so'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacin', 'rendir', 'cuentas', 'articulo 860'], segments: [], amendments: [] },
  { id: 'ccyc-art-861', lawId: 'codigo-civil-comercial', number: '861', order: 861, title: "Oportunidad", originalText: "Oportunidad. Las cuentas deben ser rendidas en la oportunidad en que estipulan las partes, o dispone la ley. En su defecto, la rendición de cuentas debe ser hecha: a) al concluir el negocio; b) si el negocio es de ejecución continuada, también al concluir cada uno de los períodos o al final de cada año calendario.", currentText: "Oportunidad. Las cuentas deben ser rendidas en la oportunidad en que estipulan las partes, o dispone la ley. En su defecto, la rendición de cuentas debe ser hecha: a) al concluir el negocio; b) si el negocio es de ejecución continuada, también al concluir cada uno de los períodos o al final de cada año calendario.", plainLanguageExplanation: "Establece el régimen de oportunidad. Las cuentas deben ser rendidas en la oportunidad en que estipulan las partes, o dispone la ley.", practicalEffects: ['En la práctica, este artículo rige oportunidad. Las cuentas deben ser rendidas en la oportunidad en que estipulan las partes, o dispone la ley.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['oportunidadarticulo 861'], segments: [], amendments: [] },
  { id: 'ccyc-art-862', lawId: 'codigo-civil-comercial', number: '862', order: 862, title: "Aprobación", originalText: "Aprobación. La rendición de cuentas puede ser aprobada expresa o tácitamente. Hay aprobación tácita si no es observada en el plazo convenido o dispuesto por la ley o, en su defecto, en el de treinta días de presentadas en debida forma. Sin embargo, puede ser observada por errores de cálculo o de registración dentro del plazo de caducidad de un año de recibida.", currentText: "Aprobación. La rendición de cuentas puede ser aprobada expresa o tácitamente. Hay aprobación tácita si no es observada en el plazo convenido o dispuesto por la ley o, en su defecto, en el de treinta días de presentadas en debida forma. Sin embargo, puede ser observada por errores de cálculo o de registración dentro del plazo de caducidad de un año de recibida.", plainLanguageExplanation: "Establece el régimen de aprobación. La rendición de cuentas puede ser aprobada expresa o tácitamente.", practicalEffects: ['En la práctica, este artículo rige aprobación. La rendición de cuentas puede ser aprobada expresa o tácitamente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aprobacinarticulo 862'], segments: [], amendments: [] },
  { id: 'ccyc-art-863', lawId: 'codigo-civil-comercial', number: '863', order: 863, title: "Relaciones de ejecución continuada", originalText: "Relaciones de ejecución continuada. En relaciones de ejecución continuada si la rendición de cuentas del último período es aprobada, se presume que también lo fueron las rendiciones correspondientes a los periodos anteriores.", currentText: "Relaciones de ejecución continuada. En relaciones de ejecución continuada si la rendición de cuentas del último período es aprobada, se presume que también lo fueron las rendiciones correspondientes a los periodos anteriores.", plainLanguageExplanation: "Establece el régimen de relaciones de ejecución continuada. En relaciones de ejecución continuada si la rendición de cuentas del último período es aprobada, se presume que también lo fueron las rendiciones correspondientes a los periodos anteriores.", practicalEffects: ['En la práctica, este artículo rige relaciones de ejecución continuada. En relaciones de ejecución continuada si la rendición de cuentas del último período es aprobada, se presume que también lo fueron las rendiciones corr'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['relaciones', 'ejecucin', 'continuada', 'articulo 863'], segments: [], amendments: [] },
  { id: 'ccyc-art-864', lawId: 'codigo-civil-comercial', number: '864', order: 864, title: "Saldos y documentos del interesado", originalText: "Saldos y documentos del interesado. Una vez aprobadas las cuentas: a) su saldo debe ser pagado en el plazo convenido o dispuesto por la ley o, en su defecto, en el de diez días; b) el obligado a rendirlas debe devolver al interesado los títulos y documentos que le hayan sido entregados, excepto las instrucciones de carácter personal. CAPITULO 4 Pago SECCION 1ª Disposiciones generales", currentText: "Saldos y documentos del interesado. Una vez aprobadas las cuentas: a) su saldo debe ser pagado en el plazo convenido o dispuesto por la ley o, en su defecto, en el de diez días; b) el obligado a rendirlas debe devolver al interesado los títulos y documentos que le hayan sido entregados, excepto las instrucciones de carácter personal. CAPITULO 4 Pago SECCION 1ª Disposiciones generales", plainLanguageExplanation: "Establece el régimen de saldos y documentos del interesado. Una vez aprobadas las cuentas: a) su saldo debe ser pagado en el plazo convenido o dispuesto por la ley o, en su defecto, en el de diez días; b) el obligado a rendirlas debe devolver al interesado los títulos y documentos que le hayan sido entregados, excepto las instrucciones de carácter personal.", practicalEffects: ['En la práctica, este artículo rige saldos y documentos del interesado. Una vez aprobadas las cuentas: a) su saldo debe ser pagado en el plazo convenido o dispuesto por la ley o, en su defecto, en el de diez días; b) el ob'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['saldos', 'documentos', 'interesado', 'articulo 864'], segments: [], amendments: [] },
  { id: 'ccyc-art-865', lawId: 'codigo-civil-comercial', number: '865', order: 865, title: "Definición", originalText: "Definición. Pago es el cumplimiento de la prestación que constituye el objeto de la obligación.", currentText: "Definición. Pago es el cumplimiento de la prestación que constituye el objeto de la obligación.", plainLanguageExplanation: "Establece el régimen de definición. Pago es el cumplimiento de la prestación que constituye el objeto de la obligación.", practicalEffects: ['En la práctica, este artículo rige definición. Pago es el cumplimiento de la prestación que constituye el objeto de la obligación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 865'], segments: [], amendments: [] },
  { id: 'ccyc-art-866', lawId: 'codigo-civil-comercial', number: '866', order: 866, title: "Reglas aplicables", originalText: "Reglas aplicables. Las reglas de los actos jurídicos se aplican al pago, con sujeción a las disposiciones de este Capítulo.", currentText: "Reglas aplicables. Las reglas de los actos jurídicos se aplican al pago, con sujeción a las disposiciones de este Capítulo.", plainLanguageExplanation: "Establece el régimen de reglas aplicables. Las reglas de los actos jurídicos se aplican al pago, con sujeción a las disposiciones de este Capítulo.", practicalEffects: ['En la práctica, este artículo rige reglas aplicables. Las reglas de los actos jurídicos se aplican al pago, con sujeción a las disposiciones de este Capítulo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglas', 'aplicables', 'articulo 866'], segments: [], amendments: [] },
  { id: 'ccyc-art-867', lawId: 'codigo-civil-comercial', number: '867', order: 867, title: "Objeto del pago", originalText: "Objeto del pago. El objeto del pago debe reunir los requisitos de identidad, integridad, puntualidad y localización.", currentText: "Objeto del pago. El objeto del pago debe reunir los requisitos de identidad, integridad, puntualidad y localización.", plainLanguageExplanation: "Establece el régimen de objeto del pago. El objeto del pago debe reunir los requisitos de identidad, integridad, puntualidad y localización.", practicalEffects: ['En la práctica, este artículo rige objeto del pago. El objeto del pago debe reunir los requisitos de identidad, integridad, puntualidad y localización.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['objeto', 'pago', 'articulo 867'], segments: [], amendments: [] },
  { id: 'ccyc-art-868', lawId: 'codigo-civil-comercial', number: '868', order: 868, title: "Identidad", originalText: "Identidad. El acreedor no está obligado a recibir y el deudor no tiene derecho a cumplir una prestación distinta a la debida, cualquiera sea su valor.", currentText: "Identidad. El acreedor no está obligado a recibir y el deudor no tiene derecho a cumplir una prestación distinta a la debida, cualquiera sea su valor.", plainLanguageExplanation: "Establece el régimen de identidad. El acreedor no está obligado a recibir y el deudor no tiene derecho a cumplir una prestación distinta a la debida, cualquiera sea su valor.", practicalEffects: ['En la práctica, este artículo rige identidad. El acreedor no está obligado a recibir y el deudor no tiene derecho a cumplir una prestación distinta a la debida, cualquiera sea su valor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['identidadarticulo 868'], segments: [], amendments: [] },
  { id: 'ccyc-art-869', lawId: 'codigo-civil-comercial', number: '869', order: 869, title: "Integridad", originalText: "Integridad. El acreedor no está obligado a recibir pagos parciales, excepto disposición legal o convencional en contrario. Si la obligación es en parte líquida y en parte ilíquida, el deudor puede pagar la parte líquida.", currentText: "Integridad. El acreedor no está obligado a recibir pagos parciales, excepto disposición legal o convencional en contrario. Si la obligación es en parte líquida y en parte ilíquida, el deudor puede pagar la parte líquida.", plainLanguageExplanation: "Establece el régimen de integridad. El acreedor no está obligado a recibir pagos parciales, excepto disposición legal o convencional en contrario.", practicalEffects: ['En la práctica, este artículo rige integridad. El acreedor no está obligado a recibir pagos parciales, excepto disposición legal o convencional en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['integridadarticulo 869'], segments: [], amendments: [] },
  { id: 'ccyc-art-870', lawId: 'codigo-civil-comercial', number: '870', order: 870, title: "Obligación con intereses", originalText: "Obligación con intereses. Si la obligación es de dar una suma de dinero con intereses, el pago sólo es íntegro si incluye el capital más los intereses.", currentText: "Obligación con intereses. Si la obligación es de dar una suma de dinero con intereses, el pago sólo es íntegro si incluye el capital más los intereses.", plainLanguageExplanation: "Establece el régimen de obligación con intereses. Si la obligación es de dar una suma de dinero con intereses, el pago sólo es íntegro si incluye el capital más los intereses.", practicalEffects: ['En la práctica, este artículo rige obligación con intereses. Si la obligación es de dar una suma de dinero con intereses, el pago sólo es íntegro si incluye el capital más los intereses.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacin', 'intereses', 'articulo 870'], segments: [], amendments: [] },
  { id: 'ccyc-art-871', lawId: 'codigo-civil-comercial', number: '871', order: 871, title: "Tiempo del pago", originalText: "Tiempo del pago. El pago debe hacerse: a) si la obligación es de exigibilidad inmediata, en el momento de su nacimiento; b) si hay un plazo determinado, cierto o incierto, el día de su vencimiento; c) si el plazo es tácito, en el tiempo en que, según la naturaleza y circunstancias de la obligación, debe cumplirse; d) si el plazo es indeterminado, en el tiempo que fije el juez, a solicitud de cualquiera de las partes, mediante el procedimiento más breve que prevea la ley local.", currentText: "Tiempo del pago. El pago debe hacerse: a) si la obligación es de exigibilidad inmediata, en el momento de su nacimiento; b) si hay un plazo determinado, cierto o incierto, el día de su vencimiento; c) si el plazo es tácito, en el tiempo en que, según la naturaleza y circunstancias de la obligación, debe cumplirse; d) si el plazo es indeterminado, en el tiempo que fije el juez, a solicitud de cualquiera de las partes, mediante el procedimiento más breve que prevea la ley local.", plainLanguageExplanation: "Establece el régimen de tiempo del pago. El pago debe hacerse: a) si la obligación es de exigibilidad inmediata, en el momento de su nacimiento; b) si hay un plazo determinado, cierto o incierto, el día de su vencimiento; c) si el plazo es tácito, en el tiempo en que, según la naturaleza y circunstancias de la obligació", practicalEffects: ['En la práctica, este artículo rige tiempo del pago. El pago debe hacerse: a) si la obligación es de exigibilidad inmediata, en el momento de su nacimiento; b) si hay un plazo determinado, cierto o incie'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tiempo', 'pago', 'articulo 871'], segments: [], amendments: [] },
  { id: 'ccyc-art-872', lawId: 'codigo-civil-comercial', number: '872', order: 872, title: "Pago anticipado", originalText: "Pago anticipado. El pago anterior al vencimiento del plazo no da derecho a exigir descuentos.", currentText: "Pago anticipado. El pago anterior al vencimiento del plazo no da derecho a exigir descuentos.", plainLanguageExplanation: "Establece el régimen de pago anticipado. El pago anterior al vencimiento del plazo no da derecho a exigir descuentos.", practicalEffects: ['En la práctica, este artículo rige pago anticipado. El pago anterior al vencimiento del plazo no da derecho a exigir descuentos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pago', 'anticipado', 'articulo 872'], segments: [], amendments: [] },
  { id: 'ccyc-art-873', lawId: 'codigo-civil-comercial', number: '873', order: 873, title: "Lugar de pago designado", originalText: "Lugar de pago designado. El lugar de pago puede ser establecido por acuerdo de las partes, de manera expresa o tácita.", currentText: "Lugar de pago designado. El lugar de pago puede ser establecido por acuerdo de las partes, de manera expresa o tácita.", plainLanguageExplanation: "Establece el régimen de lugar de pago designado. El lugar de pago puede ser establecido por acuerdo de las partes, de manera expresa o tácita.", practicalEffects: ['En la práctica, este artículo rige lugar de pago designado. El lugar de pago puede ser establecido por acuerdo de las partes, de manera expresa o tácita.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['lugar', 'pago', 'designado', 'articulo 873'], segments: [], amendments: [] },
  { id: 'ccyc-art-874', lawId: 'codigo-civil-comercial', number: '874', order: 874, title: "Lugar de pago no designado", originalText: "Lugar de pago no designado. Si nada se ha indicado, el lugar de pago es el domicilio del deudor al tiempo del nacimiento de la obligación. Si el deudor se muda, el acreedor tiene derecho a exigir el pago en el domicilio actual o en el anterior. Igual opción corresponde al deudor, cuando el lugar de pago sea el domicilio del acreedor. Esta regla no se aplica a las obligaciones: a) de dar cosa cierta; en este caso, el lugar de pago es donde la cosa se encuentra habitualmente; b) de obligaciones bilaterales de cumplimiento simultáneo; en este supuesto, lugar de pago es donde debe cumplirse la prestación principal.", currentText: "Lugar de pago no designado. Si nada se ha indicado, el lugar de pago es el domicilio del deudor al tiempo del nacimiento de la obligación. Si el deudor se muda, el acreedor tiene derecho a exigir el pago en el domicilio actual o en el anterior. Igual opción corresponde al deudor, cuando el lugar de pago sea el domicilio del acreedor. Esta regla no se aplica a las obligaciones: a) de dar cosa cierta; en este caso, el lugar de pago es donde la cosa se encuentra habitualmente; b) de obligaciones bilaterales de cumplimiento simultáneo; en este supuesto, lugar de pago es donde debe cumplirse la prestación principal.", plainLanguageExplanation: "Establece el régimen de lugar de pago no designado. Si nada se ha indicado, el lugar de pago es el domicilio del deudor al tiempo del nacimiento de la obligación.", practicalEffects: ['En la práctica, este artículo rige lugar de pago no designado. Si nada se ha indicado, el lugar de pago es el domicilio del deudor al tiempo del nacimiento de la obligación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['lugar', 'pago', 'designado', 'articulo 874'], segments: [], amendments: [] },
  { id: 'ccyc-art-875', lawId: 'codigo-civil-comercial', number: '875', order: 875, title: "Validez", originalText: "Validez. El pago debe ser realizado por persona con capacidad para disponer.", currentText: "Validez. El pago debe ser realizado por persona con capacidad para disponer.", plainLanguageExplanation: "Establece el régimen de validez. El pago debe ser realizado por persona con capacidad para disponer.", practicalEffects: ['En la práctica, este artículo rige validez. El pago debe ser realizado por persona con capacidad para disponer.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['validezarticulo 875'], segments: [], amendments: [] },
  { id: 'ccyc-art-876', lawId: 'codigo-civil-comercial', number: '876', order: 876, title: "Pago en fraude a los acreedores", originalText: "Pago en fraude a los acreedores. El pago debe hacerse sin fraude a los acreedores. En este supuesto, se aplica la normativa de la acción revocatoria y, en su caso, la de la ley concursal.", currentText: "Pago en fraude a los acreedores. El pago debe hacerse sin fraude a los acreedores. En este supuesto, se aplica la normativa de la acción revocatoria y, en su caso, la de la ley concursal.", plainLanguageExplanation: "Establece el régimen de pago en fraude a los acreedores. El pago debe hacerse sin fraude a los acreedores.", practicalEffects: ['En la práctica, este artículo rige pago en fraude a los acreedores. El pago debe hacerse sin fraude a los acreedores.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pago', 'fraude', 'acreedores', 'articulo 876'], segments: [], amendments: [] },
  { id: 'ccyc-art-877', lawId: 'codigo-civil-comercial', number: '877', order: 877, title: "Pago de créditos embargados o prendados", originalText: "Pago de créditos embargados o prendados. El crédito debe encontrarse expedito. El pago de un crédito embargado o prendado es inoponible al acreedor prendario o embargante.", currentText: "Pago de créditos embargados o prendados. El crédito debe encontrarse expedito. El pago de un crédito embargado o prendado es inoponible al acreedor prendario o embargante.", plainLanguageExplanation: "Establece el régimen de pago de créditos embargados o prendados. El crédito debe encontrarse expedito.", practicalEffects: ['En la práctica, este artículo rige pago de créditos embargados o prendados. El crédito debe encontrarse expedito.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pago', 'crditos', 'embargados', 'prendados', 'articulo 877'], segments: [], amendments: [] },
  { id: 'ccyc-art-878', lawId: 'codigo-civil-comercial', number: '878', order: 878, title: "Propiedad de la cosa", originalText: "Propiedad de la cosa. El cumplimiento de una obligación de dar cosas ciertas para constituir derechos reales requiere que el deudor sea propietario de la cosa. El pago mediante una cosa que no pertenece al deudor se rige por las normas relativas a la compraventa de cosa ajena.", currentText: "Propiedad de la cosa. El cumplimiento de una obligación de dar cosas ciertas para constituir derechos reales requiere que el deudor sea propietario de la cosa. El pago mediante una cosa que no pertenece al deudor se rige por las normas relativas a la compraventa de cosa ajena.", plainLanguageExplanation: "Establece el régimen de propiedad de la cosa. El cumplimiento de una obligación de dar cosas ciertas para constituir derechos reales requiere que el deudor sea propietario de la cosa.", practicalEffects: ['En la práctica, este artículo rige propiedad de la cosa. El cumplimiento de una obligación de dar cosas ciertas para constituir derechos reales requiere que el deudor sea propietario de la cosa.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['propiedad', 'cosa', 'articulo 878'], segments: [], amendments: [] },
  { id: 'ccyc-art-879', lawId: 'codigo-civil-comercial', number: '879', order: 879, title: "Legitimación activa", originalText: "Legitimación activa. El deudor tiene el derecho de pagar. Si hay varios deudores, el derecho de pagar de cada uno de ellos se rige por las disposiciones correspondientes a la categoría de su obligación.", currentText: "Legitimación activa. El deudor tiene el derecho de pagar. Si hay varios deudores, el derecho de pagar de cada uno de ellos se rige por las disposiciones correspondientes a la categoría de su obligación.", plainLanguageExplanation: "Establece el régimen de legitimación activa. El deudor tiene el derecho de pagar.", practicalEffects: ['En la práctica, este artículo rige legitimación activa. El deudor tiene el derecho de pagar.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legitimacin', 'activa', 'articulo 879'], segments: [], amendments: [] },
  { id: 'ccyc-art-880', lawId: 'codigo-civil-comercial', number: '880', order: 880, title: "Efectos del pago por el deudor", originalText: "Efectos del pago por el deudor. El pago realizado por el deudor que satisface el interés del acreedor, extingue el crédito y lo libera.", currentText: "Efectos del pago por el deudor. El pago realizado por el deudor que satisface el interés del acreedor, extingue el crédito y lo libera.", plainLanguageExplanation: "Establece el régimen de efectos del pago por el deudor. El pago realizado por el deudor que satisface el interés del acreedor, extingue el crédito y lo libera.", practicalEffects: ['En la práctica, este artículo rige efectos del pago por el deudor. El pago realizado por el deudor que satisface el interés del acreedor, extingue el crédito y lo libera.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'pago', 'deudor', 'articulo 880'], segments: [], amendments: [] },
  { id: 'ccyc-art-881', lawId: 'codigo-civil-comercial', number: '881', order: 881, title: "Ejecución de la prestación por un tercero", originalText: "Ejecución de la prestación por un tercero. La prestación también puede ser ejecutada por un tercero, excepto que se hayan tenido en cuenta las condiciones especiales del deudor, o hubiere oposición conjunta del acreedor y del deudor. Tercero interesado es la persona a quien el incumplimiento del deudor puede causar un menoscabo patrimonial, y puede pagar contra la oposición individual o conjunta del acreedor y del deudor.", currentText: "Ejecución de la prestación por un tercero. La prestación también puede ser ejecutada por un tercero, excepto que se hayan tenido en cuenta las condiciones especiales del deudor, o hubiere oposición conjunta del acreedor y del deudor. Tercero interesado es la persona a quien el incumplimiento del deudor puede causar un menoscabo patrimonial, y puede pagar contra la oposición individual o conjunta del acreedor y del deudor.", plainLanguageExplanation: "Establece el régimen de ejecución de la prestación por un tercero. La prestación también puede ser ejecutada por un tercero, excepto que se hayan tenido en cuenta las condiciones especiales del deudor, o hubiere oposición conjunta del acreedor y del deudor.", practicalEffects: ['En la práctica, este artículo rige ejecución de la prestación por un tercero. La prestación también puede ser ejecutada por un tercero, excepto que se hayan tenido en cuenta las condiciones especiales del deudor, o hubiere oposición conjunta del acreedor y del deudor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ejecucin', 'prestacin', 'tercero', 'articulo 881'], segments: [], amendments: [] },
  { id: 'ccyc-art-882', lawId: 'codigo-civil-comercial', number: '882', order: 882, title: "Efectos que produce la ejecución de la prestación por un tercero", originalText: "Efectos que produce la ejecución de la prestación por un tercero. La ejecución de la prestación por un tercero no extingue el crédito. El tercero tiene acción contra el deudor con los mismos alcances que: a) el mandatario que ejecuta la prestación con asentimiento del deudor; b) el gestor de negocios que obra con ignorancia de éste; c) quien interpone la acción de enriquecimiento sin causa, si actúa contra la voluntad del deudor. Puede también ejercitar la acción que nace de la subrogación por ejecución de la prestación por un tercero.", currentText: "Efectos que produce la ejecución de la prestación por un tercero. La ejecución de la prestación por un tercero no extingue el crédito. El tercero tiene acción contra el deudor con los mismos alcances que: a) el mandatario que ejecuta la prestación con asentimiento del deudor; b) el gestor de negocios que obra con ignorancia de éste; c) quien interpone la acción de enriquecimiento sin causa, si actúa contra la voluntad del deudor. Puede también ejercitar la acción que nace de la subrogación por ejecución de la prestación por un tercero.", plainLanguageExplanation: "Establece el régimen de efectos que produce la ejecución de la prestación por un tercero. La ejecución de la prestación por un tercero no extingue el crédito.", practicalEffects: ['En la práctica, este artículo rige efectos que produce la ejecución de la prestación por un tercero. La ejecución de la prestación por un tercero no extingue el crédito.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'produce', 'ejecucin', 'prestacin', 'tercero', 'articulo 882'], segments: [], amendments: [] },
  { id: 'ccyc-art-883', lawId: 'codigo-civil-comercial', number: '883', order: 883, title: "Legitimación para recibir pagos", originalText: "Legitimación para recibir pagos. Tiene efecto extintivo del crédito el pago hecho: a) al acreedor, o a su cesionario o subrogante; si hay varios acreedores, el derecho al cobro de cada uno de ellos se rige por las disposiciones correspondientes a la categoría de su obligación; b) a la orden del juez que dispuso el embargo del crédito; c) al tercero indicado para recibir el pago, en todo o en parte; d) a quien posee el título de crédito extendido al portador, o endosado en blanco, excepto sospecha fundada de no pertenecerle el documento, o de no estar autorizado para el cobro; e) al acreedor aparente, si quien realiza el pago actúa de buena fe y de las circunstancias resulta verosímil el derecho invocado; el pago es válido, aunque después sea vencido en juicio sobre el derecho que invoca.", currentText: "Legitimación para recibir pagos. Tiene efecto extintivo del crédito el pago hecho: a) al acreedor, o a su cesionario o subrogante; si hay varios acreedores, el derecho al cobro de cada uno de ellos se rige por las disposiciones correspondientes a la categoría de su obligación; b) a la orden del juez que dispuso el embargo del crédito; c) al tercero indicado para recibir el pago, en todo o en parte; d) a quien posee el título de crédito extendido al portador, o endosado en blanco, excepto sospecha fundada de no pertenecerle el documento, o de no estar autorizado para el cobro; e) al acreedor aparente, si quien realiza el pago actúa de buena fe y de las circunstancias resulta verosímil el derecho invocado; el pago es válido, aunque después sea vencido en juicio sobre el derecho que invoca.", plainLanguageExplanation: "Establece el régimen de legitimación para recibir pagos. Tiene efecto extintivo del crédito el pago hecho: a) al acreedor, o a su cesionario o subrogante; si hay varios acreedores, el derecho al cobro de cada uno de ellos se rige por las disposiciones correspondientes a la categoría de su obligación; b) a la orden del juez que dispuso", practicalEffects: ['En la práctica, este artículo rige legitimación para recibir pagos. Tiene efecto extintivo del crédito el pago hecho: a) al acreedor, o a su cesionario o subrogante; si hay varios acreedores, el derecho al cobro de cad'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legitimacin', 'para', 'recibir', 'pagos', 'articulo 883'], segments: [], amendments: [] },
  { id: 'ccyc-art-884', lawId: 'codigo-civil-comercial', number: '884', order: 884, title: "Derechos del acreedor contra el tercero", originalText: "Derechos del acreedor contra el tercero. El acreedor tiene derecho a reclamar al tercero el valor de lo que ha recibido: a) en el caso del inciso c) del artículo 883, conforme a los términos de la relación interna entre ambos; b) en los casos de los incisos d) y e) del artículo 883, conforme a las reglas del pago indebido.", currentText: "Derechos del acreedor contra el tercero. El acreedor tiene derecho a reclamar al tercero el valor de lo que ha recibido: a) en el caso del inciso c) del artículo 883, conforme a los términos de la relación interna entre ambos; b) en los casos de los incisos d) y e) del artículo 883, conforme a las reglas del pago indebido.", plainLanguageExplanation: "Establece el régimen de derechos del acreedor contra el tercero. El acreedor tiene derecho a reclamar al tercero el valor de lo que ha recibido: a) en el caso del inciso c) del artículo 883, conforme a los términos de la relación interna entre ambos; b) en los casos de los incisos d) y e) del artículo 883, conforme a las reglas del pago indebi", practicalEffects: ['En la práctica, este artículo rige derechos del acreedor contra el tercero. El acreedor tiene derecho a reclamar al tercero el valor de lo que ha recibido: a) en el caso del inciso c) del artículo 883, conforme a los términos'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos', 'acreedor', 'contra', 'tercero', 'articulo 884'], segments: [], amendments: [] },
  { id: 'ccyc-art-885', lawId: 'codigo-civil-comercial', number: '885', order: 885, title: "Pago a persona incapaz o con capacidad restringida y a tercero no legitimado", originalText: "Pago a persona incapaz o con capacidad restringida y a tercero no legitimado. No es válido el pago realizado a una persona incapaz, ni con capacidad restringida no autorizada por el juez para recibir pagos, ni a un tercero no autorizado por el acreedor para recibirlo, excepto que medie ratificación del acreedor. No obstante, el pago produce efectos en la medida en que el acreedor se ha beneficiado. SECCION 2ª Mora", currentText: "Pago a persona incapaz o con capacidad restringida y a tercero no legitimado. No es válido el pago realizado a una persona incapaz, ni con capacidad restringida no autorizada por el juez para recibir pagos, ni a un tercero no autorizado por el acreedor para recibirlo, excepto que medie ratificación del acreedor. No obstante, el pago produce efectos en la medida en que el acreedor se ha beneficiado. SECCION 2ª Mora", plainLanguageExplanation: "Establece el régimen de pago a persona incapaz o con capacidad restringida y a tercero no legitimado. No es válido el pago realizado a una persona incapaz, ni con capacidad restringida no autorizada por el juez para recibir pagos, ni a un tercero no autorizado por el acreedor para recibirlo, excepto que medie ratificación del acreedor.", practicalEffects: ['En la práctica, este artículo rige pago a persona incapaz o con capacidad restringida y a tercero no legitimado. No es válido el pago realizado a una persona incapaz, ni con capacidad restringida no autorizada por el juez para recibir pagos, ni a un tercero no au'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pago', 'persona', 'incapaz', 'capacidad', 'restringida', 'tercero', 'legitimado', 'articulo 885'], segments: [], amendments: [] },
  { id: 'ccyc-art-886', lawId: 'codigo-civil-comercial', number: '886', order: 886, title: "Mora del deudor", originalText: "Mora del deudor. Principio. Mora automática. Mora del acreedor. La mora del deudor se produce por el solo transcurso del tiempo fijado para el cumplimiento de la obligación. El acreedor incurre en mora si el deudor le efectúa una oferta de pago de conformidad con el artículo 867 y se rehúsa injustificadamente a recibirlo.", currentText: "Mora del deudor. Principio. Mora automática. Mora del acreedor. La mora del deudor se produce por el solo transcurso del tiempo fijado para el cumplimiento de la obligación. El acreedor incurre en mora si el deudor le efectúa una oferta de pago de conformidad con el artículo 867 y se rehúsa injustificadamente a recibirlo.", plainLanguageExplanation: "Establece el régimen de mora del deudor. Principio.", practicalEffects: ['En la práctica, este artículo rige mora del deudor. Principio.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mora', 'deudor', 'articulo 886'], segments: [], amendments: [] },
  { id: 'ccyc-art-887', lawId: 'codigo-civil-comercial', number: '887', order: 887, title: "Excepciones al principio de la mora automática", originalText: "Excepciones al principio de la mora automática. La regla de la mora automática no rige respecto de las obligaciones: a) sujetas a plazo tácito; si el plazo no está expresamente determinado, pero resulta tácitamente de la naturaleza y circunstancias de la obligación, en la fecha que conforme a los usos y a la buena fe, debe cumplirse; b) sujetas a plazo indeterminado propiamente dicho; si no hay plazo, el juez a pedido de parte, lo debe fijar mediante el procedimiento más breve que prevea la ley local, a menos que el acreedor opte por acumular las acciones de fijación de plazo y de cumplimiento, en cuyo caso el deudor queda constituido en mora en la fecha indicada por la sentencia para el cumplimiento de la obligación. En caso de duda respecto a si el plazo es tácito o indeterminado propiamente dicho, se considera que es tácito.", currentText: "Excepciones al principio de la mora automática. La regla de la mora automática no rige respecto de las obligaciones: a) sujetas a plazo tácito; si el plazo no está expresamente determinado, pero resulta tácitamente de la naturaleza y circunstancias de la obligación, en la fecha que conforme a los usos y a la buena fe, debe cumplirse; b) sujetas a plazo indeterminado propiamente dicho; si no hay plazo, el juez a pedido de parte, lo debe fijar mediante el procedimiento más breve que prevea la ley local, a menos que el acreedor opte por acumular las acciones de fijación de plazo y de cumplimiento, en cuyo caso el deudor queda constituido en mora en la fecha indicada por la sentencia para el cumplimiento de la obligación. En caso de duda respecto a si el plazo es tácito o indeterminado propiamente dicho, se considera que es tácito.", plainLanguageExplanation: "Establece el régimen de excepciones al principio de la mora automática. La regla de la mora automática no rige respecto de las obligaciones: a) sujetas a plazo tácito; si el plazo no está expresamente determinado, pero resulta tácitamente de la naturaleza y circunstancias de la obligación, en la fecha que conforme a los usos y a la buena fe, debe cum", practicalEffects: ['En la práctica, este artículo rige excepciones al principio de la mora automática. La regla de la mora automática no rige respecto de las obligaciones: a) sujetas a plazo tácito; si el plazo no está expresamente determinado, pero res'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['excepciones', 'principio', 'mora', 'automtica', 'articulo 887'], segments: [], amendments: [] },
  { id: 'ccyc-art-888', lawId: 'codigo-civil-comercial', number: '888', order: 888, title: "Eximición", originalText: "Eximición. Para eximirse de las consecuencias jurídicas derivadas de la mora, el deudor debe probar que no le es imputable, cualquiera sea el lugar de pago de la obligación. SECCION 3ª Pago a mejor fortuna", currentText: "Eximición. Para eximirse de las consecuencias jurídicas derivadas de la mora, el deudor debe probar que no le es imputable, cualquiera sea el lugar de pago de la obligación. SECCION 3ª Pago a mejor fortuna", plainLanguageExplanation: "Establece el régimen de eximición. Para eximirse de las consecuencias jurídicas derivadas de la mora, el deudor debe probar que no le es imputable, cualquiera sea el lugar de pago de la obligación.", practicalEffects: ['En la práctica, este artículo rige eximición. Para eximirse de las consecuencias jurídicas derivadas de la mora, el deudor debe probar que no le es imputable, cualquiera sea el lugar de pago de la obligación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['eximicinarticulo 888'], segments: [], amendments: [] },
  { id: 'ccyc-art-889', lawId: 'codigo-civil-comercial', number: '889', order: 889, title: "Principio", originalText: "Principio. Las partes pueden acordar que el deudor pague cuando pueda, o mejore de fortuna; en este supuesto, se aplican las reglas de las obligaciones a plazo indeterminado.", currentText: "Principio. Las partes pueden acordar que el deudor pague cuando pueda, o mejore de fortuna; en este supuesto, se aplican las reglas de las obligaciones a plazo indeterminado.", plainLanguageExplanation: "Establece el régimen de principio. Las partes pueden acordar que el deudor pague cuando pueda, o mejore de fortuna; en este supuesto, se aplican las reglas de las obligaciones a plazo indeterminado.", practicalEffects: ['En la práctica, este artículo rige principio. Las partes pueden acordar que el deudor pague cuando pueda, o mejore de fortuna; en este supuesto, se aplican las reglas de las obligaciones a plazo i'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['principioarticulo 889'], segments: [], amendments: [] },
  { id: 'ccyc-art-890', lawId: 'codigo-civil-comercial', number: '890', order: 890, title: "Carga de la prueba", originalText: "Carga de la prueba. El acreedor puede reclamar el cumplimiento de la prestación, y corresponde al deudor demostrar que su estado patrimonial le impide pagar. En caso de condena, el juez puede fijar el pago en cuotas.", currentText: "Carga de la prueba. El acreedor puede reclamar el cumplimiento de la prestación, y corresponde al deudor demostrar que su estado patrimonial le impide pagar. En caso de condena, el juez puede fijar el pago en cuotas.", plainLanguageExplanation: "Establece el régimen de carga de la prueba. El acreedor puede reclamar el cumplimiento de la prestación, y corresponde al deudor demostrar que su estado patrimonial le impide pagar.", practicalEffects: ['En la práctica, este artículo rige carga de la prueba. El acreedor puede reclamar el cumplimiento de la prestación, y corresponde al deudor demostrar que su estado patrimonial le impide pagar.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['carga', 'prueba', 'articulo 890'], segments: [], amendments: [] },
  { id: 'ccyc-art-891', lawId: 'codigo-civil-comercial', number: '891', order: 891, title: "Muerte del deudor", originalText: "Muerte del deudor. Se presume que la cláusula de pago a mejor fortuna se establece en beneficio exclusivo del deudor; la deuda se transmite a los herederos como obligación pura y simple. SECCION 4ª Beneficio de competencia", currentText: "Muerte del deudor. Se presume que la cláusula de pago a mejor fortuna se establece en beneficio exclusivo del deudor; la deuda se transmite a los herederos como obligación pura y simple. SECCION 4ª Beneficio de competencia", plainLanguageExplanation: "Establece el régimen de muerte del deudor. Se presume que la cláusula de pago a mejor fortuna se establece en beneficio exclusivo del deudor; la deuda se transmite a los herederos como obligación pura y simple.", practicalEffects: ['En la práctica, este artículo rige muerte del deudor. Se presume que la cláusula de pago a mejor fortuna se establece en beneficio exclusivo del deudor; la deuda se transmite a los herederos como obligación pura y simple.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['muerte', 'deudor', 'articulo 891'], segments: [], amendments: [] },
  { id: 'ccyc-art-892', lawId: 'codigo-civil-comercial', number: '892', order: 892, title: "Definición", originalText: "Definición. El beneficio de competencia es un derecho que se otorga a ciertos deudores, para que paguen lo que buenamente puedan, según las circunstancias, y hasta que mejoren de fortuna.", currentText: "Definición. El beneficio de competencia es un derecho que se otorga a ciertos deudores, para que paguen lo que buenamente puedan, según las circunstancias, y hasta que mejoren de fortuna.", plainLanguageExplanation: "Establece el régimen de definición. El beneficio de competencia es un derecho que se otorga a ciertos deudores, para que paguen lo que buenamente puedan, según las circunstancias, y hasta que mejoren de fortuna.", practicalEffects: ['En la práctica, este artículo rige definición. El beneficio de competencia es un derecho que se otorga a ciertos deudores, para que paguen lo que buenamente puedan, según las circunstancias, y hast'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 892'], segments: [], amendments: [] },
  { id: 'ccyc-art-893', lawId: 'codigo-civil-comercial', number: '893', order: 893, title: "Personas incluidas", originalText: "Personas incluidas. El acreedor debe conceder este beneficio: a) a sus ascendientes, descendientes y colaterales hasta el segundo grado, si no han incurrido en alguna causal de indignidad para suceder; b) a su cónyuge o conviviente; c) al donante en cuanto a hacerle cumplir la donación. SECCION 5ª Prueba del pago", currentText: "Personas incluidas. El acreedor debe conceder este beneficio: a) a sus ascendientes, descendientes y colaterales hasta el segundo grado, si no han incurrido en alguna causal de indignidad para suceder; b) a su cónyuge o conviviente; c) al donante en cuanto a hacerle cumplir la donación. SECCION 5ª Prueba del pago", plainLanguageExplanation: "Establece el régimen de personas incluidas. El acreedor debe conceder este beneficio: a) a sus ascendientes, descendientes y colaterales hasta el segundo grado, si no han incurrido en alguna causal de indignidad para suceder; b) a su cónyuge o conviviente; c) al donante en cuanto a hacerle cumplir la donación.", practicalEffects: ['En la práctica, este artículo rige personas incluidas. El acreedor debe conceder este beneficio: a) a sus ascendientes, descendientes y colaterales hasta el segundo grado, si no han incurrido en alguna cau'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['personas', 'incluidas', 'articulo 893'], segments: [], amendments: [] },
  { id: 'ccyc-art-894', lawId: 'codigo-civil-comercial', number: '894', order: 894, title: "Carga de la prueba", originalText: "Carga de la prueba. La carga de la prueba incumbe: a) en las obligaciones de dar y de hacer, sobre quien invoca el pago; b) en las obligaciones de no hacer, sobre el acreedor que invoca el incumplimiento.", currentText: "Carga de la prueba. La carga de la prueba incumbe: a) en las obligaciones de dar y de hacer, sobre quien invoca el pago; b) en las obligaciones de no hacer, sobre el acreedor que invoca el incumplimiento.", plainLanguageExplanation: "Establece el régimen de carga de la prueba. La carga de la prueba incumbe: a) en las obligaciones de dar y de hacer, sobre quien invoca el pago; b) en las obligaciones de no hacer, sobre el acreedor que invoca el incumplimiento.", practicalEffects: ['En la práctica, este artículo rige carga de la prueba. La carga de la prueba incumbe: a) en las obligaciones de dar y de hacer, sobre quien invoca el pago; b) en las obligaciones de no hacer, sobre el acre'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['carga', 'prueba', 'articulo 894'], segments: [], amendments: [] },
  { id: 'ccyc-art-895', lawId: 'codigo-civil-comercial', number: '895', order: 895, title: "Medios de prueba", originalText: "Medios de prueba. El pago puede ser probado por cualquier medio excepto que de la estipulación o de la ley resulte previsto el empleo de uno determinado, o revestido de ciertas formalidades.", currentText: "Medios de prueba. El pago puede ser probado por cualquier medio excepto que de la estipulación o de la ley resulte previsto el empleo de uno determinado, o revestido de ciertas formalidades.", plainLanguageExplanation: "Establece el régimen de medios de prueba. El pago puede ser probado por cualquier medio excepto que de la estipulación o de la ley resulte previsto el empleo de uno determinado, o revestido de ciertas formalidades.", practicalEffects: ['En la práctica, este artículo rige medios de prueba. El pago puede ser probado por cualquier medio excepto que de la estipulación o de la ley resulte previsto el empleo de uno determinado, o revestido de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medios', 'prueba', 'articulo 895'], segments: [], amendments: [] },
  { id: 'ccyc-art-896', lawId: 'codigo-civil-comercial', number: '896', order: 896, title: "Recibo", originalText: "Recibo. El recibo es un instrumento público o privado en el que el acreedor reconoce haber recibido la prestación debida.", currentText: "Recibo. El recibo es un instrumento público o privado en el que el acreedor reconoce haber recibido la prestación debida.", plainLanguageExplanation: "Establece el régimen de recibo. El recibo es un instrumento público o privado en el que el acreedor reconoce haber recibido la prestación debida.", practicalEffects: ['En la práctica, este artículo rige recibo. El recibo es un instrumento público o privado en el que el acreedor reconoce haber recibido la prestación debida.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reciboarticulo 896'], segments: [], amendments: [] },
  { id: 'ccyc-art-897', lawId: 'codigo-civil-comercial', number: '897', order: 897, title: "Derecho de exigir el recibo", originalText: "Derecho de exigir el recibo. El cumplimiento de la obligación confiere al deudor derecho de obtener la constancia de la liberación correspondiente. El acreedor también puede exigir un recibo que pruebe la recepción.", currentText: "Derecho de exigir el recibo. El cumplimiento de la obligación confiere al deudor derecho de obtener la constancia de la liberación correspondiente. El acreedor también puede exigir un recibo que pruebe la recepción.", plainLanguageExplanation: "Establece el régimen de derecho de exigir el recibo. El cumplimiento de la obligación confiere al deudor derecho de obtener la constancia de la liberación correspondiente.", practicalEffects: ['En la práctica, este artículo rige derecho de exigir el recibo. El cumplimiento de la obligación confiere al deudor derecho de obtener la constancia de la liberación correspondiente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'exigir', 'recibo', 'articulo 897'], segments: [], amendments: [] },
  { id: 'ccyc-art-898', lawId: 'codigo-civil-comercial', number: '898', order: 898, title: "Inclusión de reservas", originalText: "Inclusión de reservas. El deudor puede incluir reservas de derechos en el recibo y el acreedor está obligado a consignarlas. La inclusión de estas reservas no perjudica los derechos de quien extiende el recibo.", currentText: "Inclusión de reservas. El deudor puede incluir reservas de derechos en el recibo y el acreedor está obligado a consignarlas. La inclusión de estas reservas no perjudica los derechos de quien extiende el recibo.", plainLanguageExplanation: "Establece el régimen de inclusión de reservas. El deudor puede incluir reservas de derechos en el recibo y el acreedor está obligado a consignarlas.", practicalEffects: ['En la práctica, este artículo rige inclusión de reservas. El deudor puede incluir reservas de derechos en el recibo y el acreedor está obligado a consignarlas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inclusin', 'reservas', 'articulo 898'], segments: [], amendments: [] },
  { id: 'ccyc-art-899', lawId: 'codigo-civil-comercial', number: '899', order: 899, title: "Presunciones relativas al pago", originalText: "Presunciones relativas al pago. Se presume, excepto prueba en contrario que: a) si se otorga un recibo por saldo, quedan canceladas todas las deudas correspondientes a la obligación por la cual fue otorgado; b) si se recibe el pago correspondiente a uno de los periodos, están cancelados los anteriores, sea que se deba una prestación única de ejecución diferida cuyo cumplimiento se realiza mediante pagos parciales, o que se trate de prestaciones sucesivas que nacen por el transcurso del tiempo; c) si se extiende recibo por el pago de la prestación principal, sin los accesorios del crédito, y no se hace reserva, éstos quedan extinguidos; d) si se debe daño moratorio, y al recibir el pago el acreedor no hace reserva a su respecto, la deuda por ese daño está extinguida. SECCION 6ª Imputación del pago", currentText: "Presunciones relativas al pago. Se presume, excepto prueba en contrario que: a) si se otorga un recibo por saldo, quedan canceladas todas las deudas correspondientes a la obligación por la cual fue otorgado; b) si se recibe el pago correspondiente a uno de los periodos, están cancelados los anteriores, sea que se deba una prestación única de ejecución diferida cuyo cumplimiento se realiza mediante pagos parciales, o que se trate de prestaciones sucesivas que nacen por el transcurso del tiempo; c) si se extiende recibo por el pago de la prestación principal, sin los accesorios del crédito, y no se hace reserva, éstos quedan extinguidos; d) si se debe daño moratorio, y al recibir el pago el acreedor no hace reserva a su respecto, la deuda por ese daño está extinguida. SECCION 6ª Imputación del pago", plainLanguageExplanation: "Establece el régimen de presunciones relativas al pago. Se presume, excepto prueba en contrario que: a) si se otorga un recibo por saldo, quedan canceladas todas las deudas correspondientes a la obligación por la cual fue otorgado; b) si se recibe el pago correspondiente a uno de los periodos, están cancelados los anteriores, sea que", practicalEffects: ['En la práctica, este artículo rige presunciones relativas al pago. Se presume, excepto prueba en contrario que: a) si se otorga un recibo por saldo, quedan canceladas todas las deudas correspondientes a la obligación'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presunciones', 'relativas', 'pago', 'articulo 899'], segments: [], amendments: [] },
  { id: 'ccyc-art-900', lawId: 'codigo-civil-comercial', number: '900', order: 900, title: "Imputación por el deudor", originalText: "Imputación por el deudor. Si las obligaciones para con un solo acreedor tienen por objeto prestaciones de la misma naturaleza, el deudor tiene la facultad de declarar, al tiempo de hacer el pago, por cuál de ellas debe entenderse que lo hace. La elección debe recaer sobre deuda líquida y de plazo vencido. Si adeuda capital e intereses, el pago no puede imputarse a la deuda principal sin consentimiento del acreedor.", currentText: "Imputación por el deudor. Si las obligaciones para con un solo acreedor tienen por objeto prestaciones de la misma naturaleza, el deudor tiene la facultad de declarar, al tiempo de hacer el pago, por cuál de ellas debe entenderse que lo hace. La elección debe recaer sobre deuda líquida y de plazo vencido. Si adeuda capital e intereses, el pago no puede imputarse a la deuda principal sin consentimiento del acreedor.", plainLanguageExplanation: "Establece el régimen de imputación por el deudor. Si las obligaciones para con un solo acreedor tienen por objeto prestaciones de la misma naturaleza, el deudor tiene la facultad de declarar, al tiempo de hacer el pago, por cuál de ellas debe entenderse que lo hace.", practicalEffects: ['En la práctica, este artículo rige imputación por el deudor. Si las obligaciones para con un solo acreedor tienen por objeto prestaciones de la misma naturaleza, el deudor tiene la facultad de declarar, al tiemp'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['imputacin', 'deudor', 'articulo 900'], segments: [], amendments: [] },
];
